import { Injectable } from '@angular/core';
import { LearningModule } from '../models/learning.model';

@Injectable({ providedIn: 'root' })
export class AdvancedLearningDataService {
  getAdvancedModules(): LearningModule[] {
    return [
      {
        id: 'taor-pattern',
        title: 'Think-Act-Observe-Repeat (TAOR)',
        description: 'The core reasoning loop that makes AI agents accurate and reliable',
        icon: '🔄',
        color: '#0984e3',
        order: 7,
        lessons: [
{
    id: 'taor-explained',
    moduleId: 'taor-pattern',
    title: 'The TAOR Loop Explained',
    description: 'Why AI agents need disciplined reasoning, and how Think-Act-Observe-Repeat prevents hallucination, infinite loops, and wrong actions',
    order: 1,
    content: [
      { type: 'text', content: '## Why Agents Fail Without Discipline\n\nGive an LLM a task and a set of tools, and it will happily start doing things. The problem is that "doing things" without a framework produces catastrophic outcomes:\n\n- **Hallucination cascades.** The agent assumes a file exists, writes code that imports from it, then writes more code that depends on that code. Three steps in, the entire chain is built on a fiction. Every subsequent action compounds the error because the agent never stopped to verify its assumption.\n- **Infinite loops.** The agent encounters a test failure, applies a fix, the fix breaks something else, the agent fixes that, which re-introduces the original bug. Without a conscious decision about whether to continue or stop, this cycle repeats until your token budget is exhausted.\n- **Compound actions that are impossible to debug.** The agent rewrites three files in a single step. Tests fail. Which change caused the failure? The agent does not know. You do not know. Nobody knows, because the changes were entangled.\n- **Wrong actions at wrong times.** The agent starts writing code before it has read the existing implementation. The result conflicts with conventions, duplicates existing utilities, or breaks interfaces that other modules depend on.\n\nThese are not edge cases. They are the **default behavior** of any agent that lacks a reasoning discipline. The TAOR pattern exists to prevent every single one of them.\n\n### The Scientific Method for AI Agents\n\nTAOR is to AI agents what the scientific method is to researchers. A scientist does not run experiments randomly and hope for insight. They **hypothesize** (Think), **design and run one experiment** (Act), **analyze the results** (Observe), and **decide whether to continue or change direction** (Repeat). The power comes not from any single step but from the discipline of following them in order, every time, without exception.\n\nTAOR applies the same rigor to AI agents: **Think** before you act, **Act** one step at a time, **Observe** critically before proceeding, and **Repeat** with conscious intent.' },
      { type: 'text', content: '## The Four Phases of TAOR\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="position:relative;border:2px solid #6c5ce7;border-radius:16px;padding:1.5rem;background:rgba(108,92,231,0.03);">\n<div style="font-weight:700;font-size:1.1rem;color:#6c5ce7;margin-bottom:1.2rem;text-align:center;">The TAOR Cycle</div>\n<div style="display:flex;flex-wrap:wrap;justify-content:center;gap:0.6rem;">\n<div style="flex:1;min-width:200px;max-width:240px;border:2px solid #0984e3;border-radius:10px;padding:0.8rem;background:rgba(9,132,227,0.05);">\n<div style="font-weight:700;color:#0984e3;font-size:1rem;margin-bottom:0.3rem;">1. THINK</div>\n<div style="font-size:0.82rem;color:#555;line-height:1.5;">What do I know? What do I need? What is my next single step and why? Reason about the current state before touching anything.</div>\n<div style="margin-top:0.4rem;font-size:0.75rem;padding:0.25rem 0.5rem;background:rgba(9,132,227,0.1);border-radius:4px;color:#0984e3;font-weight:600;">Prevents: hallucination, wrong assumptions</div>\n</div>\n<div style="flex:1;min-width:200px;max-width:240px;border:2px solid #00cec9;border-radius:10px;padding:0.8rem;background:rgba(0,206,201,0.05);">\n<div style="font-weight:700;color:#00cec9;font-size:1rem;margin-bottom:0.3rem;">2. ACT</div>\n<div style="font-size:0.82rem;color:#555;line-height:1.5;">Execute exactly one action. Read one file. Write one change. Run one command. Never compound multiple actions into a single step.</div>\n<div style="margin-top:0.4rem;font-size:0.75rem;padding:0.25rem 0.5rem;background:rgba(0,206,201,0.1);border-radius:4px;color:#00cec9;font-weight:600;">Prevents: entangled changes, debugging nightmares</div>\n</div>\n</div>\n<div style="display:flex;justify-content:center;margin:0.5rem 0;">\n<div style="width:0;height:0;border-left:8px solid transparent;border-right:8px solid transparent;border-top:8px solid #6c5ce7;"></div>\n</div>\n<div style="display:flex;flex-wrap:wrap;justify-content:center;gap:0.6rem;">\n<div style="flex:1;min-width:200px;max-width:240px;border:2px solid #e17055;border-radius:10px;padding:0.8rem;background:rgba(225,112,85,0.05);">\n<div style="font-weight:700;color:#e17055;font-size:1rem;margin-bottom:0.3rem;">3. OBSERVE</div>\n<div style="font-size:0.82rem;color:#555;line-height:1.5;">Critically examine the result. Did it succeed? Are there errors? Is the output what you expected? Do not assume success -- verify it.</div>\n<div style="margin-top:0.4rem;font-size:0.75rem;padding:0.25rem 0.5rem;background:rgba(225,112,85,0.1);border-radius:4px;color:#e17055;font-weight:600;">Prevents: silent failures, compounding errors</div>\n</div>\n<div style="flex:1;min-width:200px;max-width:240px;border:2px solid #27ae60;border-radius:10px;padding:0.8rem;background:rgba(39,174,96,0.05);">\n<div style="font-weight:700;color:#27ae60;font-size:1rem;margin-bottom:0.3rem;">4. REPEAT</div>\n<div style="font-size:0.82rem;color:#555;line-height:1.5;">Make a conscious decision: continue to the next step, retry the current step with adjustments, or stop because the goal is met or the situation requires escalation.</div>\n<div style="margin-top:0.4rem;font-size:0.75rem;padding:0.25rem 0.5rem;background:rgba(39,174,96,0.1);border-radius:4px;color:#27ae60;font-weight:600;">Prevents: infinite loops, runaway token spend</div>\n</div>\n</div>\n<div style="margin-top:1rem;text-align:center;">\n<div style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.4rem 1rem;border-radius:20px;background:rgba(108,92,231,0.1);font-size:0.82rem;color:#6c5ce7;font-weight:600;">\n&#8634; The cycle repeats until the task is complete or an exit condition is met\n</div>\n</div>\n</div>\n</div>\n\n### THINK: Reason Before You Touch Anything\n\nThe THINK phase is where the agent pauses to assess its current state. What information do I have? What information am I missing? What is the most productive single next step? This is not filler -- it is the step that prevents the entire chain of downstream errors. Without THINK, the agent acts on assumptions. With THINK, the agent acts on evidence.\n\nConcretely, THINK means: before reading a file, articulate what you expect to find and why you need it. Before writing code, state what the code should accomplish and what interface it must satisfy. Before running a command, predict what a successful result looks like.\n\n### ACT: One Action, One Step, No Exceptions\n\nThe single-action constraint is the most counterintuitive rule for developers who value efficiency. Why not edit three files at once if you know what all three changes should be? Because you do not actually know. You think you know, based on your current understanding, which may be wrong. By acting one step at a time, you create a checkpoint after every change. If something goes wrong, you know exactly which change caused it, and you can reason about why.\n\n### OBSERVE: Verify, Do Not Assume\n\nAfter every action, the agent must critically examine the result. Did the file read return what was expected? Did the code compile? Did the test pass? The word "critically" is essential. A lazy OBSERVE says "okay, done." A real OBSERVE says "the function returned a 200 status but the response body is empty -- that is unexpected, let me investigate before proceeding."\n\n### REPEAT: Conscious Continue or Stop\n\nThe REPEAT phase is a decision point, not an automatic loop. The agent must explicitly decide: Is the task complete? Should I continue to the next sub-task? Should I retry the current step with a different approach? Should I stop and report that I am stuck? Without this conscious decision, agents either loop forever or stop prematurely.' },
      { type: 'code', content: '// TAOR in action: a concrete example\n// Task: \"Add input validation to the createUser endpoint\"\n\n// === THINK Phase ===\n// I need to add input validation to createUser.\n// Before writing anything, I should:\n// 1. Read the current createUser implementation to understand the interface\n// 2. Check if there\'s an existing validation library or pattern in the project\n// 3. Understand what fields need validation\n// Let me start by reading the endpoint file.\n\n// === ACT Phase (single action) ===\n// Action: Read the createUser controller\nconst fileContent = await readFile(\'src/controllers/users.controller.ts\');\n\n// === OBSERVE Phase ===\n// The file exports createUser which takes req.body with:\n//   { name: string, email: string, role?: string }\n// There is NO existing validation -- the body is passed directly to the service.\n// I also see that other controllers use a \\`validateRequest\\` middleware\n// from \\`src/middleware/validation.ts\\`. I should follow that pattern.\n\n// === THINK Phase (next iteration) ===\n// Now I know the interface and the project\'s validation pattern.\n// My next single step: read the validation middleware to understand\n// how to create a validation schema for createUser.\n\n// === ACT Phase ===\nconst validationMiddleware = await readFile(\'src/middleware/validation.ts\');\n\n// === OBSERVE Phase ===\n// The middleware uses Zod schemas. Each schema is defined in\n// \\`src/schemas/\\` and imported by the controller.\n// Pattern: z.object({ field: z.string().min(1) })\n\n// === THINK Phase (next iteration) ===\n// I have everything I need. I\'ll create a Zod schema for createUser\n// in src/schemas/user.schema.ts. Just ONE file, ONE change.\n\n// === ACT Phase ===\nawait writeFile(\'src/schemas/user.schema.ts\', `\nimport { z } from \'zod\\\';\n\nexport const createUserSchema = z.object({\n  name: z.string().min(1, \'Name is required\\\').max(100),\n  email: z.string().email(\'Invalid email format\\\'),\n  role: z.enum([\'admin\\\', \'user\\\', \'viewer\\\']).optional(),\n});\n`);\n\n// === OBSERVE Phase ===\n// File written. Let me verify it by reading it back.\nconst written = await readFile(\'src/schemas/user.schema.ts\');\n// Confirmed: schema matches what I intended.\n\n// === REPEAT Decision ===\n// Schema created. Next I need to wire it into the controller.\n// Task is NOT complete yet -- continue to next TAOR cycle.', language: 'typescript' },
      { type: 'tip', content: 'The THINK phase maps directly to Extended Thinking in the Claude API (the `thinking` block that Claude produces before its response). When you enable Extended Thinking, Claude literally performs the THINK phase as a visible, auditable step. This is not a metaphor -- the model reasons about what it knows, what it needs, and what to do next, then outputs the reasoning before acting. You get THINK for free with every API call.' },
      { type: 'warning', content: 'The most common TAOR violation is skipping OBSERVE. An agent writes a file and immediately moves to the next file without verifying the write succeeded, checking for syntax errors, or confirming the content matches intent. Every skipped OBSERVE is a potential error that compounds silently through all subsequent actions. When debugging a failing agent, the root cause is almost always an OBSERVE that did not happen three steps earlier.' },
      { type: 'agent-demo', content: 'taor-live-demo' }
    ],
    quiz: [
      { id: 'taor-ex-q1', question: 'What is the primary purpose of the THINK phase in the TAOR loop?', options: ['To generate code as quickly as possible', 'To reason about what you know and what you need before taking any action', 'To call the LLM with a prompt', 'To check if the previous action succeeded'], correctIndex: 1, explanation: 'The THINK phase forces the agent to pause and assess: What do I know? What am I missing? What is the best single next step? This prevents acting on assumptions and is the first line of defense against hallucination and wrong actions.' },
      { id: 'taor-ex-q2', question: 'Why does TAOR enforce a single-action constraint in the ACT phase?', options: ['Because LLMs can only execute one tool call at a time', 'So each action can be individually observed and debugged -- compound actions make it impossible to identify which change caused a failure', 'To reduce API costs', 'Because multiple actions would overload the context window'], correctIndex: 1, explanation: 'When an agent makes multiple changes in one step and something breaks, nobody can tell which change caused the failure. Single actions create checkpoints: after each one, you observe the result and know exactly what happened and why. This is the foundation of debuggable agent behavior.' },
      { id: 'taor-ex-q3', question: 'An agent writes code to a file and immediately starts editing the next file without checking the result. Which TAOR phase was skipped, and what is the risk?', options: ['THINK was skipped -- the agent might hallucinate the file contents', 'ACT was skipped -- the agent did not actually write the file', 'OBSERVE was skipped -- the write may have failed silently, and all subsequent actions build on an unverified assumption', 'REPEAT was skipped -- the agent should have stopped'], correctIndex: 2, explanation: 'Skipping OBSERVE means the agent never verified that the write succeeded or that the content is correct. If the write failed (wrong path, permission error) or the content has a syntax error, every subsequent action compounds the problem. The root cause of most agent failures traces back to a missing OBSERVE step.' }
    ]
  },
  {
    id: 'taor-prompts',
    moduleId: 'taor-pattern',
    title: 'Structuring Agent Prompts for TAOR',
    description: 'Five techniques for writing system prompts that enforce disciplined Think-Act-Observe-Repeat behavior in any LLM agent',
    order: 2,
    content: [
      { type: 'text', content: '## Why Prompt Structure Determines Agent Behavior\n\nAn LLM agent is only as disciplined as its prompt. You can understand TAOR perfectly, but if your system prompt says "complete the task" and nothing more, the agent will revert to its default behavior: act fast, skip verification, compound actions, and hope for the best. The prompt is not documentation -- it is the **runtime configuration** of the agent\'s reasoning process.\n\nThe difference between a good agent and a bad agent is almost never the model. It is the prompt. The same Claude Sonnet model, given a lazy prompt, will hallucinate file paths and write untested code. Given a disciplined TAOR prompt, the same model will methodically read before writing, verify every change, and stop when it detects something unexpected.\n\nThis lesson teaches five concrete techniques for writing prompts that enforce TAOR. Each technique targets a specific failure mode. Together, they transform an unreliable "try and hope" agent into a systematic "verify and proceed" agent.\n\n### Bad Prompt vs. Good Prompt\n\nBefore diving into techniques, see the difference in action:\n\n**Bad prompt** (produces unreliable agents):\n> You are a helpful coding assistant. Complete the user\'s task. Use the available tools.\n\nThis prompt provides zero structure. The agent will:\n- Start writing code before reading existing files\n- Make multiple changes in a single step\n- Never verify that changes compile or pass tests\n- Continue indefinitely without a clear stopping condition\n- Crash or hallucinate when it encounters an error\n\n**Good prompt** (produces disciplined TAOR agents):\n> Before each action, explain your reasoning: what you know, what you need, and why this specific action is the right next step. Execute exactly ONE tool call at a time. After each result, analyze it critically: did it succeed? Is the output what you expected? Are there errors or surprises? Decide explicitly whether to continue, adjust your approach, or stop. If you encounter an unexpected error, do NOT retry blindly -- analyze the error message, form a hypothesis about the cause, and test that hypothesis with your next action.\n\nSame model. Radically different behavior. The prompt is the difference.' },
      { type: 'code', content: '// Technique 1: Mandatory Reasoning (enforces THINK)\n// Force the agent to explain its reasoning before EVERY action.\n\nconst BAD_PROMPT = `You are a coding assistant. Help the user with their task.`;\n// Result: Agent dives straight into writing code. No reasoning visible.\n// If code fails, you have no idea what the agent was thinking.\n\nconst GOOD_PROMPT = `You are a senior software engineer.\n\nBEFORE each action, you MUST write a reasoning block that includes:\n1. WHAT you currently know (facts from previous observations)\n2. WHAT you still need to learn or verify\n3. WHY your next action is the right single step\n4. WHAT you expect the result to look like\n\nIf you skip the reasoning block, your action is likely wrong.\nThe reasoning is not overhead -- it is how you avoid mistakes.`;\n// Result: Agent produces visible chain-of-thought before every tool call.\n// You can audit the reasoning and catch flawed logic BEFORE it causes damage.\n\n// Technique 2: Single-Action Constraint (enforces ACT)\n// Explicitly prohibit compound actions.\n\nconst SINGLE_ACTION_PROMPT = `CRITICAL RULE: Execute exactly ONE tool call per turn.\n\nDo NOT:\n- Read multiple files in one turn\n- Write to a file and then run tests in the same turn\n- Make changes to multiple files at once\n\nDO:\n- Read ONE file, observe the result, then decide the next step\n- Write ONE change, verify it, then proceed\n- Run ONE command, analyze the output, then act on it\n\nEvery compound action is a debugging disaster waiting to happen.\nOne action. One observation. One decision. Always.`;', language: 'typescript' },
      { type: 'text', content: '## The Five Techniques in Detail\n\n### Technique 1: Mandatory Reasoning\nForce the agent to produce a visible reasoning block before every action. This makes the THINK phase explicit and auditable. When something goes wrong, you can read the reasoning and identify exactly where the logic went off track. Without mandatory reasoning, the agent\'s "thinking" is invisible and uncheckable.\n\nThe key phrase is **"before each action, explain"** -- this creates a structural dependency where reasoning must precede action.\n\n### Technique 2: Single-Action Constraint\nExplicitly state that the agent must execute ONE tool call per turn. List specific violations ("do not read multiple files in one turn") because LLMs respond better to concrete examples than abstract rules. The phrase "every compound action is a debugging disaster" provides the WHY, which helps the model internalize the rule rather than treat it as arbitrary.\n\n### Technique 3: Verification Requirement\nAfter every write action, the agent must verify the result with a separate read or test action. This enforces OBSERVE. The prompt should list what to check: "Did the file write succeed? Does the code compile? Are there syntax errors? Does the output match your expectation?" Without this, agents assume success and build on unverified foundations.\n\n### Technique 4: Exit Criteria\nDefine exactly when the agent should stop. Without exit criteria, agents either stop too early ("I wrote the code, done!") or loop forever ("tests still failing, let me try again..."). Good exit criteria include: "Stop when all acceptance criteria from the ticket are met and tests pass" and "Stop after 3 failed retry attempts and report what you tried."\n\n### Technique 5: Failure Protocols\nTell the agent what to do when things go wrong. Without a failure protocol, agents either crash, retry blindly (infinite loop), or hallucinate a fix. A good failure protocol says: "If you encounter an error, do NOT retry the same action. Instead: (1) read the full error message, (2) form a hypothesis about the root cause, (3) test your hypothesis with a diagnostic action, (4) only then attempt a fix."' },
      { type: 'code', content: '// Complete TAOR system prompt combining all 5 techniques\n\nconst TAOR_SYSTEM_PROMPT = `You are a senior software engineer working on a production codebase.\n\n## REASONING (before every action)\nBefore each tool call, write a brief reasoning block:\n- Current understanding: what you know from previous steps\n- Knowledge gap: what you still need to verify\n- Next action: the ONE thing you will do and why\n- Expected result: what success looks like\n\n## SINGLE-ACTION RULE\nExecute exactly ONE tool call per turn. Never combine:\n- Reading multiple files\n- Writing and testing in the same step\n- Editing multiple files at once\nOne action. One observation. One decision.\n\n## VERIFICATION\nAfter every WRITE action (creating/editing files), you MUST:\n1. Read the file back to confirm the change was applied\n2. If applicable, run the relevant test or lint command\n3. Only proceed if verification passes\nNever assume a write succeeded. Verify it.\n\n## EXIT CRITERIA\nYou are done when ALL of the following are true:\n- All requirements from the task are implemented\n- All modified files have been verified (read back)\n- All relevant tests pass\n- No lint errors in changed files\nIf you cannot meet these criteria after 3 attempts at the same\nsub-task, STOP and report what you tried and what failed.\n\n## FAILURE PROTOCOL\nWhen you encounter an error:\n1. Read the FULL error message carefully\n2. Form a hypothesis: what specifically caused this?\n3. Test your hypothesis with ONE diagnostic action\n   (e.g., read the file, check a type, inspect a dependency)\n4. Only THEN attempt a fix based on evidence\nNever retry the same action hoping for a different result.\nNever guess at a fix without understanding the cause.`;\n\n// Using it with the Anthropic SDK\nimport Anthropic from \'@anthropic-ai/sdk\';\n\nconst client = new Anthropic();\n\nconst response = await client.messages.create({\n  model: \'claude-sonnet-4-6-20250514\',\n  max_tokens: 16384,\n  // Extended Thinking makes THINK explicit -- the model\'s internal\n  // reasoning becomes a visible, auditable \\`thinking\\` block\n  thinking: {\n    type: \'enabled\',\n    budget_tokens: 10000,  // Token budget for the THINK phase\n  },\n  system: TAOR_SYSTEM_PROMPT,\n  tools: [\n    { name: \'read_file\', description: \'Read a file\', input_schema: { type: \'object\', properties: { path: { type: \'string\' } }, required: [\'path\'] } },\n    { name: \'write_file\', description: \'Write to a file\', input_schema: { type: \'object\', properties: { path: { type: \'string\' }, content: { type: \'string\' } }, required: [\'path\', \'content\'] } },\n    { name: \'run_command\', description: \'Run a shell command\', input_schema: { type: \'object\', properties: { command: { type: \'string\' } }, required: [\'command\'] } },\n  ],\n  messages: [\n    { role: \'user\', content: \'Add input validation to the createUser endpoint in src/controllers/users.ts\' },\n  ],\n});\n\n// The response will contain:\n// 1. A \\`thinking\\` block (the model\'s THINK phase -- visible reasoning)\n// 2. A \\`text\\` block (the agent\'s explanation to the user)\n// 3. A \\`tool_use\\` block (the single ACT -- one tool call)\n// Your agent loop then: execute the tool, feed result back, repeat.', language: 'typescript' },
      { type: 'text', content: '## Extended Thinking: THINK Made Visible\n\nClaude\'s Extended Thinking feature deserves special attention because it literally implements the THINK phase at the API level. When you enable `thinking: { type: \'enabled\', budget_tokens: N }`, Claude produces a `thinking` block before its response. This block contains the model\'s internal reasoning: assessing the situation, considering alternatives, planning the next step.\n\nThis is not a gimmick. Extended Thinking has three concrete benefits for TAOR agents:\n\n1. **Auditability.** You can log the thinking block and review the agent\'s reasoning after the fact. When the agent makes a bad decision, you can see exactly why -- the reasoning is right there in the API response.\n2. **Better decisions.** The model genuinely reasons more carefully when thinking is enabled. It catches edge cases, considers failure modes, and produces more thorough plans. The quality improvement is measurable, not just theoretical.\n3. **Prompt reinforcement.** When your system prompt says "reason before acting" and Extended Thinking is enabled, the model has a dedicated space to follow that instruction. The thinking block and the prompt reinforce each other.\n\n### Common Mistakes in TAOR Prompts\n\n1. **Too vague.** "Think carefully" is useless. "Write a reasoning block with: what you know, what you need, why this action, what you expect" is actionable.\n2. **No concrete examples of violations.** "Don\'t do multiple actions" is weaker than "Don\'t read multiple files in one turn, don\'t write and test in the same step."\n3. **Missing failure protocols.** The prompt says what to do when things go right but nothing about what to do when things go wrong. Agents spend most of their time recovering from errors -- the failure path matters more than the happy path.\n4. **No exit criteria.** The agent keeps going forever or stops at an arbitrary point. Always define "done" explicitly.\n5. **Overloading the prompt.** A 5,000-word system prompt with 47 rules will be partially ignored. The five techniques above are the essential ones. Add more only when you observe a specific failure pattern that the current prompt does not prevent.' },
      { type: 'tip', content: 'When debugging an agent that is behaving poorly, enable Extended Thinking and read the thinking blocks. Nine times out of ten, the reasoning reveals the problem: the agent misunderstood the task, made a wrong assumption, or is following a flawed plan. Fix the system prompt to address the specific reasoning failure you see in the thinking block. This is faster than guessing and rewriting the entire prompt.' }
    ],
    quiz: [
      { id: 'taor-pr-q1', question: 'Why does a vague system prompt like "You are a helpful coding assistant. Complete the task." produce unreliable agent behavior?', options: ['Because the model is not powerful enough', 'Because the prompt provides no structure for reasoning, action sequencing, verification, or failure handling -- so the agent defaults to acting fast without discipline', 'Because the prompt is too short for the context window', 'Because it does not specify which programming language to use'], correctIndex: 1, explanation: 'Without structural constraints in the prompt, the agent has no framework for disciplined behavior. It will skip reasoning, compound actions, skip verification, and have no protocol for errors. The prompt is the agent\'s runtime configuration -- a vague prompt produces vague, unreliable behavior.' },
      { id: 'taor-pr-q2', question: 'What is the purpose of a "failure protocol" in a TAOR system prompt?', options: ['To log errors for compliance', 'To tell the agent to retry the same action until it works', 'To give the agent a structured process for diagnosing errors -- read the error, hypothesize a cause, test the hypothesis, then fix -- instead of retrying blindly or hallucinating a solution', 'To automatically escalate all errors to a human'], correctIndex: 2, explanation: 'Without a failure protocol, agents either retry blindly (infinite loop) or hallucinate fixes (compounding errors). A good failure protocol forces the agent to diagnose before fixing: read the error, form a hypothesis, test it with a diagnostic action, then attempt a fix based on evidence. This prevents both loops and hallucinated fixes.' },
      { id: 'taor-pr-q3', question: 'How does Claude\'s Extended Thinking feature relate to the THINK phase of TAOR?', options: ['It replaces TAOR entirely', 'It makes the THINK phase explicit -- Claude produces a visible reasoning block before acting, which can be audited and which improves decision quality', 'It is unrelated to TAOR', 'It only works with the Opus model'], correctIndex: 1, explanation: 'Extended Thinking creates a dedicated `thinking` block in the API response where Claude reasons about the situation before responding. This is a literal implementation of the THINK phase: visible, auditable reasoning that happens before any action. It improves decision quality and lets you debug the agent\'s logic by reading its reasoning.' }
    ]
  },
  {
    id: 'jira-to-taor',
    moduleId: 'taor-pattern',
    title: 'From Jira Ticket to Agent Execution Plan',
    description: 'Apply the TAOR pattern to a real-world development workflow: parsing tickets, searching codebases, making changes, and verifying results one step at a time',
    order: 3,
    content: [
      { type: 'text', content: '## The Real-World Test of TAOR\n\nTheory is easy. The real question is: does TAOR work when you hand an agent a Jira ticket and say "implement this"? The answer is yes, but only if you map each phase of the development workflow to TAOR\'s structure.\n\nA typical Jira ticket looks like this:\n\n> **PROJ-321: Add rate limiting to POST /api/payments**\n> As a platform engineer, I want rate limiting on the payments endpoint so that a single client cannot overwhelm the service.\n> **Acceptance criteria:**\n> - Limit to 100 requests per minute per API key\n> - Return 429 Too Many Requests with a Retry-After header when exceeded\n> - Log rate limit violations to the audit trail\n> - Existing tests must still pass\n\nA naive agent reads this ticket and immediately starts writing a rate limiting middleware. A TAOR agent reads this ticket and starts **thinking**.\n\n### Phase 1: THINK -- Parse the Requirements\n\nBefore touching any code, the TAOR agent decomposes the ticket into specific, verifiable requirements:\n1. Rate limiting middleware that checks requests per minute per API key\n2. A 429 response with Retry-After header when the limit is exceeded\n3. Audit trail logging for violations\n4. No regression in existing tests\n\nThen it identifies knowledge gaps: Where is the payments endpoint defined? Is there an existing rate limiting pattern in the codebase? What audit logging utility does the project use? What testing framework and conventions are in place?\n\nEach knowledge gap becomes a single ACT step. No guessing. No assumptions. Verify everything before writing a single line.\n\n### Phase 2: ACT -- One File, One Read, One Change at a Time\n\nThe agent\'s action sequence looks like this (each line is a separate TAOR cycle):\n\n1. **Read** `src/routes/payments.ts` -- understand the current endpoint structure\n2. **Search** for "rate limit" across the codebase -- check for existing patterns\n3. **Read** `src/middleware/auth.ts` -- see how existing middleware is structured\n4. **Read** `src/utils/audit.ts` -- understand the audit logging interface\n5. **Write** `src/middleware/rate-limit.ts` -- create the middleware (ONE file)\n6. **Read** it back -- verify the write succeeded and content is correct\n7. **Write** `src/routes/payments.ts` -- wire the middleware into the route (ONE change)\n8. **Read** it back -- verify\n9. **Write** `src/tests/rate-limit.test.ts` -- add tests (ONE file)\n10. **Run** `npm test` -- verify ALL tests pass\n\nNotice: ten TAOR cycles for what a naive agent would attempt in two or three compound steps. But each step is verified. Each step builds on confirmed results. When step 10 fails, the agent knows exactly what changed and can diagnose the issue.' },
      { type: 'code', content: '// TAOR agent loop for Jira ticket implementation\nimport Anthropic from \'@anthropic-ai/sdk\';\n\ninterface TaorStep {\n  phase: \'think\' | \'act\' | \'observe\' | \'repeat\';\n  content: string;\n  toolCall?: { name: string; input: Record<string, unknown> };\n  toolResult?: string;\n}\n\nasync function executeTicket(\n  ticket: string,\n  tools: Anthropic.Tool[],\n  maxIterations: number = 30\n): Promise<{ success: boolean; log: TaorStep[] }> {\n  const client = new Anthropic();\n  const log: TaorStep[] = [];\n\n  const systemPrompt = `You are implementing a Jira ticket in a production codebase.\n\n## PROCESS\n1. THINK: Parse the ticket into specific requirements and knowledge gaps\n2. ACT: Address ONE knowledge gap or make ONE change at a time\n3. OBSERVE: Verify every action\'s result before proceeding\n4. REPEAT: Continue until ALL acceptance criteria are met and tests pass\n\n## RULES\n- ONE tool call per turn. No exceptions.\n- After every write, read the file back to verify.\n- After all changes, run the test suite.\n- If tests fail, read the error, diagnose, and fix ONE thing at a time.\n\n## EXIT CRITERIA\nYou are done when:\n- All acceptance criteria from the ticket are implemented\n- All files have been verified (read back after writing)\n- All tests pass (including new and existing)\n- You have stated which files were changed and why\n\nIf you cannot resolve a test failure after 3 attempts, STOP and\nreport what you tried.`;\n\n  const messages: Anthropic.MessageParam[] = [\n    { role: \'user\', content: `Implement this ticket:\\n\\n${ticket}` },\n  ];\n\n  for (let i = 0; i < maxIterations; i++) {\n    // THINK + ACT: model reasons then calls one tool\n    const response = await client.messages.create({\n      model: \'claude-sonnet-4-6-20250514\',\n      max_tokens: 8192,\n      thinking: { type: \'enabled\', budget_tokens: 8000 },\n      system: systemPrompt,\n      tools,\n      messages,\n    });\n\n    // Log the THINK phase (Extended Thinking output)\n    const thinkingBlock = response.content.find(\n      (b) => b.type === \'thinking\'\n    );\n    if (thinkingBlock && thinkingBlock.type === \'thinking\') {\n      log.push({ phase: \'think\', content: thinkingBlock.thinking });\n    }\n\n    // Check for task completion (end_turn = agent says it\'s done)\n    if (response.stop_reason === \'end_turn\') {\n      const textBlock = response.content.find((b) => b.type === \'text\');\n      log.push({\n        phase: \'repeat\',\n        content: textBlock?.type === \'text\'\n          ? textBlock.text\n          : \'Task complete\',\n      });\n      return { success: true, log };\n    }\n\n    // ACT: extract the single tool call\n    if (response.stop_reason === \'tool_use\') {\n      const toolUse = response.content.find((b) => b.type === \'tool_use\');\n      if (!toolUse || toolUse.type !== \'tool_use\') continue;\n\n      log.push({\n        phase: \'act\',\n        content: `${toolUse.name}(${JSON.stringify(toolUse.input)})`,\n        toolCall: {\n          name: toolUse.name,\n          input: toolUse.input as Record<string, unknown>,\n        },\n      });\n\n      // Execute the tool and get result\n      const result = await executeTool(toolUse.name, toolUse.input);\n\n      // OBSERVE: log the result for the audit trail\n      log.push({ phase: \'observe\', content: result, toolResult: result });\n\n      // Feed result back to the model for next TAOR cycle\n      messages.push({ role: \'assistant\', content: response.content });\n      messages.push({\n        role: \'user\',\n        content: [{\n          type: \'tool_result\',\n          tool_use_id: toolUse.id,\n          content: result,\n        }],\n      });\n    }\n  }\n\n  log.push({\n    phase: \'repeat\',\n    content: `Stopped after ${maxIterations} iterations`,\n  });\n  return { success: false, log };\n}', language: 'typescript' },
      { type: 'text', content: '## Phase 3: OBSERVE -- Every Result Is Suspect\n\nThe OBSERVE phase in a Jira workflow is where most agents fail. Observation is not "I wrote the file, moving on." Observation is critical analysis:\n\n- **After reading a file:** Does the structure match what the ticket implies? Are there dependencies I did not expect? Is the file larger or more complex than anticipated?\n- **After searching the codebase:** Did the search find existing patterns I should follow? Are there utility functions I should reuse instead of writing from scratch? Did the search return zero results (meaning I might have the wrong search term)?\n- **After writing code:** Does the file read back match what I intended? Are there any syntax errors visible? Does the code follow the conventions I observed in other files?\n- **After running tests:** Did ALL tests pass, or just the new ones? If a test failed, is it my new code or did I break an existing test? What is the specific error message and line number?\n\nThe discipline of observation is what separates a TAOR agent from a "write and pray" agent. Every tool result is a data point that either confirms or challenges the agent\'s current understanding. A good OBSERVE step updates the agent\'s mental model. A bad OBSERVE step ignores the result and barrels ahead.\n\n## Phase 4: REPEAT -- Acceptance Criteria as Exit Conditions\n\nThe REPEAT phase in a Jira workflow maps directly to the ticket\'s acceptance criteria. The agent continues cycling through TAOR until every acceptance criterion is verified:\n\n- Rate limiting middleware exists and is wired to the endpoint: **verified by reading the route file**\n- 429 response with Retry-After header: **verified by reading the test that checks it**\n- Audit trail logging: **verified by reading the middleware and seeing the audit call**\n- All tests pass: **verified by running `npm test` and seeing zero failures**\n\nWhen all four are confirmed, the agent stops. Not before. Not "I think I\'m done." The agent checks each criterion against actual evidence from OBSERVE steps.\n\n### The Retry Loop\n\nWhen tests fail, the REPEAT phase becomes a bounded retry loop:\n1. OBSERVE the test failure (read the error output)\n2. THINK about the root cause (not "let me just try something")\n3. ACT to fix ONE specific issue\n4. OBSERVE the fix (read the file back)\n5. Run tests again\n6. If still failing after 3 attempts at the same issue, STOP and report\n\nThe bounded retry (maximum 3 attempts) prevents infinite loops. The requirement to diagnose before fixing prevents blind retries. Together, they make the agent both persistent and intelligent about failure recovery.' },
      { type: 'code', content: '// Mapping Jira acceptance criteria to TAOR exit conditions\n\ninterface AcceptanceCriterion {\n  description: string;\n  verificationMethod: \'file_contains\' | \'test_passes\' | \'command_output\';\n  verificationTarget: string;\n  verificationExpected: string;\n  verified: boolean;\n}\n\nfunction buildExitCriteria(ticket: string): AcceptanceCriterion[] {\n  // In a real system, the agent parses these from the ticket\n  // during the initial THINK phase\n  return [\n    {\n      description: \'Rate limiting middleware exists\',\n      verificationMethod: \'file_contains\',\n      verificationTarget: \'src/middleware/rate-limit.ts\',\n      verificationExpected: \'rateLimit\',\n      verified: false,\n    },\n    {\n      description: \'Middleware wired to payments route\',\n      verificationMethod: \'file_contains\',\n      verificationTarget: \'src/routes/payments.ts\',\n      verificationExpected: \'rateLimit\',\n      verified: false,\n    },\n    {\n      description: \'429 response with Retry-After header\',\n      verificationMethod: \'file_contains\',\n      verificationTarget: \'src/middleware/rate-limit.ts\',\n      verificationExpected: \'Retry-After\',\n      verified: false,\n    },\n    {\n      description: \'Audit trail logging on violations\',\n      verificationMethod: \'file_contains\',\n      verificationTarget: \'src/middleware/rate-limit.ts\',\n      verificationExpected: \'auditLog\',\n      verified: false,\n    },\n    {\n      description: \'All tests pass\',\n      verificationMethod: \'test_passes\',\n      verificationTarget: \'npm test\',\n      verificationExpected: \'0 failures\',\n      verified: false,\n    },\n  ];\n}\n\n// The REPEAT decision function\nfunction shouldContinue(\n  criteria: AcceptanceCriterion[],\n  retryCount: number,\n  maxRetries: number = 3\n): \'continue\' | \'done\' | \'escalate\' {\n  const allVerified = criteria.every((c) => c.verified);\n  if (allVerified) return \'done\';\n  if (retryCount >= maxRetries) return \'escalate\';\n  return \'continue\';\n}\n\n// Usage in the agent loop:\nconst criteria = buildExitCriteria(ticket);\nlet retries = 0;\n\nwhile (true) {\n  // ... TAOR cycle runs here ...\n\n  // After each OBSERVE, check if any criteria were just met\n  updateVerificationStatus(criteria, latestObservation);\n\n  const decision = shouldContinue(criteria, retries);\n  if (decision === \'done\') {\n    console.log(\'All acceptance criteria verified. Task complete.\');\n    break;\n  }\n  if (decision === \'escalate\') {\n    console.log(\'Max retries exceeded. Escalating to human.\');\n    console.log(\'Unmet criteria:\',\n      criteria.filter((c) => !c.verified).map((c) => c.description)\n    );\n    break;\n  }\n  // decision === \'continue\\\' -> next TAOR cycle\n}', language: 'typescript' },
      { type: 'tip', content: 'Before the agent writes any code, have it produce a numbered list of TAOR cycles it plans to execute: "1. Read payments route, 2. Search for existing rate limit patterns, 3. Read audit utility, 4. Write middleware, 5. Verify middleware, 6. Wire into route, 7. Verify route, 8. Write tests, 9. Run tests." This plan-first approach means you can review the agent\'s strategy before it starts executing, catching flawed plans early instead of debugging flawed code later.' },
      { type: 'warning', content: 'Never let an agent run `npm test` (or any test command) without first reading back all files it modified. If a test fails after an unverified write, you do not know whether the test is catching a real bug in your logic or whether the file was written incorrectly (wrong path, truncated content, syntax error). Verify every write BEFORE running tests. This order matters.' },
      { type: 'agent-demo', content: 'jira-taor-demo' }
    ],
    quiz: [
      { id: 'jira-taor-q1', question: 'A TAOR agent receives a Jira ticket. What should its FIRST action be?', options: ['Start writing the implementation code immediately', 'Read the files mentioned in the ticket to understand the current codebase before making any changes', 'Run the existing test suite', 'Create a new branch in git'], correctIndex: 1, explanation: 'The first step is always THINK then ACT to fill knowledge gaps. Before writing any code, the agent must read existing files to understand the current implementation, conventions, and dependencies. Writing code without reading first produces changes that conflict with the existing codebase.' },
      { id: 'jira-taor-q2', question: 'An agent writes a new middleware file and then immediately runs `npm test`. The tests fail. What TAOR violation occurred, and why does it matter?', options: ['The agent skipped THINK -- it should have planned the middleware better', 'The agent skipped OBSERVE after the write -- it never verified the file was written correctly, so the test failure could be a write error rather than a logic error', 'The agent should have written tests before writing the middleware', 'The agent should have asked a human for approval'], correctIndex: 1, explanation: 'The agent skipped the OBSERVE phase after writing the file. Without reading the file back to verify it was written correctly, the test failure is ambiguous: it could be a logic bug in the middleware OR a write failure (wrong path, truncated file, syntax error). Always verify writes before running tests so you know test failures reflect actual logic issues.' },
      { id: 'jira-taor-q3', question: 'How does a TAOR agent decide when to stop working on a Jira ticket?', options: ['After a fixed number of tool calls', 'When the LLM outputs the word "done"', 'When every acceptance criterion from the ticket has been individually verified through OBSERVE steps, with evidence from actual tool results', 'When all files have been modified'], correctIndex: 2, explanation: 'The REPEAT phase maps directly to the ticket\'s acceptance criteria. The agent stops when every criterion has been verified through actual OBSERVE evidence: files read back to confirm changes, tests run to confirm they pass. "I think I\'m done" is not sufficient -- each criterion must be checked against real tool output.' }
    ]
  },
{
    id: 'debugging-agents',
    moduleId: 'taor-pattern',
    title: 'Debugging Agent Reasoning',
    description: 'Diagnose which TAOR step broke, classify failures, and build systematic debugging checklists',
    order: 4,
    content: [
      { type: 'text', content: '## Why Agents Fail Silently\n\nWhen a traditional program breaks, it throws an error with a stack trace pointing to the exact line. When an agent breaks, it **keeps going** -- confidently producing wrong answers, hallucinating tool outputs, or spinning in circles. There is no stack trace. There is no red squiggly line. The agent looks like it is working until you inspect the output and realize it rewrote the wrong file, ignored a test failure, or invented an API endpoint that does not exist.\n\nThis is the fundamental debugging challenge with agents: **failures are semantic, not syntactic.** The code runs fine. The LLM responds. The tools execute. But the reasoning is wrong at some step, and that error compounds through every subsequent step.\n\nThe key insight is that every agent failure can be traced to a specific TAOR step. If you know the taxonomy of failures and can map a bad output back to the step that caused it, debugging agents becomes systematic instead of guesswork.\n\n### The TAOR Failure Taxonomy\n\nEvery agent failure maps to one of six categories. Each category corresponds to a specific TAOR step and has distinct symptoms. Learn these and you can diagnose most agent failures in under two minutes.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:620px;">\n<div style="border:2px solid #6c5ce7;border-radius:12px;overflow:hidden;">\n<div style="background:#6c5ce7;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">TAOR Failure Taxonomy</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;white-space:nowrap;">Hallucination</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;color:#e17055;font-weight:600;">THINK</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Agent invents facts, file paths, API endpoints, or function signatures that do not exist. It never checked reality.</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;white-space:nowrap;">Blind Execution</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;color:#e17055;font-weight:600;">THINK</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Agent acts without thinking first. It jumps to writing code before reading the existing file, or calls a tool without reasoning about which tool is appropriate.</td>\n</tr>\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;white-space:nowrap;">Wrong Tool</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;color:#00cec9;font-weight:600;">ACT</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Agent picks the wrong tool or passes wrong arguments. It uses <code>write_file</code> when it should <code>patch_file</code>, or searches with a regex that matches nothing.</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;white-space:nowrap;">Ignored Error</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;color:#fdcb6e;font-weight:600;">OBSERVE</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Tool returns an error or unexpected result and the agent does not notice. It proceeds as if the operation succeeded. This is the most dangerous failure because it is invisible.</td>\n</tr>\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;white-space:nowrap;">Infinite Loop</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;color:#fd79a8;font-weight:600;">REPEAT</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Agent keeps retrying the same failing action without changing its approach. The REPEAT step does not incorporate the OBSERVE feedback, so each attempt is identical.</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;font-weight:700;color:#6c5ce7;white-space:nowrap;">Premature Exit</td>\n<td style="padding:0.5rem 0.7rem;color:#fd79a8;font-weight:600;">REPEAT</td>\n<td style="padding:0.5rem 0.7rem;">Agent declares the task done before it actually is. It wrote the function but did not export it. It fixed the bug but did not run the tests. The REPEAT decision-making is too eager to stop.</td>\n</tr>\n</table>\n</div>\n</div>\n\nNotice the pattern: **THINK** failures are about reasoning quality (hallucination, not planning). **ACT** failures are about tool selection and arguments. **OBSERVE** failures are about reading results carefully. **REPEAT** failures are about the loop control logic itself -- either too aggressive (infinite loop) or too conservative (premature exit).' },
      { type: 'text', content: '## Extended Thinking as a Debugging Microscope\n\nClaude\'s Extended Thinking feature is the single most powerful debugging tool for agent failures. When you enable `thinking` in the API request, Claude exposes its internal reasoning process -- the step-by-step logic that leads to each decision. This is the agent equivalent of a stack trace.\n\nWithout Extended Thinking, you see:\n1. Agent called `read_file(\'src/api/users.ts\')`\n2. Agent called `write_file(\'src/api/users.ts\', ...)`\n3. Output: broken code\n\nWith Extended Thinking, you see:\n1. **THINK:** "The user wants pagination. I need to find the users endpoint. I think it\'s in `src/api/users.ts`..." (you can see if the agent is guessing or reasoning)\n2. **ACT:** `read_file(\'src/api/users.ts\')` (you can verify the action matches the thinking)\n3. **OBSERVE:** File content returned (you can check if the agent actually processed the result)\n4. **THINK:** "I see the endpoint uses `findAll()`. I need to add `skip` and `take` parameters..." (you can verify the analysis is correct)\n\nThe thinking trace turns opaque failures into transparent reasoning chains. When something goes wrong, you read the thinking trace and find the exact moment where the reasoning diverged from reality.\n\n### Practical Debugging Checklist\n\nWhen an agent produces bad output, work through this checklist in order. Each step takes 30-60 seconds and covers one failure category.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #27ae60;border-radius:12px;padding:1rem;">\n<div style="font-weight:700;color:#27ae60;font-size:0.95rem;margin-bottom:0.8rem;">Agent Debugging Checklist</div>\n<div style="display:flex;flex-direction:column;gap:0.5rem;font-size:0.85rem;">\n<div style="display:flex;gap:0.5rem;align-items:flex-start;"><span style="color:#27ae60;font-weight:700;min-width:1.5rem;">1.</span><span><b style="color:#e17055;">Check THINK:</b> Enable Extended Thinking. Read the first reasoning block. Did the agent understand the task correctly? Did it hallucinate any facts about the codebase?</span></div>\n<div style="display:flex;gap:0.5rem;align-items:flex-start;"><span style="color:#27ae60;font-weight:700;min-width:1.5rem;">2.</span><span><b style="color:#00cec9;">Check ACT:</b> Look at the first tool call. Is it the right tool? Are the arguments correct? Did the agent read before writing?</span></div>\n<div style="display:flex;gap:0.5rem;align-items:flex-start;"><span style="color:#27ae60;font-weight:700;min-width:1.5rem;">3.</span><span><b style="color:#fdcb6e;">Check OBSERVE:</b> Look at each tool result. Did the agent acknowledge errors? Did it adapt its plan when it found unexpected content?</span></div>\n<div style="display:flex;gap:0.5rem;align-items:flex-start;"><span style="color:#27ae60;font-weight:700;min-width:1.5rem;">4.</span><span><b style="color:#fd79a8;">Check REPEAT:</b> Count the iterations. Is the agent stuck in a loop doing the same thing? Did it stop too early?</span></div>\n<div style="display:flex;gap:0.5rem;align-items:flex-start;"><span style="color:#27ae60;font-weight:700;min-width:1.5rem;">5.</span><span><b style="color:#6c5ce7;">Check system prompt:</b> Does the system prompt give the agent enough context to succeed? Are the tool descriptions clear about what each tool does and when to use it?</span></div>\n</div>\n</div>\n</div>\n\nMost agent bugs are found at step 1 or step 3. Either the agent misunderstood the task (THINK failure) or it ignored a tool error (OBSERVE failure). Steps 2 and 4 catch the rest.' },
      { type: 'code', content: '// Enable Extended Thinking for agent debugging\nimport Anthropic from \'@anthropic-ai/sdk\';\n\nconst client = new Anthropic();\n\n// Run the agent with Extended Thinking enabled\nconst response = await client.messages.create({\n  model: \'claude-sonnet-4-6-20250514\',\n  max_tokens: 16000,\n  thinking: {\n    type: \'enabled\',\n    budget_tokens: 10000, // How much \'thinking space\' the model gets\n  },\n  system: \'You are a coding agent. Use tools to complete the task.\',\n  tools: [readFileTool, writeFileTool, searchTool],\n  messages: [{ role: \'user\', content: \'Add pagination to /api/users\' }],\n});\n\n// Extract the thinking trace for debugging\nfor (const block of response.content) {\n  if (block.type === \'thinking\') {\n    console.log(\'=== AGENT THINKING ===\");\n    console.log(block.thinking);\n    // This reveals the agent\'s reasoning:\n    // \"I need to find the users endpoint. Let me search for it...\"\n    // \"The file uses Express. I see findAll() on line 23...\"\n    // \"I should add skip/take parameters to the query...\"\n  }\n  if (block.type === \'tool_use\') {\n    console.log(`=== TOOL CALL: ${block.name} ===`);\n    console.log(JSON.stringify(block.input, null, 2));\n  }\n  if (block.type === \'text\') {\n    console.log(\'=== AGENT RESPONSE ===\");\n    console.log(block.text);\n  }\n}\n\n// Debugging helper: log the full TAOR trace\nfunction logTaorTrace(\n  messages: Anthropic.MessageParam[],\n  response: Anthropic.Message\n): void {\n  let step = 1;\n  for (const block of response.content) {\n    if (block.type === \'thinking\') {\n      console.log(`\\n[Step ${step}] THINK:`);\n      // Truncate for readability, but keep enough to spot issues\n      const preview = block.thinking.slice(0, 500);\n      console.log(preview + (block.thinking.length > 500 ? \'...\' : \'\'));\n    }\n    if (block.type === \'tool_use\') {\n      console.log(`[Step ${step}] ACT: ${block.name}(${JSON.stringify(block.input)})`);\n    }\n    if (block.type === \'text\') {\n      console.log(`[Step ${step}] FINAL: ${block.text.slice(0, 200)}`);\n    }\n    step++;\n  }\n}\n\n// After each tool result, log the OBSERVE step:\nfunction logObserve(toolName: string, result: string): void {\n  const isError = result.includes(\'Error\') || result.includes(\'not found\');\n  console.log(`[OBSERVE] ${toolName} => ${isError ? \'ERROR: \' : \'\'}${result.slice(0, 300)}`);\n  if (isError) {\n    console.warn(\'  ^ Watch if the agent acknowledges this error in next THINK step\');\n  }\n}', language: 'typescript' },
      { type: 'text', content: '## Common Anti-Patterns and How to Fix Them\n\nThese are the patterns that cause the most agent failures in production. Each one maps to a specific TAOR failure category and has a concrete fix.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:620px;">\n<div style="border:2px solid #e17055;border-radius:12px;overflow:hidden;">\n<div style="background:#e17055;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Anti-Pattern Hall of Shame</div>\n<div style="padding:0.8rem;display:flex;flex-direction:column;gap:0.8rem;font-size:0.85rem;">\n<div style="border-left:3px solid #e17055;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">1. \"Write first, read never\"</div>\n<div style="color:#666;margin:0.2rem 0;">Agent overwrites a file without reading it first. Destroys existing code. <b>THINK failure</b> -- the agent did not plan to gather context before acting.</div>\n<div style="color:#27ae60;font-weight:600;">Fix: System prompt must say \"Always read a file before modifying it.\"</div>\n</div>\n<div style="border-left:3px solid #fdcb6e;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">2. \"Error? What error?\"</div>\n<div style="color:#666;margin:0.2rem 0;">Tool returns <code>File not found</code> and the agent proceeds as if it read the file. <b>OBSERVE failure</b> -- the agent did not process the result.</div>\n<div style="color:#27ae60;font-weight:600;">Fix: Add error-checking instructions to system prompt: \"If a tool returns an error, stop and reassess.\"</div>\n</div>\n<div style="border-left:3px solid #fd79a8;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">3. \"Same thing, expect different results\"</div>\n<div style="color:#666;margin:0.2rem 0;">Agent retries the exact same tool call after it fails, hoping for a different result. <b>REPEAT failure</b> -- the loop does not learn from observation.</div>\n<div style="color:#27ae60;font-weight:600;">Fix: Add to system prompt: \"If a tool call fails, try a different approach. Never repeat the exact same call.\"</div>\n</div>\n<div style="border-left:3px solid #0984e3;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">4. \"I\'ll just assume the API shape\"</div>\n<div style="color:#666;margin:0.2rem 0;">Agent hallucinates function signatures or API endpoints instead of looking them up. <b>THINK failure</b> -- the agent relied on training data instead of checking reality.</div>\n<div style="color:#27ae60;font-weight:600;">Fix: System prompt: \"Never assume function signatures. Use search tools to verify before calling.\"</div>\n</div>\n<div style="border-left:3px solid #6c5ce7;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">5. \"Done!\" (it\'s not done)</div>\n<div style="color:#666;margin:0.2rem 0;">Agent declares completion after writing code but does not verify it works. No tests run, no compilation check. <b>REPEAT failure</b> -- premature exit.</div>\n<div style="color:#27ae60;font-weight:600;">Fix: System prompt: \"Before declaring done, verify your changes by running tests or type-checking.\"</div>\n</div>\n</div>\n</div>\n</div>\n\n### Key Takeaways\n\n1. **Every agent failure maps to a specific TAOR step.** Learn the six failure categories and you can diagnose any agent bug systematically.\n2. **Extended Thinking is your debugger.** It exposes the reasoning chain, letting you see exactly where the agent\'s logic diverged from reality.\n3. **Most failures are THINK or OBSERVE.** The agent either misunderstood the task or ignored a tool error. Check these two steps first.\n4. **Anti-patterns are fixable with system prompt instructions.** \"Read before write,\" \"check errors,\" \"verify before done\" -- these three rules prevent 80% of failures.\n5. **Log everything.** In production, log the thinking trace, tool calls, tool results, and final output. When something breaks at 2 AM, logs are all you have.' },
      { type: 'tip', content: 'When debugging a multi-step agent failure, start from the end and work backward. Look at the bad output, then find the last tool call that produced correct results. The bug is in the THINK or ACT step immediately after that last-good-point. This \"binary search\" approach is much faster than reading the entire trace from the beginning.' },
      { type: 'warning', content: 'Extended Thinking tokens count toward your token usage and cost. In production, enable Extended Thinking only for debugging sessions or for critical paths where reasoning transparency is worth the extra cost. For routine agent runs where you trust the pipeline, disable it to save tokens and reduce latency.' }
    ],
    quiz: [
      { id: 'q1', question: 'An agent calls write_file without first reading the existing file, overwriting important code. Which TAOR failure category is this?', options: ['Wrong Tool (ACT)', 'Hallucination (THINK)', 'Blind Execution (THINK)', 'Ignored Error (OBSERVE)'], correctIndex: 2, explanation: 'Blind Execution is a THINK failure where the agent acts without planning first. It jumped straight to writing without reasoning that it should read the existing file to understand what is already there. The fix is a system prompt instruction: "Always read a file before modifying it."' },
      { id: 'q2', question: 'A tool returns "Error: file not found" but the agent proceeds as if the file was read successfully. Which TAOR step failed?', options: ['THINK -- the agent reasoned incorrectly', 'ACT -- the agent used the wrong tool', 'OBSERVE -- the agent did not process the tool result', 'REPEAT -- the agent should have retried'], correctIndex: 2, explanation: 'This is an OBSERVE failure. The tool executed correctly (it returned an error because the file does not exist), but the agent did not process the error in the result. It continued its plan as if the read succeeded, compounding the error in every subsequent step.' },
      { id: 'q3', question: 'What is the fastest way to find the root cause of a multi-step agent failure?', options: ['Read the entire trace from beginning to end', 'Start from the bad output and work backward to find the last correct tool result', 'Re-run the agent with a different model', 'Add more tools to give the agent more options'], correctIndex: 1, explanation: 'Working backward from the bad output to the last correct tool result is the fastest approach. The bug is in the THINK or ACT step immediately after the last point where everything was still correct. This \"binary search\" approach avoids reading potentially dozens of correct steps at the beginning of the trace.' }
    ]
  },
  {
    id: 'team-agents',
    moduleId: 'taor-pattern',
    title: 'Team Agents: Organizing Multiple TAOR Loops',
    description: 'Orchestrate multiple agents each running their own TAOR loop, with structured state as the communication layer',
    order: 5,
    content: [
      { type: 'text', content: '## Why One Agent Is Not Enough\n\nA single TAOR agent is powerful. It can read files, write code, run tests, and iterate until the task is done. But as tasks grow in complexity, a single agent hits a wall:\n\n- **Context window overflow:** A single agent working on a large feature accumulates thousands of tokens of tool results, code snippets, and reasoning history. Eventually the context fills up and the agent starts forgetting earlier decisions.\n- **Jack-of-all-trades problem:** A single system prompt cannot make an agent equally good at architectural planning, low-level coding, test design, security review, and documentation. Each discipline requires different instructions, examples, and tool sets.\n- **No separation of concerns:** When something goes wrong, you cannot tell whether the planning was bad, the code was bad, or the tests were bad. Everything is tangled in one long conversation.\n\nThe solution is the same pattern that works for human teams: **specialization**. Instead of one agent doing everything, you create multiple agents that each do one thing well, and an **orchestrator** that delegates work between them.\n\n### The Orchestrator Pattern\n\nAn orchestrator is a higher-level agent (or a simple state machine) that:\n1. **Receives** the overall task\n2. **Decomposes** it into sub-tasks\n3. **Delegates** each sub-task to a specialist agent\n4. **Collects** results via structured state\n5. **Routes** to the next specialist based on the results\n6. **Enforces** quality gates (tests pass? review approved?)\n\nEach specialist runs its own TAOR loop internally. The orchestrator does not care *how* the specialist does its work -- only *what* it produces. This is exactly how a tech lead manages a team: assign the task, check the deliverable, route the next step.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #0984e3;border-radius:12px;padding:1.2rem;background:rgba(9,132,227,0.03);">\n<div style="font-weight:700;font-size:1rem;color:#0984e3;margin-bottom:1rem;text-align:center;">Orchestrator + Specialists</div>\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.5rem;">\n<div style="padding:0.5rem 1.5rem;border-radius:8px;background:#0984e3;color:white;font-weight:700;font-size:0.9rem;">Orchestrator</div>\n<div style="font-size:0.75rem;color:#666;">Decomposes task, routes work, enforces quality gates</div>\n<div style="display:flex;gap:0.4rem;margin:0.3rem 0;">\n<span style="color:#0984e3;">&#8601;</span>\n<span style="color:#0984e3;margin:0 1rem;">&#8595;</span>\n<span style="color:#0984e3;">&#8600;</span>\n</div>\n<div style="display:flex;gap:0.8rem;flex-wrap:wrap;justify-content:center;">\n<div style="border:2px solid #6c5ce7;border-radius:8px;padding:0.5rem 0.7rem;min-width:100px;text-align:center;">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.82rem;">Planner</div>\n<div style="font-size:0.7rem;color:#888;margin-top:0.2rem;">TAOR loop<br/>Tools: search, read</div>\n</div>\n<div style="border:2px solid #00cec9;border-radius:8px;padding:0.5rem 0.7rem;min-width:100px;text-align:center;">\n<div style="font-weight:700;color:#00cec9;font-size:0.82rem;">Coder</div>\n<div style="font-size:0.7rem;color:#888;margin-top:0.2rem;">TAOR loop<br/>Tools: read, write</div>\n</div>\n<div style="border:2px solid #e17055;border-radius:8px;padding:0.5rem 0.7rem;min-width:100px;text-align:center;">\n<div style="font-weight:700;color:#e17055;font-size:0.82rem;">Tester</div>\n<div style="font-size:0.7rem;color:#888;margin-top:0.2rem;">TAOR loop<br/>Tools: read, run</div>\n</div>\n</div>\n<div style="margin-top:0.8rem;text-align:center;font-size:0.78rem;color:#0984e3;font-weight:600;">Communication: structured state objects, not free-form text</div>\n</div>\n</div>\n</div>' },
      { type: 'text', content: '## Structured State: The Communication Layer\n\nThe critical design decision in multi-agent systems is **how agents communicate**. The wrong answer is passing free-form text between them. The right answer is **structured state** -- typed objects with explicit fields that each agent reads from and writes to.\n\nWhy? Because free-form text between agents creates the same problem as untyped function boundaries in code: **compounding interpretation errors.** Agent A writes "I found 3 issues, the most critical is the SQL injection in line 42." Agent B receives this as a string and has to parse it -- and might misinterpret "3 issues" or miss that line 42 was the critical one. By the time Agent C receives B\'s interpretation of A\'s text, the original signal is degraded.\n\nStructured state eliminates this entirely:\n\n```\n// Bad: free-form text between agents\nstate.reviewOutput = \'Found 3 issues. Critical: SQL injection line 42...\';\n\n// Good: structured state with typed fields\nstate.review = {\n  issues: [\n    { severity: \'critical\', type: \'sql-injection\', file: \'api.ts\', line: 42 },\n    { severity: \'medium\', type: \'missing-validation\', file: \'api.ts\', line: 18 },\n    { severity: \'low\', type: \'naming-convention\', file: \'api.ts\', line: 7 }\n  ],\n  criticalCount: 1,\n  passed: false\n};\n```\n\nWith structured state, Agent B does not need to parse text. It reads `state.review.issues.filter(i => i.severity === \'critical\')` and gets an exact, unambiguous list. No interpretation. No signal loss.\n\n### One Powerful Agent vs. Many Specialists\n\nThis is the most common design question in multi-agent systems. The answer depends on your task.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:600px;">\n<div style="border:2px solid #fdcb6e;border-radius:12px;overflow:hidden;">\n<div style="background:#fdcb6e;color:#333;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Decision Framework: One Agent vs. Many</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(253,203,110,0.1);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;">Factor</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#27ae60;">Use One Agent When</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:700;color:#0984e3;">Use Multiple When</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:600;">Task complexity</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Simple, single-domain</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Multi-domain (plan + code + test)</td>\n</tr>\n<tr style="background:rgba(253,203,110,0.06);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:600;">Context length</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Fits in one context window</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Too much for a single agent</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:600;">Tool count</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">5 or fewer tools</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">10+ tools from different domains</td>\n</tr>\n<tr style="background:rgba(253,203,110,0.06);">\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;font-weight:600;">Quality requirement</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Good enough with one pass</td>\n<td style="padding:0.5rem 0.7rem;border-bottom:1px solid #eee;">Needs review/validation loops</td>\n</tr>\n<tr>\n<td style="padding:0.5rem 0.7rem;font-weight:600;">Debuggability</td>\n<td style="padding:0.5rem 0.7rem;">Failures are easy to trace</td>\n<td style="padding:0.5rem 0.7rem;">Need to isolate which stage failed</td>\n</tr>\n</table>\n</div>\n</div>\n\nThe rule of thumb: **start with one agent. Split into multiple only when you can identify a specific quality problem** that specialization would solve (e.g., the single agent keeps writing bad tests, so you create a dedicated tester agent with a focused prompt and testing tools).' },
      { type: 'code', content: '// Multi-agent orchestrator with structured state\nimport Anthropic from \'@anthropic-ai/sdk\';\n\nconst client = new Anthropic();\n\n// --- Structured state: typed contracts between agents ---\ninterface TeamState {\n  task: string;\n  plan: {\n    steps: { description: string; files: string[]; agent: string }[];\n    estimatedComplexity: \'low\' | \'medium\' | \'high\';\n  } | null;\n  codeChanges: {\n    file: string;\n    diff: string;\n    linesChanged: number;\n  }[];\n  testResults: {\n    passed: boolean;\n    totalTests: number;\n    failedTests: { name: string; error: string }[];\n  } | null;\n  review: {\n    approved: boolean;\n    issues: { severity: string; description: string; file: string }[];\n  } | null;\n  retryCount: number;\n  status: \'planning\' | \'coding\' | \'testing\' | \'reviewing\' | \'done\' | \'failed\';\n}\n\n// --- Specialist agent runner ---\nasync function runSpecialist(\n  systemPrompt: string,\n  task: string,\n  tools: Anthropic.Tool[],\n  maxIterations = 15\n): Promise<string> {\n  const messages: Anthropic.MessageParam[] = [\n    { role: \'user\', content: task },\n  ];\n\n  for (let i = 0; i < maxIterations; i++) {\n    const response = await client.messages.create({\n      model: \'claude-sonnet-4-6-20250514\',\n      max_tokens: 8192,\n      system: systemPrompt,\n      tools,\n      messages,\n    });\n\n    messages.push({ role: \'assistant\', content: response.content });\n\n    if (response.stop_reason === \'end_turn\') {\n      const text = response.content.find(b => b.type === \'text\');\n      return text ? text.text : \'\';\n    }\n\n    if (response.stop_reason === \'tool_use\') {\n      const toolUses = response.content.filter(b => b.type === \'tool_use\');\n      const results: Anthropic.ToolResultBlockParam[] = [];\n      for (const tu of toolUses) {\n        const result = await executeTool(tu.name, tu.input);\n        results.push({\n          type: \'tool_result\',\n          tool_use_id: tu.id,\n          content: typeof result === \'string\' ? result : JSON.stringify(result),\n        });\n      }\n      messages.push({ role: \'user\', content: results });\n    }\n  }\n  return \'Agent reached max iterations\';\n}\n\n// --- Orchestrator: routes work between specialists ---\nasync function orchestrate(task: string): Promise<TeamState> {\n  const state: TeamState = {\n    task,\n    plan: null,\n    codeChanges: [],\n    testResults: null,\n    review: null,\n    retryCount: 0,\n    status: \'planning\',\n  };\n\n  // Step 1: Planner agent\n  state.status = \'planning\';\n  const planJson = await runSpecialist(\n    \'You are a software architect. Analyze the task and create a plan.\\n\' +\n    \'Return ONLY valid JSON: { \"steps\": [...], \"estimatedComplexity\": \"low\"|\"medium\"|\"high\" }\',\n    `Task: ${state.task}`,\n    [searchCodeTool, readFileTool]\n  );\n  state.plan = JSON.parse(planJson);\n\n  // Step 2-4: Code -> Test -> Review loop\n  while (state.retryCount < 3) {\n    // Coder agent\n    state.status = \'coding\';\n    const codeJson = await runSpecialist(\n      \'You are a senior developer. Follow the plan. Return changes as JSON array.\\n\' +\n      (state.testResults && !state.testResults.passed\n        ? `PREVIOUS TESTS FAILED:\\n${JSON.stringify(state.testResults.failedTests)}\\nFix these specific failures.`\n        : \'\'),\n      `Plan: ${JSON.stringify(state.plan)}`,\n      [readFileTool, writeFileTool, searchCodeTool]\n    );\n    state.codeChanges = JSON.parse(codeJson);\n\n    // Tester agent\n    state.status = \'testing\';\n    const testJson = await runSpecialist(\n      \'You are a QA engineer. Run tests and report results as JSON:\\n\' +\n      \'{ \"passed\": boolean, \"totalTests\": number, \"failedTests\": [...] }\',\n      `Test these changes: ${JSON.stringify(state.codeChanges)}`,\n      [readFileTool, writeFileTool, runCommandTool]\n    );\n    state.testResults = JSON.parse(testJson);\n\n    if (state.testResults!.passed) break;\n    state.retryCount++;\n  }\n\n  // Reviewer agent (only if tests pass)\n  if (state.testResults?.passed) {\n    state.status = \'reviewing\';\n    const reviewJson = await runSpecialist(\n      \'You are a code reviewer. Check quality and security. Return JSON:\\n\' +\n      \'{ \"approved\": boolean, \"issues\": [...] }\',\n      `Review: ${JSON.stringify(state.codeChanges)}`,\n      [readFileTool, searchCodeTool]\n    );\n    state.review = JSON.parse(reviewJson);\n  }\n\n  state.status = state.testResults?.passed ? \'done\' : \'failed\';\n  return state;\n}\n\n// --- Run it ---\nconst result = await orchestrate(\'Add rate limiting to POST /api/payments\');\nconsole.log(\'Status:\', result.status);\nconsole.log(\'Retries:\', result.retryCount);\nconsole.log(\'Tests:\', result.testResults);\nconsole.log(\'Review:\', result.review);', language: 'typescript' },
      { type: 'agent-demo', content: 'team-taor-demo' },
      { type: 'text', content: '## Practical Patterns for Team Agent Communication\n\nBeyond structured state, there are three communication patterns that appear in production multi-agent systems:\n\n**1. Pipeline (serial):** Agent A finishes completely, then Agent B starts. State is the handoff. This is the simplest and most debuggable pattern. Use it when each agent\'s output is the next agent\'s input and there is no parallelism opportunity.\n\n**2. Fan-out/Fan-in (parallel):** The orchestrator sends the same context to multiple agents simultaneously (e.g., security reviewer, performance reviewer, style reviewer), waits for all to finish, then merges their structured outputs. This is faster but requires careful state merging -- what if two reviewers give conflicting advice?\n\n**3. Iterative refinement (loop):** Agent A produces output, Agent B critiques it, and the critique goes back to Agent A for revision. This loop repeats until Agent B approves or a max iteration count is reached. This is the pattern behind \"generate -> review -> fix\" cycles.\n\n### State Merging Strategies\n\nWhen multiple agents write to state concurrently (fan-out pattern), you need a merge strategy:\n\n- **Last-write-wins:** Simple but lossy. Agent B\'s output overwrites Agent A\'s.\n- **Append (reducer):** Both outputs are collected into an array. Good for reviews, logs, and feedback.\n- **Structured merge:** A merge function combines outputs intelligently (e.g., take the highest severity issue from all reviewers).\n\nAlways use the **append** strategy for review feedback and logs. Use **structured merge** when you need to synthesize conflicting outputs. Avoid **last-write-wins** unless you are sure agents write to different fields.\n\n### Key Takeaways\n\n1. **Split into multiple agents when a single agent hits context limits, needs too many tools, or produces inconsistent quality** across different sub-tasks.\n2. **The orchestrator delegates, collects, and routes.** It does not do the actual work. Keep it simple -- a state machine or a few conditional checks.\n3. **Structured state, not free-form text,** is the communication layer between agents. Typed fields prevent compounding interpretation errors.\n4. **Start with one agent, split only when needed.** Each additional agent adds complexity to debugging and state management. The minimum viable team is usually 3 agents: plan, code, test.\n5. **Always bound retry loops.** The orchestrator must enforce a maximum retry count and escalate to a human or gracefully fail when it is exceeded.' },
      { type: 'tip', content: 'When designing your structured state interface, write it as a TypeScript interface first and review it like you would review an API contract. Every field should have a clear purpose, a clear type, and a clear owner (which agent writes it). If two agents write the same field, you need a reducer or you will get race conditions in fan-out patterns.' }
    ],
    quiz: [
      { id: 'q1', question: 'Why is structured state preferred over free-form text for communication between agents?', options: ['It uses fewer tokens', 'It prevents compounding interpretation errors -- each agent reads exact typed fields instead of parsing ambiguous text', 'It is required by the Anthropic API', 'It makes the code look cleaner'], correctIndex: 1, explanation: 'Free-form text between agents creates compounding interpretation errors, like a game of telephone. Each agent has to parse the previous agent\'s natural language, and misinterpretations accumulate. Structured state (typed fields like { severity: \'critical\\\', line: 42 }) is unambiguous -- agents read exact values, not interpretations.' },
      { id: 'q2', question: 'When should you split a single agent into multiple specialist agents?', options: ['Always -- multiple agents are always better', 'When the single agent hits context limits, needs too many tools, or has inconsistent quality across sub-tasks', 'Only when using Claude Opus', 'When you want to reduce API costs'], correctIndex: 1, explanation: 'Split when you have a specific quality problem that specialization solves: context overflow (too much history for one agent), tool overload (10+ tools from different domains), or inconsistent quality (great at planning but bad at testing). Each split adds debugging complexity, so only split when the benefit is clear.' },
      { id: 'q3', question: 'In the fan-out/fan-in pattern, multiple agents run in parallel. What is the key challenge?', options: ['Agents cannot run in parallel', 'Merging their structured outputs when they write to the same state fields', 'The orchestrator cannot handle multiple results', 'Parallel agents always produce worse quality'], correctIndex: 1, explanation: 'When multiple agents run concurrently and write to the same state fields, you need a merge strategy. Without one, the last agent to finish overwrites the others (last-write-wins). The append reducer pattern collects all outputs into an array, preserving every agent\'s contribution.' }
    ]
  },
  {
    id: 'structured-output',
    moduleId: 'taor-pattern',
    title: 'Structured Output & Reliable Extraction',
    description: 'Three approaches to getting JSON from LLMs: tool_choice forced, Zod validation loops, and tool_choice any -- with decision frameworks for when to use each',
    order: 6,
    content: [
      { type: 'text', content: '## Why Structured Output Is the Most Important Agent Skill\n\nHere is a truth that is not immediately obvious: **the reliability of your entire multi-agent system depends on structured output.** Every handoff between agents, every tool call result, every quality gate decision -- they all depend on the LLM producing correctly structured data that downstream code can parse.\n\nConsider what happens without structured output. Your reviewer agent returns: "I found some issues. The main one is a potential SQL injection on line 42 of the users file. There are also some style problems but they\'re minor." Now your orchestrator needs to decide: did the review pass? What severity are the issues? Which file? What line? You are back to parsing natural language, which means regex hacks, brittle string matching, or a second LLM call to extract structure from the first one\'s free-form text.\n\nThis is the same problem as untyped function boundaries in code. If every function returns `any`, your TypeScript project compiles but breaks at runtime in unpredictable ways. If every agent returns unstructured text, your pipeline runs but produces unpredictable outputs.\n\n**Structured output is type safety for LLM systems.**\n\nThe good news: Claude provides multiple mechanisms to guarantee structured output, ranging from 99.9% reliable to 100% reliable (with validation). The three primary approaches are:\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:600px;">\n<div style="border:2px solid #6c5ce7;border-radius:12px;overflow:hidden;">\n<div style="background:#6c5ce7;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Three Approaches to Structured Output</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;">Approach</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:700;">Reliability</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:700;">How It Works</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:700;">Best For</td>\n</tr>\n<tr>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:600;color:#27ae60;">tool_choice: { type: \'tool\', name: \'X\' }</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">~99.9%</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">Forces the model to call a specific tool. The tool\'s input_schema defines the JSON shape.</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">Known schemas, agent-to-agent handoffs</td>\n</tr>\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.6rem;border-bottom:1px solid #eee;font-weight:600;color:#0984e3;">Zod validation loop</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">100% (with retries)</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">Parse response with Zod. If invalid, send error back to model and retry. Loop until valid.</td>\n<td style="padding:0.6rem;border-bottom:1px solid #eee;">Complex schemas, custom validation rules</td>\n</tr>\n<tr>\n<td style="padding:0.6rem;font-weight:600;color:#e17055;">tool_choice: { type: \'any\' }</td>\n<td style="padding:0.6rem;">~99%</td>\n<td style="padding:0.6rem;">Model must call a tool but picks which one. Define multiple tools as multiple output schemas.</td>\n<td style="padding:0.6rem;">When the model should choose between different output formats</td>\n</tr>\n</table>\n</div>\n</div>\n\nEach approach trades off between reliability, flexibility, and complexity. The next sections show all three in code, so you can choose the right one for each situation.' },
      { type: 'code', content: '// ============================================\n// APPROACH 1: tool_choice forced (99.9% reliable)\n// ============================================\n// Force the model to output a specific JSON schema by\n// defining a \"dummy\" tool and forcing it to be called.\n\nimport Anthropic from \'@anthropic-ai/sdk\';\n\nconst client = new Anthropic();\n\n// Define the output schema as a tool\nconst reviewOutputTool: Anthropic.Tool = {\n  name: \'submit_review\',\n  description: \'Submit the code review results in structured format.\',\n  input_schema: {\n    type: \'object\' as const,\n    properties: {\n      approved: {\n        type: \'boolean\',\n        description: \'Whether the code passes review\',\n      },\n      issues: {\n        type: \'array\',\n        items: {\n          type: \'object\',\n          properties: {\n            severity: {\n              type: \'string\',\n              enum: [\'critical\', \'major\', \'minor\', \'style\'],\n            },\n            file: { type: \'string\' },\n            line: { type: \'number\' },\n            description: { type: \'string\' },\n            suggestion: { type: \'string\' },\n          },\n          required: [\'severity\', \'file\', \'description\'],\n        },\n      },\n      summary: { type: \'string\' },\n    },\n    required: [\'approved\', \'issues\', \'summary\'],\n  },\n};\n\nconst response = await client.messages.create({\n  model: \'claude-sonnet-4-6-20250514\',\n  max_tokens: 4096,\n  tools: [reviewOutputTool],\n  // Force the model to call this specific tool\n  tool_choice: { type: \'tool\', name: \'submit_review\' },\n  messages: [\n    {\n      role: \'user\',\n      content: \'Review this code for security issues:\\n\\n\' +\n        \'app.get(\\\"/users\\\", (req, res) => {\\n\' +\n        \'  const query = `SELECT * FROM users WHERE name = \\\\\'${req.query.name}\\\\\'`;\\n\' +\n        \'  db.query(query).then(rows => res.json(rows));\\n\' +\n        \'});\',\n    },\n  ],\n});\n\n// Extract the structured output -- guaranteed to match the schema\nconst toolUse = response.content.find(b => b.type === \'tool_use\')!;\nconst review = toolUse.input as {\n  approved: boolean;\n  issues: { severity: string; file: string; line?: number; description: string; suggestion?: string }[];\n  summary: string;\n};\n\nconsole.log(\'Approved:\', review.approved);  // false\nconsole.log(\'Issues:\', review.issues);       // [{ severity: \'critical\', ... }]\nconsole.log(\'Summary:\', review.summary);     // \"SQL injection vulnerability...\"', language: 'typescript' },
      { type: 'code', content: '// ============================================\n// APPROACH 2: Zod validation loop (100% reliable)\n// ============================================\n// Parse the model\'s response with Zod. If validation fails,\n// send the error message back and retry until it\'s valid.\n\nimport Anthropic from \'@anthropic-ai/sdk\';\nimport { z } from \'zod\';\n\nconst client = new Anthropic();\n\n// Define the expected schema with Zod\nconst ReviewSchema = z.object({\n  approved: z.boolean(),\n  issues: z.array(z.object({\n    severity: z.enum([\'critical\', \'major\', \'minor\', \'style\']),\n    file: z.string().min(1),\n    line: z.number().int().positive().optional(),\n    description: z.string().min(10),\n    suggestion: z.string().optional(),\n  })),\n  summary: z.string().min(20),\n  // Custom validation: if not approved, must have at least one issue\n}).refine(\n  data => data.approved || data.issues.length > 0,\n  { message: \'If not approved, must include at least one issue\' }\n);\n\ntype ReviewOutput = z.infer<typeof ReviewSchema>;\n\nasync function getStructuredOutput<T>(\n  schema: z.ZodType<T>,\n  systemPrompt: string,\n  userMessage: string,\n  maxRetries = 3\n): Promise<T> {\n  const messages: Anthropic.MessageParam[] = [\n    { role: \'user\', content: userMessage },\n  ];\n\n  for (let attempt = 0; attempt <= maxRetries; attempt++) {\n    const response = await client.messages.create({\n      model: \'claude-sonnet-4-6-20250514\',\n      max_tokens: 4096,\n      system: systemPrompt + \'\\n\\nRespond with ONLY valid JSON. No markdown, no explanation.\',\n      messages,\n    });\n\n    const text = response.content.find(b => b.type === \'text\');\n    if (!text) throw new Error(\'No text in response\');\n\n    try {\n      // Try to parse and validate\n      const parsed = JSON.parse(text.text);\n      return schema.parse(parsed);  // Throws ZodError if invalid\n    } catch (error) {\n      if (attempt === maxRetries) {\n        throw new Error(`Failed to get valid output after ${maxRetries} retries: ${error}`);\n      }\n\n      // Send the validation error back to the model\n      const errorMessage = error instanceof z.ZodError\n        ? `Validation failed:\\n${error.errors.map(e => `  - ${e.path.join(\'.\')}: ${e.message}`).join(\'\\n\')}\\n\\nFix these issues and respond with valid JSON only.`\n        : `Invalid JSON: ${error}. Respond with valid JSON only.`;\n\n      messages.push(\n        { role: \'assistant\', content: text.text },\n        { role: \'user\', content: errorMessage }\n      );\n    }\n  }\n\n  throw new Error(\'Unreachable\');\n}\n\n// Usage\nconst review = await getStructuredOutput(\n  ReviewSchema,\n  \'You are a code reviewer. Analyze the code for issues.\',\n  \'Review this code: ...\'\n);\n// review is guaranteed to be a valid ReviewOutput\nconsole.log(review.approved);    // boolean, guaranteed\nconsole.log(review.issues[0]);   // typed, guaranteed to have severity/file/description\n\n\n// ============================================\n// APPROACH 3: tool_choice \'any\' (model picks)\n// ============================================\n// Define multiple tools as possible output schemas.\n// The model chooses which one fits its response.\n\nconst passReviewTool: Anthropic.Tool = {\n  name: \'pass_review\',\n  description: \'Submit a passing review with optional minor suggestions.\',\n  input_schema: {\n    type: \'object\' as const,\n    properties: {\n      summary: { type: \'string\' },\n      suggestions: { type: \'array\', items: { type: \'string\' } },\n    },\n    required: [\'summary\'],\n  },\n};\n\nconst failReviewTool: Anthropic.Tool = {\n  name: \'fail_review\',\n  description: \'Submit a failing review with blocking issues.\',\n  input_schema: {\n    type: \'object\' as const,\n    properties: {\n      summary: { type: \'string\' },\n      blockingIssues: {\n        type: \'array\',\n        items: {\n          type: \'object\',\n          properties: {\n            severity: { type: \'string\', enum: [\'critical\', \'major\'] },\n            description: { type: \'string\' },\n            file: { type: \'string\' },\n          },\n          required: [\'severity\', \'description\', \'file\'],\n        },\n      },\n    },\n    required: [\'summary\', \'blockingIssues\'],\n  },\n};\n\nconst response3 = await client.messages.create({\n  model: \'claude-sonnet-4-6-20250514\',\n  max_tokens: 4096,\n  tools: [passReviewTool, failReviewTool],\n  // Model MUST call a tool, but it picks which one\n  tool_choice: { type: \'any\' },\n  messages: [{ role: \'user\', content: \'Review this code: ...\' }],\n});\n\nconst toolCall = response3.content.find(b => b.type === \'tool_use\')!;\n\n// The tool name tells you which schema the model chose\nif (toolCall.name === \'pass_review\') {\n  const result = toolCall.input as { summary: string; suggestions?: string[] };\n  console.log(\'PASSED:\', result.summary);\n} else if (toolCall.name === \'fail_review\') {\n  const result = toolCall.input as { summary: string; blockingIssues: { severity: string; description: string; file: string }[] };\n  console.log(\'FAILED:\', result.blockingIssues.length, \'blocking issues\');\n}', language: 'typescript' },
      { type: 'text', content: '## JSON Schema as Typed Contracts\n\nThe mental model that makes structured output click is this: **JSON Schema is to LLM communication what TypeScript interfaces are to function boundaries.** When you define a tool\'s `input_schema`, you are writing a type contract that both the model and your code agree on.\n\nThis means you should treat schemas with the same rigor you treat TypeScript types:\n\n- **Be specific with enums:** Use `enum: [\'critical\\\', \'major\\\', \'minor\\\']` instead of `type: \'string\\\'`. The model will only output values from the enum, and your switch statement can be exhaustive.\n- **Use required fields:** Mark every field that downstream code depends on as required. The model will always include them.\n- **Add descriptions:** The `description` field on each property tells the model what you expect. "The file path relative to the project root" is much better than just "file".\n- **Use nested objects for complex data:** Do not flatten everything into top-level fields. `{ review: { issues: [...], approved: boolean } }` is clearer than `{ reviewIssues: [...], reviewApproved: boolean }`.\n\n### Decision Framework: Which Approach When?\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:620px;">\n<div style="border:2px solid #00cec9;border-radius:12px;overflow:hidden;">\n<div style="background:#00cec9;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">When to Use Each Approach</div>\n<div style="padding:0.8rem;display:flex;flex-direction:column;gap:0.8rem;font-size:0.85rem;">\n<div style="border-left:3px solid #27ae60;padding-left:0.8rem;">\n<div style="font-weight:700;color:#27ae60;">Use tool_choice: { type: \'tool\\\' } when:</div>\n<div style="color:#666;margin-top:0.2rem;">You know exactly what schema you want. Agent-to-agent handoffs, API responses, database records. This is your default choice for 80% of cases. Highest reliability with the least code.</div>\n</div>\n<div style="border-left:3px solid #0984e3;padding-left:0.8rem;">\n<div style="font-weight:700;color:#0984e3;">Use Zod validation loop when:</div>\n<div style="color:#666;margin-top:0.2rem;">You need custom validation rules beyond what JSON Schema supports (e.g., \"if approved is false, issues array must not be empty\"). Or when you need 100% reliability guarantee with automatic error correction. Adds latency from retries but guarantees validity.</div>\n</div>\n<div style="border-left:3px solid #e17055;padding-left:0.8rem;">\n<div style="font-weight:700;color:#e17055;">Use tool_choice: { type: \'any\\\' } when:</div>\n<div style="color:#666;margin-top:0.2rem;">The model should choose between different output formats based on its analysis. Pass vs. fail reviews. Simple vs. complex responses. The tool name becomes a discriminated union tag that your code can switch on.</div>\n</div>\n</div>\n</div>\n</div>\n\n### Key Takeaways\n\n1. **Structured output is type safety for LLM systems.** Without it, every agent boundary is an `any` type that can break at runtime.\n2. **tool_choice forced (`{ type: \'tool\\\', name: \'X\\\' }`) is your default.** It is 99.9% reliable, requires minimal code, and the schema is self-documenting.\n3. **Zod validation loops guarantee 100% validity** by sending parse errors back to the model for correction. Use them for complex validation rules or mission-critical outputs.\n4. **tool_choice any (`{ type: \'any\\\' }`) lets the model choose its output format.** Think of each tool as a variant in a discriminated union -- the tool name is the discriminator.\n5. **Treat JSON Schema like TypeScript interfaces:** be specific with enums, mark required fields, add descriptions, and use nested objects for structure.' },
      { type: 'tip', content: 'For the Zod validation loop, most models self-correct on the first retry when you include the specific Zod error messages. A well-structured error like "issues.0.severity: Expected \'critical\\\' | \'major\\\' | \'minor\\\', received \'high\\\'" gives the model exactly enough information to fix the output. Average retry count in production is 0.1 -- meaning 90% of the time, the first attempt is valid.' },
      { type: 'warning', content: 'Do not use tool_choice forced when the model also needs to use real tools (like read_file or search). Forced tool_choice makes the model call ONLY the specified tool -- it cannot call other tools first. If the model needs to gather information before producing structured output, either (a) gather the information in a separate API call, then use forced tool_choice in a second call, or (b) use the Zod validation loop approach with a text response.' }
    ],
    quiz: [
      { id: 'q1', question: 'Why is structured output described as "type safety for LLM systems"?', options: ['Because it uses TypeScript types internally', 'Because it prevents runtime parsing failures at agent boundaries, just like types prevent runtime errors at function boundaries', 'Because JSON Schema is the same as TypeScript', 'Because it makes the code compile faster'], correctIndex: 1, explanation: 'Just as TypeScript types prevent runtime type errors at function boundaries by enforcing contracts at compile time, structured output prevents runtime parsing failures at agent boundaries by enforcing JSON Schema contracts. Without structured output, every agent handoff is like an `any` type -- it might work, but it might produce unparseable text that crashes downstream code.' },
      { id: 'q2', question: 'What is the key advantage of the Zod validation loop over tool_choice forced?', options: ['It is faster', 'It uses fewer tokens', 'It supports custom cross-field validation rules (like "if not approved, must have issues") and guarantees 100% validity with retries', 'It works with more models'], correctIndex: 2, explanation: 'tool_choice forced validates against JSON Schema, which only checks individual field types and required fields. Zod supports cross-field validation through `.refine()` (e.g., "if approved is false, issues array must not be empty"). The retry loop sends Zod error messages back to the model, which self-corrects, guaranteeing 100% validity at the cost of occasional extra API calls.' },
      { id: 'q3', question: 'When should you use tool_choice: { type: \'any\' } instead of forcing a specific tool?', options: ['When you want faster responses', 'When the model should choose between different output formats based on its analysis, like pass vs. fail reviews', 'When you do not know the schema in advance', 'When you want the model to use real tools like read_file'], correctIndex: 1, explanation: 'tool_choice: { type: \'any\\\' } is ideal when you have multiple valid output formats and the model should pick the right one. Each tool acts as a variant in a discriminated union -- the tool name is the discriminator. For example, pass_review and fail_review have different schemas, and the model chooses which to call based on its analysis of the code.' }
    ]
  }
        ]
      },
      {
        id: 'langchain',
        title: 'LangChain: Building with Claude',
        description: 'Chains, agents, memory, and production patterns with LangChain',
        icon: '🔗',
        color: '#fdcb6e',
        order: 8,
        lessons: [
{
      id: 'langchain-fundamentals',
      moduleId: 'langchain',
      title: 'LangChain Fundamentals',
      description: 'What LangChain is, why it exists, and how to compose chains with LCEL pipe syntax',
      order: 1,
      content: [
        { type: 'text', content: '## Why Does LangChain Exist?\n\nBefore LangChain, every LLM application was a snowflake. You wrote custom glue code to format prompts, call models, parse outputs, manage memory, and orchestrate multi-step flows. When you switched models or added a retrieval step, you rewrote half your codebase.\n\nLangChain solves this with **composable abstractions** -- standardized building blocks that snap together like LEGO. Each block has a consistent interface: it takes input, transforms it, and produces output. You compose blocks into chains, and chains into complex workflows, all while keeping each piece independently testable and swappable.\n\n### When to Use LangChain vs the Raw Anthropic SDK\n\nThis is the most important decision you\'ll make. Here is a decision framework:\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:520px;">\n<div style="padding:0.75rem 1rem;border-radius:8px;border:2px solid #27ae60;background:rgba(39,174,96,0.06);">\n<div style="font-weight:700;color:#27ae60;margin-bottom:0.3rem;">Use the Raw SDK when:</div>\n<ul style="margin:0;padding-left:1.2rem;font-size:0.9rem;line-height:1.5;">\n<li>You have a single model call with tool use</li>\n<li>You need maximum control over request/response</li>\n<li>You want the smallest dependency footprint</li>\n<li>Your application is a simple request-response pattern</li>\n</ul>\n</div>\n<div style="padding:0.75rem 1rem;border-radius:8px;border:2px solid #fdcb6e;background:rgba(253,203,110,0.06);">\n<div style="font-weight:700;color:#e17055;margin-bottom:0.3rem;">Use LangChain when:</div>\n<ul style="margin:0;padding-left:1.2rem;font-size:0.9rem;line-height:1.5;">\n<li>You need to compose multiple steps (prompt + model + parser + retriever)</li>\n<li>You want built-in memory management across conversations</li>\n<li>You need to swap models/providers without rewriting logic</li>\n<li>You want structured agent loops with tool execution</li>\n<li>You need observability and tracing (LangSmith) out of the box</li>\n</ul>\n</div>\n</div>\n\nThe key insight: LangChain is not a replacement for the SDK -- it is a **composition layer on top of it**. Under the hood, LangChain\'s `ChatAnthropic` class calls the same Anthropic SDK. You are paying for abstraction in exchange for composability.' },
        { type: 'code', content: '// Setup: Install LangChain with Anthropic support\n// npm install langchain @langchain/anthropic @langchain/core\n\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { HumanMessage, SystemMessage } from \'@langchain/core/messages\';\n\n// Initialize Claude through LangChain\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n  maxTokens: 1024,\n  anthropicApiKey: process.env.ANTHROPIC_API_KEY,\n});\n\n// Simple invocation -- same as calling the raw API\nconst response = await model.invoke([\n  new SystemMessage(\'You are a senior TypeScript engineer.\'),\n  new HumanMessage(\'Explain the Builder pattern in 3 sentences.\'),\n]);\n\nconsole.log(response.content);\n// The Builder pattern separates the construction of a complex\n// object from its representation...', language: 'typescript' },
        { type: 'text', content: '## Core Concepts: The Six Building Blocks\n\nEvery LangChain application is built from six types of components. Understanding these is essential before writing a single line of chain code.\n\n### 1. Models\nThe LLM itself. LangChain wraps providers behind a unified interface (`BaseChatModel`). You can swap `ChatAnthropic` for `ChatOpenAI` without changing your chain logic. This is the **Strategy pattern** applied to LLMs.\n\n### 2. Prompt Templates\nParameterized prompts that accept variables. Instead of string concatenation, you define a template once and fill it with different inputs. `ChatPromptTemplate.fromMessages([ [\'system\', \'You are a {role}\'], [\'human\', \'{question}\'] ])` creates a reusable, type-safe prompt.\n\n### 3. Output Parsers\nTransform raw LLM text into structured data. `StringOutputParser` gives you plain text. `StructuredOutputParser` gives you typed JSON. `JsonOutputParser` validates against a schema. This is where you go from "unstructured AI output" to "reliable application data."\n\n### 4. Chains\nCompositions of the above. A chain is a sequence: prompt -> model -> parser. LangChain\'s LCEL (LangChain Expression Language) lets you pipe these together with the `|` operator, creating readable, composable workflows.\n\n### 5. Agents\nChains that can **decide** which tools to call. Instead of a fixed sequence, an agent receives tools, reasons about the task, and picks the right tool at each step. This is the TAOR pattern implemented through LangChain\'s abstractions.\n\n### 6. Retrievers\nComponents that fetch relevant context from external sources -- vector databases, search engines, SQL databases. Retrievers are the "R" in RAG (Retrieval-Augmented Generation), and LangChain standardizes the interface so you can swap Pinecone for Chroma for PostgreSQL pgvector without touching your chain logic.' },
        { type: 'code', content: '// LCEL (LangChain Expression Language) -- the pipe syntax\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { ChatPromptTemplate } from \'@langchain/core/prompts\';\nimport { StringOutputParser } from \'@langchain/core/output_parsers\';\n\n// Define each component\nconst prompt = ChatPromptTemplate.fromMessages([\n  [\'system\', \'You are a technical writer. Write concise, accurate explanations.\'],\n  [\'human\', \'Explain {concept} for a {audience} audience in {format} format.\'],\n]);\n\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0.3,\n});\n\nconst parser = new StringOutputParser();\n\n// Compose with LCEL pipe syntax: prompt -> model -> parser\nconst chain = prompt.pipe(model).pipe(parser);\n\n// Invoke the chain with variables\nconst result = await chain.invoke({\n  concept: \'dependency injection\',\n  audience: \'junior developer\',\n  format: \'bullet points\',\n});\n\nconsole.log(result);\n// - Dependency injection is a design pattern where...\n// - Instead of creating its own dependencies...\n\n// LCEL chains are also streamable\nconst stream = await chain.stream({\n  concept: \'event sourcing\',\n  audience: \'senior architect\',\n  format: \'paragraph\',\n});\n\nfor await (const chunk of stream) {\n  process.stdout.write(chunk); // Real-time streaming output\n}', language: 'typescript' },
        { type: 'tip', content: 'LCEL\'s pipe syntax is not just syntactic sugar. Each `.pipe()` call creates a new `RunnableSequence` that supports `.invoke()`, `.stream()`, `.batch()`, and `.streamLog()` automatically. You get streaming and batching for free on any chain you compose. This is the real power of the abstraction -- uniform interfaces across all compositions.' },
        { type: 'text', content: '### Common Mistake: Over-Abstracting\n\nThe biggest trap with LangChain is using it when you do not need it. If your application is "take user input, call Claude, return response," the raw SDK is simpler, faster to debug, and has fewer dependencies. LangChain earns its keep when you need **composition** -- multi-step chains, swappable components, built-in memory, or observability.\n\n### Key Takeaways\n\n1. **LangChain is a composition framework**, not a model wrapper. Its value is in snapping pieces together.\n2. **LCEL pipe syntax** (`prompt.pipe(model).pipe(parser)`) is the modern way to build chains -- it gives you streaming and batching for free.\n3. **Use the raw SDK for simple cases**. LangChain adds value at the composition layer.\n4. **Six building blocks**: Models, Prompts, Parsers, Chains, Agents, Retrievers. Everything else is a combination of these.\n5. **Provider-agnostic by design** -- swap Claude for GPT-4 by changing one line, not your entire codebase.' }
      ],
      quiz: [
        { id: 'q1', question: 'What is the primary value proposition of LangChain over the raw Anthropic SDK?', options: ['It makes API calls faster', 'It provides composable abstractions for multi-step workflows', 'It gives access to more Claude features', 'It reduces API costs'], correctIndex: 1, explanation: 'LangChain\'s core value is composability. It provides standardized building blocks (prompts, models, parsers, chains) that snap together with consistent interfaces. The raw SDK is better for simple, single-step calls.' },
        { id: 'q2', question: 'What does LCEL stand for, and what does the pipe syntax provide?', options: ['LangChain Execution Layer -- provides parallel execution', 'LangChain Expression Language -- provides composable chains with automatic streaming and batching', 'Language Chain Evaluation Logic -- provides testing utilities', 'LangChain Event Loop -- provides async processing'], correctIndex: 1, explanation: 'LCEL (LangChain Expression Language) lets you compose chains with the `.pipe()` operator. Every chain built with LCEL automatically supports `.invoke()`, `.stream()`, `.batch()`, and `.streamLog()` without extra code.' },
        { id: 'q3', question: 'When should you prefer the raw Anthropic SDK over LangChain?', options: ['Always -- LangChain is outdated', 'When you have a simple single-step request-response pattern', 'When you need streaming support', 'When you need to use Claude Opus'], correctIndex: 1, explanation: 'For simple request-response patterns (one model call, one response), the raw SDK is simpler, has fewer dependencies, and is easier to debug. LangChain adds value when you need composition, memory, agent loops, or observability.' }
      ]
    },
    {
      id: 'langchain-agents-tools',
      moduleId: 'langchain',
      title: 'LangChain Agents & Custom Tools',
      description: 'Agent architecture, custom tools, and the agent executor loop',
      order: 2,
      content: [
        { type: 'text', content: '## Agents: Chains That Make Decisions\n\nA chain is a fixed sequence: prompt -> model -> parser. Every input follows the same path. An **agent** breaks this rigidity. Instead of a fixed sequence, an agent receives a set of tools and **decides at runtime** which tool to call, what arguments to pass, and whether to continue or stop.\n\nThis is the fundamental shift: chains are **declarative** (you define the sequence), agents are **imperative** (the LLM decides the sequence).\n\n### How the Agent Executor Loop Works\n\nThe agent executor is LangChain\'s implementation of the TAOR pattern:\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:480px;">\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.06);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.95rem;">1. PROMPT ASSEMBLY</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">System prompt + tool definitions + conversation history + user input are assembled into a single prompt.</div>\n</div>\n<div style="text-align:center;color:#6c5ce7;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.06);">\n<div style="font-weight:700;color:#0984e3;font-size:0.95rem;">2. LLM REASONING</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">Claude analyzes the situation and decides: call a tool, or return a final answer?</div>\n</div>\n<div style="text-align:center;color:#0984e3;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #00cec9;background:rgba(0,206,201,0.06);">\n<div style="font-weight:700;color:#00cec9;font-size:0.95rem;">3. TOOL EXECUTION</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">If a tool was chosen, LangChain executes it and captures the result. The result is appended to conversation history.</div>\n</div>\n<div style="text-align:center;color:#00cec9;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px dashed #e17055;background:rgba(225,112,85,0.04);">\n<div style="font-weight:700;color:#e17055;font-size:0.95rem;">4. LOOP OR RETURN</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">If a tool was called &#8594; go back to step 1 with updated history.<br>If final answer &#8594; return to user.</div>\n</div>\n</div>\n\n### Why Tool Descriptions Are CRITICAL\n\nClaude decides which tool to call based almost entirely on the **tool description**. A vague description means the wrong tool gets called. A missing edge case means the tool gets called when it should not be. This is the single most common source of agent bugs -- not the logic, not the code, but the tool description.' },
        { type: 'code', content: '// Creating custom tools in LangChain\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { tool } from \'@langchain/core/tools\';\nimport { z } from \'zod\';\nimport { createToolCallingAgent, AgentExecutor } from \'langchain/agents\';\nimport { ChatPromptTemplate } from \'@langchain/core/prompts\';\n\n// BAD tool description -- vague, missing context\nconst badTool = tool(\n  async ({ query }) => { /* ... */ return \'result\'; },\n  {\n    name: \'search\',\n    description: \'Searches for stuff\',  // Too vague!\n    schema: z.object({ query: z.string() }),\n  }\n);\n\n// GOOD tool description -- specific, explains WHEN to use it\nconst searchJira = tool(\n  async ({ query, project, status }) => {\n    // Real implementation: call Jira REST API\n    const response = await fetch(\n      `https://your-org.atlassian.net/rest/api/3/search?jql=` +\n      `project=${project} AND text ~ \"${query}\" AND status=\"${status}\"`\n    );\n    const data = await response.json();\n    return JSON.stringify(data.issues.map((i: any) => ({\n      key: i.key,\n      summary: i.fields.summary,\n      status: i.fields.status.name,\n    })));\n  },\n  {\n    name: \'search_jira_tickets\',\n    description:\n      \'Search for Jira tickets by text query within a specific project. \' +\n      \'Use this when the user asks about tickets, bugs, tasks, or stories. \' +\n      \'Returns ticket key, summary, and status. \' +\n      \'Do NOT use this for general web searches or documentation lookups.\',\n    schema: z.object({\n      query: z.string().describe(\'Search text to match against ticket summary and description\'),\n      project: z.string().describe(\'Jira project key, e.g. \"PROJ\" or \"BACKEND\"\'),\n      status: z.string().optional().describe(\'Filter by status: \"To Do\", \"In Progress\", \"Done\"\'),\n    }),\n  }\n);\n\n// Another custom tool: read a file from the codebase\nconst readFile = tool(\n  async ({ filePath }) => {\n    const fs = await import(\'fs/promises\');\n    try {\n      const content = await fs.readFile(filePath, \'utf-8\');\n      return content;\n    } catch (err: any) {\n      return `Error reading file: ${err.message}`;\n    }\n  },\n  {\n    name: \'read_file\',\n    description:\n      \'Read the contents of a file from the local filesystem. \' +\n      \'Use this to examine source code, configuration files, or logs. \' +\n      \'Returns the full file content as a string. \' +\n      \'Returns an error message if the file does not exist.\',\n    schema: z.object({\n      filePath: z.string().describe(\'Absolute path to the file, e.g. /src/app/main.ts\'),\n    }),\n  }\n);', language: 'typescript' },
        { type: 'text', content: '### Building a Complete Agent\n\nWith tools defined, you assemble the agent using three components:\n\n1. **Model** -- the LLM that does the reasoning (Claude)\n2. **Tools** -- the actions the agent can take\n3. **Prompt** -- the system instructions that guide behavior\n\nThe `AgentExecutor` wraps all three into the TAOR loop automatically. It handles tool execution, conversation history, error handling, and the loop/terminate decision.\n\n### Agent Types in LangChain\n\n| Agent Type | How It Works | Best For |\n|-----------|-------------|----------|\n| **Tool-calling agent** | Uses Claude\'s native tool_use API | Most tasks -- it is the most reliable |\n| **ReAct agent** | Formats reasoning as Thought/Action/Observation text | Models without native tool calling |\n| **Structured chat agent** | Uses JSON for tool inputs | Complex multi-argument tools |\n| **OpenAI Functions agent** | Uses OpenAI function calling format | OpenAI-specific features |\n\nFor Claude, always use the **tool-calling agent** (`createToolCallingAgent`). It leverages Claude\'s native `tool_use` API, which is more reliable than text-based ReAct parsing. The model was specifically trained on this format, so tool selection and argument generation are significantly better.' },
        { type: 'code', content: '// Complete agent with tool-calling and error handling\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { createToolCallingAgent, AgentExecutor } from \'langchain/agents\';\nimport { ChatPromptTemplate, MessagesPlaceholder } from \'@langchain/core/prompts\';\n\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n});\n\n// The agent prompt MUST include a MessagesPlaceholder for agent_scratchpad\nconst prompt = ChatPromptTemplate.fromMessages([\n  [\'system\',\n    \'You are a development assistant with access to Jira and the codebase. \' +\n    \'Always check existing tickets before creating new ones. \' +\n    \'When reading code, explain what you find before making changes. \' +\n    \'If a tool returns an error, explain the error and try an alternative approach.\'\n  ],\n  new MessagesPlaceholder(\'chat_history\'),\n  [\'human\', \'{input}\'],\n  new MessagesPlaceholder(\'agent_scratchpad\'),\n]);\n\n// Assemble the agent\nconst agent = createToolCallingAgent({\n  llm: model,\n  tools: [searchJira, readFile],\n  prompt,\n});\n\n// Wrap in executor (this runs the TAOR loop)\nconst executor = new AgentExecutor({\n  agent,\n  tools: [searchJira, readFile],\n  verbose: true,         // Log each step to console\n  maxIterations: 10,     // Safety limit on TAOR loops\n  handleParsingErrors: true,  // Graceful error handling\n  returnIntermediateSteps: true,  // Include tool call history in output\n});\n\n// Run the agent\nconst result = await executor.invoke({\n  input: \'Find all open bugs in the BACKEND project and check if main.ts has related code\',\n  chat_history: [],\n});\n\nconsole.log(\'Final answer:\', result.output);\nconsole.log(\'Steps taken:\', result.intermediateSteps.length);\n\n// Output shows the agent:\n// 1. Called search_jira_tickets for open bugs\n// 2. Read main.ts to check for related code\n// 3. Correlated the results and provided a summary', language: 'typescript' },
        { type: 'warning', content: 'Always set `maxIterations` on your `AgentExecutor`. Without it, a confused agent can loop indefinitely, burning through API credits. Start with 10 iterations for simple tasks and 25 for complex ones. If the agent consistently hits the limit, the problem is in your tool descriptions or system prompt, not the iteration count.' },
        { type: 'tip', content: 'Tool description best practice: describe WHEN to use the tool, not just WHAT it does. Compare "Searches Jira" (what) vs "Use this when the user asks about tickets, bugs, or tasks. Do NOT use for general web searches" (when). The "when" framing dramatically reduces mis-invocation.' }
      ],
      quiz: [
        { id: 'q1', question: 'What is the fundamental difference between a chain and an agent?', options: ['Chains are faster, agents are slower', 'Chains follow a fixed sequence; agents decide which tools to call at runtime', 'Chains use Claude, agents use GPT-4', 'Chains are synchronous, agents are asynchronous'], correctIndex: 1, explanation: 'Chains execute a predefined sequence of steps. Agents use the LLM to decide at runtime which tools to call, in what order, and when to stop. The LLM acts as the controller.' },
        { id: 'q2', question: 'What is the most common source of agent bugs?', options: ['Complex chain logic', 'Vague or incorrect tool descriptions', 'Using the wrong model', 'Not enough memory'], correctIndex: 1, explanation: 'Claude decides which tool to call based almost entirely on the tool description. A vague description ("searches for stuff") leads to the wrong tool being called. Descriptions should specify WHEN to use the tool and when NOT to.' },
        { id: 'q3', question: 'Why should you use createToolCallingAgent instead of ReAct for Claude?', options: ['ReAct is deprecated', 'Tool-calling uses Claude\'s native tool_use API, which is more reliable than text-based parsing', 'ReAct does not support streaming', 'Tool-calling is faster'], correctIndex: 1, explanation: 'Claude was specifically trained on the tool_use API format. The tool-calling agent uses this native capability, producing more reliable tool selection and argument generation than text-based ReAct parsing.' }
      ]
    },
    {
      id: 'langchain-memory',
      moduleId: 'langchain',
      title: 'Memory & Conversation Management',
      description: 'Buffer, window, summary, and vector store memory patterns with Claude',
      order: 3,
      content: [
        { type: 'text', content: '## Why Memory Matters\n\nLLMs are stateless. Every API call starts fresh -- Claude does not remember your previous conversation unless you explicitly include it in the prompt. Memory in LangChain is the mechanism that manages conversation history and injects it into each new prompt automatically.\n\nWithout memory, every interaction is isolated:\n\n```\nUser: My name is Alex.\nClaude: Nice to meet you, Alex!\n\nUser: What is my name?\nClaude: I don\'t know your name.  // No memory of previous turn\n```\n\nWith memory, LangChain automatically prepends the conversation history:\n\n```\nUser: My name is Alex.\nClaude: Nice to meet you, Alex!\n\nUser: What is my name?  // LangChain injects previous messages automatically\nClaude: Your name is Alex!\n```\n\n### How Memory Works Under the Hood\n\nMemory does one thing: it **injects extra messages into the prompt** before sending it to the LLM. The different memory types differ only in **what** they inject and **how much** they keep.\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:520px;">\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.06);">\n<div style="font-weight:700;color:#0984e3;font-size:0.95rem;">User sends message</div>\n</div>\n<div style="text-align:center;color:#6c5ce7;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.06);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.95rem;">Memory loads conversation history</div>\n<div style="font-size:0.82rem;line-height:1.5;margin-top:0.2rem;">Retrieves stored messages and formats them for injection.</div>\n</div>\n<div style="text-align:center;color:#fdcb6e;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #e17055;background:rgba(225,112,85,0.04);">\n<div style="font-weight:700;color:#e17055;font-size:0.95rem;">Prompt Template assembles full prompt</div>\n<div style="font-size:0.82rem;line-height:1.5;margin-top:0.2rem;">System prompt + memory messages + new user message = complete prompt.</div>\n</div>\n<div style="text-align:center;color:#e17055;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #00cec9;background:rgba(0,206,201,0.06);">\n<div style="font-weight:700;color:#00cec9;font-size:0.95rem;">LLM generates response</div>\n</div>\n<div style="text-align:center;color:#00cec9;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #27ae60;background:rgba(39,174,96,0.06);">\n<div style="font-weight:700;color:#27ae60;font-size:0.95rem;">Memory saves both user message and response</div>\n</div>\n</div>' },
        { type: 'code', content: '// Memory Type 1: BufferMemory -- stores everything\nimport { BufferMemory } from \'langchain/memory\';\nimport { ConversationChain } from \'langchain/chains\';\nimport { ChatAnthropic } from \'@langchain/anthropic\';\n\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n});\n\n// BufferMemory stores ALL messages -- simple but unbounded\nconst memory = new BufferMemory({\n  returnMessages: true,    // Return as Message objects, not strings\n  memoryKey: \'chat_history\', // Variable name in the prompt template\n});\n\nconst chain = new ConversationChain({\n  llm: model,\n  memory,\n  verbose: true,  // See what memory injects into each call\n});\n\nawait chain.invoke({ input: \'My name is Alex and I work on the payments team.\' });\nawait chain.invoke({ input: \'What team do I work on?\' });\n// Claude sees the full history and answers: \"You work on the payments team.\"\n\n// Problem: after 100 messages, you are sending ALL of them every call.\n// At ~100 tokens per message pair, that is 10,000 tokens of history\n// on every single API call. This gets expensive fast.', language: 'typescript' },
        { type: 'text', content: '## The Four Memory Types: A Decision Matrix\n\n| Memory Type | What It Stores | Token Usage | Best For |\n|------------|---------------|-------------|----------|\n| **BufferMemory** | Every message, verbatim | Grows linearly forever | Short conversations (<20 turns), demos |\n| **BufferWindowMemory** | Last K message pairs | Fixed ceiling (K * msg_size) | Chat UIs with a scrollback limit |\n| **ConversationSummaryMemory** | Running summary of conversation | Roughly constant | Long conversations where detail can be lost |\n| **VectorStoreMemory** | Semantically relevant past messages | Only relevant messages | Large knowledge bases, long-running sessions |\n\n### BufferWindowMemory: Keep the Last K Turns\n\nBufferWindowMemory solves the unbounded growth problem by keeping only the most recent K exchanges. Older messages are discarded. This is the simplest memory type for production use -- predictable token costs, no summarization overhead.\n\n**When to use it:** Chat applications where only recent context matters. Support bots, coding assistants, Q&A systems.\n\n**When NOT to use it:** When the user might reference something from 20 turns ago. The agent will not remember.\n\n### ConversationSummaryMemory: Compress History\n\nInstead of storing raw messages, SummaryMemory uses an LLM to maintain a running summary. After each exchange, it updates the summary. This keeps token usage roughly constant regardless of conversation length.\n\n**The trade-off:** You pay for an extra LLM call on every turn to update the summary, and you lose specific details. The summary says "the user discussed authentication issues" instead of keeping the exact error message.\n\n### VectorStoreMemory: Semantic Search Over History\n\nVectorStoreMemory stores each message as a vector embedding and retrieves only the most semantically relevant past messages for each new query. If the user asks about "authentication" 50 turns later, VectorStoreMemory retrieves the earlier auth-related messages even though BufferWindowMemory would have discarded them.\n\n**When to use it:** Long-running agents that need to recall specific past interactions. Research assistants, project management bots, persistent coding agents.' },
        { type: 'code', content: '// Memory Type 2: BufferWindowMemory -- keep last K turns\nimport { BufferWindowMemory } from \'langchain/memory\';\n\nconst windowMemory = new BufferWindowMemory({\n  k: 10,                     // Keep last 10 exchanges\n  returnMessages: true,\n  memoryKey: \'chat_history\',\n});\n\n// Memory Type 3: ConversationSummaryMemory -- compress to summary\nimport { ConversationSummaryMemory } from \'langchain/memory\';\n\nconst summaryMemory = new ConversationSummaryMemory({\n  llm: new ChatAnthropic({ modelName: \'claude-haiku-4-20250414\' }),\n  returnMessages: true,\n  memoryKey: \'chat_history\',\n});\n\n// After 50 messages, instead of 50 message objects,\n// the prompt gets something like:\n// \"The user is Alex from the payments team. They discussed\n//  a pagination bug in the /api/users endpoint and asked\n//  about cursor-based pagination implementation...\"\n\n// Memory Type 4: VectorStoreMemory -- semantic retrieval\nimport { VectorStoreRetrieverMemory } from \'langchain/memory\';\nimport { MemoryVectorStore } from \'langchain/vectorstores/memory\';\nimport { OpenAIEmbeddings } from \'@langchain/openai\';\n\nconst vectorStore = new MemoryVectorStore(\n  new OpenAIEmbeddings()  // Embedding model for semantic search\n);\n\nconst vectorMemory = new VectorStoreRetrieverMemory({\n  vectorStoreRetriever: vectorStore.asRetriever(5), // Retrieve top 5 relevant\n  memoryKey: \'chat_history\',\n});\n\n// Usage: combine memory with an agent\nimport { createToolCallingAgent, AgentExecutor } from \'langchain/agents\';\nimport { ChatPromptTemplate, MessagesPlaceholder } from \'@langchain/core/prompts\';\n\nconst prompt = ChatPromptTemplate.fromMessages([\n  [\'system\', \'You are a helpful assistant. Use conversation history for context.\'],\n  new MessagesPlaceholder(\'chat_history\'),\n  [\'human\', \'{input}\'],\n  new MessagesPlaceholder(\'agent_scratchpad\'),\n]);\n\nconst agent = createToolCallingAgent({ llm: model, tools: myTools, prompt });\nconst executor = new AgentExecutor({\n  agent,\n  tools: myTools,\n  memory: windowMemory,  // Plug in any memory type here\n});', language: 'typescript' },
        { type: 'tip', content: 'Production tip: Use BufferWindowMemory (k=10-15) as your default. It covers 90% of use cases with predictable costs. Only upgrade to SummaryMemory or VectorStoreMemory when users actually report that the agent "forgets" important context. Premature optimization of memory is a common time sink.' },
        { type: 'warning', content: 'ConversationSummaryMemory uses an LLM call on EVERY turn to update the summary. If you use Claude Opus for the summarizer, you are doubling your API costs. Always use a cheaper, faster model (Haiku) for the summarization step. The summary does not need to be brilliant -- it just needs to be accurate.' }
      ],
      quiz: [
        { id: 'q1', question: 'Why do LangChain memory types exist?', options: ['Because Claude has a memory API', 'Because LLMs are stateless -- memory must be explicitly managed and injected into each prompt', 'To store data in a database', 'To reduce the number of API calls'], correctIndex: 1, explanation: 'LLMs are stateless. Every API call starts fresh. Memory types manage conversation history and inject relevant context into each new prompt automatically. Without memory, every interaction is isolated.' },
        { id: 'q2', question: 'What is the key trade-off of ConversationSummaryMemory?', options: ['It is slower because it stores more data', 'It requires an extra LLM call per turn to update the summary, and loses specific details', 'It cannot be used with Claude', 'It does not support streaming'], correctIndex: 1, explanation: 'SummaryMemory uses an LLM to compress history into a running summary. This costs an extra API call per turn and loses specific details (exact error messages, code snippets). Use a cheap model like Haiku for the summarizer.' },
        { id: 'q3', question: 'Which memory type would you choose for a long-running coding assistant that needs to recall specific file changes from hours ago?', options: ['BufferMemory', 'BufferWindowMemory', 'ConversationSummaryMemory', 'VectorStoreMemory'], correctIndex: 3, explanation: 'VectorStoreMemory stores each message as a vector embedding and retrieves semantically relevant past messages. When the user asks about a file they edited hours ago, VectorStoreMemory can find that specific exchange even if BufferWindowMemory would have discarded it.' }
      ]
    },
    {
      id: 'langchain-production',
      moduleId: 'langchain',
      title: 'LangChain + Claude: Production Patterns',
      description: 'Retry logic, fallbacks, streaming, tracing, and cost management for production',
      order: 4,
      content: [
        { type: 'text', content: '## Moving from Prototype to Production\n\nYour LangChain prototype works in development. You demo it to the team. Everyone is impressed. Then you deploy it and discover: API calls timeout under load. Rate limits cause cascading failures. You have no visibility into why the agent chose the wrong tool. Costs spiral because the agent loops 15 times on simple tasks.\n\nProduction LLM applications need the same resilience patterns as any distributed system: **retries**, **fallbacks**, **rate limiting**, **observability**, and **cost controls**. LangChain provides built-in primitives for all of these.\n\n### The Production Checklist\n\n<div style="display:flex;flex-direction:column;gap:0.4rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:480px;">\n<div style="padding:0.5rem 0.8rem;border-radius:6px;border-left:4px solid #e17055;background:rgba(225,112,85,0.04);font-size:0.9rem;">\n<span style="font-weight:700;color:#e17055;">Resilience:</span> Retries with exponential backoff, model fallbacks, timeout handling\n</div>\n<div style="padding:0.5rem 0.8rem;border-radius:6px;border-left:4px solid #0984e3;background:rgba(9,132,227,0.04);font-size:0.9rem;">\n<span style="font-weight:700;color:#0984e3;">Observability:</span> LangSmith tracing, structured logging, step-level metrics\n</div>\n<div style="padding:0.5rem 0.8rem;border-radius:6px;border-left:4px solid #27ae60;background:rgba(39,174,96,0.04);font-size:0.9rem;">\n<span style="font-weight:700;color:#27ae60;">Cost Control:</span> Token budgets, iteration limits, model tiering\n</div>\n<div style="padding:0.5rem 0.8rem;border-radius:6px;border-left:4px solid #6c5ce7;background:rgba(108,92,231,0.04);font-size:0.9rem;">\n<span style="font-weight:700;color:#6c5ce7;">UX:</span> Streaming responses, progress indicators, graceful degradation\n</div>\n</div>\n\nLet us tackle each one.' },
        { type: 'code', content: '// PATTERN 1: Retries with exponential backoff\nimport { ChatAnthropic } from \'@langchain/anthropic\';\n\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n  maxRetries: 3,  // Built-in retry on transient failures (429, 500, 529)\n});\n\n// PATTERN 2: Model fallbacks -- try Opus, fall back to Sonnet, then Haiku\nconst opusModel = new ChatAnthropic({\n  modelName: \'claude-opus-4-6-20250414\',\n  maxRetries: 2,\n});\n\nconst sonnetModel = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  maxRetries: 2,\n});\n\nconst haikuModel = new ChatAnthropic({\n  modelName: \'claude-haiku-4-20250414\',\n  maxRetries: 2,\n});\n\n// .withFallbacks() tries each model in order\nconst resilientModel = opusModel.withFallbacks({\n  fallbacks: [sonnetModel, haikuModel],\n});\n\n// If Opus fails (rate limit, outage), Sonnet is tried.\n// If Sonnet also fails, Haiku is the last resort.\n// The rest of your chain does not change at all.\n\n// PATTERN 3: Timeout handling\nconst modelWithTimeout = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  timeout: 30000,  // 30 second timeout per request\n});\n\n// PATTERN 4: Rate limiting with a simple semaphore\nclass RateLimiter {\n  private queue: (() => void)[] = [];\n  private active = 0;\n\n  constructor(private maxConcurrent: number) {}\n\n  async acquire(): Promise<void> {\n    if (this.active < this.maxConcurrent) {\n      this.active++;\n      return;\n    }\n    return new Promise(resolve => this.queue.push(resolve));\n  }\n\n  release(): void {\n    this.active--;\n    const next = this.queue.shift();\n    if (next) { this.active++; next(); }\n  }\n}\n\nconst limiter = new RateLimiter(5); // Max 5 concurrent LLM calls\n\nasync function rateLimitedInvoke(chain: any, input: any) {\n  await limiter.acquire();\n  try {\n    return await chain.invoke(input);\n  } finally {\n    limiter.release();\n  }\n}', language: 'typescript' },
        { type: 'text', content: '## Streaming: Responsive User Experience\n\nIn production, users cannot stare at a spinner for 10 seconds waiting for Claude to finish thinking. Streaming delivers tokens as they are generated, making the application feel responsive even when the full response takes time.\n\nLangChain\'s LCEL chains support streaming natively. Every chain built with `.pipe()` inherits `.stream()` automatically.\n\n## Observability with LangSmith\n\nLangSmith is LangChain\'s observability platform. It captures every step of your chain or agent execution: the prompt sent, the model response, tool calls, tool results, latency, token usage, and cost. In production, this is non-negotiable -- when an agent does something unexpected, you need to see **exactly** what it saw, what it thought, and what it did.\n\nSetup is two environment variables:\n\n```bash\nexport LANGCHAIN_TRACING_V2=true\nexport LANGCHAIN_API_KEY=your-langsmith-api-key\n```\n\nOnce set, every chain and agent invocation is automatically traced. No code changes required. You can then view traces in the LangSmith dashboard, filter by latency or error rate, and drill into individual steps.\n\n### Cost Management Strategies\n\n| Strategy | Implementation | Savings |\n|----------|---------------|--------|\n| **Model tiering** | Use Haiku for classification, Sonnet for general tasks, Opus only for complex reasoning | 50-80% |\n| **Iteration caps** | Set `maxIterations: 10` on AgentExecutor | Prevents runaway loops |\n| **Token budgets** | Set `maxTokens` per request based on expected output size | Avoids paying for rambling |\n| **Caching** | Use LangChain\'s cache to avoid re-calling the LLM with identical inputs | Up to 90% on repeated queries |\n| **Batch processing** | Use `.batch()` for bulk operations instead of sequential `.invoke()` | Better throughput, lower latency |' },
        { type: 'code', content: '// PATTERN 5: Streaming with LCEL\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { ChatPromptTemplate } from \'@langchain/core/prompts\';\nimport { StringOutputParser } from \'@langchain/core/output_parsers\';\n\nconst chain = ChatPromptTemplate.fromMessages([\n  [\'system\', \'You are a technical writer.\'],\n  [\'human\', \'{question}\'],\n]).pipe(\n  new ChatAnthropic({ modelName: \'claude-sonnet-4-6-20250514\' })\n).pipe(\n  new StringOutputParser()\n);\n\n// Stream tokens to the client\nconst stream = await chain.stream({ question: \'Explain event sourcing\' });\nfor await (const chunk of stream) {\n  process.stdout.write(chunk);  // Each chunk is a few tokens\n}\n\n// PATTERN 6: Caching identical requests\nimport { InMemoryCache } from \'@langchain/core/caches\';\n\nconst cachedModel = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  cache: new InMemoryCache(),\n});\n\n// First call: hits API, costs tokens\nawait cachedModel.invoke(\'What is TypeScript?\');\n// Second identical call: returns cached response instantly, zero cost\nawait cachedModel.invoke(\'What is TypeScript?\');\n\n// PATTERN 7: Callbacks for custom logging and metrics\nimport { BaseCallbackHandler } from \'@langchain/core/callbacks/base\';\n\nclass MetricsCallback extends BaseCallbackHandler {\n  name = \'metrics\';\n\n  async handleLLMStart(llm: any, prompts: string[]) {\n    console.log(`[LLM START] Model: ${llm.modelName}`);\n    console.log(`[LLM START] Prompt tokens (est): ${prompts[0]?.length / 4}`);\n  }\n\n  async handleLLMEnd(output: any) {\n    const usage = output?.llmOutput?.usage;\n    if (usage) {\n      console.log(`[LLM END] Input: ${usage.input_tokens}, Output: ${usage.output_tokens}`);\n      console.log(`[LLM END] Cost: $${(\n        usage.input_tokens * 3 / 1_000_000 +\n        usage.output_tokens * 15 / 1_000_000\n      ).toFixed(6)}`);\n    }\n  }\n\n  async handleToolStart(tool: any, input: string) {\n    console.log(`[TOOL] ${tool.name} called with: ${input.slice(0, 100)}`);\n  }\n\n  async handleChainError(err: Error) {\n    console.error(`[ERROR] Chain failed: ${err.message}`);\n    // Send to your error tracking service (Sentry, etc.)\n  }\n}\n\n// Attach to any chain or agent\nconst result = await executor.invoke(\n  { input: \'Check latest bugs\' },\n  { callbacks: [new MetricsCallback()] }\n);', language: 'typescript' },
        { type: 'warning', content: 'Production pitfall: LangChain\'s built-in `maxRetries` only retries on HTTP errors (429, 500, 529). It does NOT retry on malformed LLM output (e.g., the model returns text when you expected JSON). For output validation failures, you need your own retry logic that re-invokes the chain with a corrective prompt like "Your previous response was invalid JSON. Try again."' },
        { type: 'tip', content: 'Start every production deployment with LangSmith tracing enabled. The most common production issue is not crashes -- it is the agent taking too many steps or choosing the wrong tool. LangSmith lets you see every step, measure latency per step, and identify which tool descriptions need improvement. It is the "debugger" for LLM applications.' },
        { type: 'text', content: '### Key Takeaways for Production\n\n1. **Fallback chains are your safety net.** Opus -> Sonnet -> Haiku ensures your application stays up even during provider issues.\n2. **Streaming is not optional for user-facing apps.** Nobody waits 10 seconds for a blank screen. Use `.stream()` everywhere.\n3. **LangSmith tracing is your observability layer.** Two environment variables give you full visibility into every chain and agent step.\n4. **Cost control is architectural.** Model tiering (right model for the right task) saves more than any code optimization.\n5. **Set `maxIterations` on every agent.** A confused agent looping 50 times costs 50x what it should.\n6. **Cache identical requests.** If you call the LLM with the same system prompt + input repeatedly, caching eliminates redundant API calls entirely.' }
      ],
      quiz: [
        { id: 'q1', question: 'What does `.withFallbacks()` do in LangChain?', options: ['It adds error messages to responses', 'It tries alternative models in order when the primary model fails', 'It caches responses for fallback', 'It reduces the temperature on retry'], correctIndex: 1, explanation: 'withFallbacks() creates a chain that tries models in order. If Opus fails (rate limit, timeout, outage), it automatically tries Sonnet, then Haiku. The rest of your chain remains unchanged.' },
        { id: 'q2', question: 'How do you enable LangSmith tracing in a LangChain application?', options: ['Import and configure the LangSmith client library', 'Set LANGCHAIN_TRACING_V2=true and LANGCHAIN_API_KEY environment variables', 'Add .trace() to every chain call', 'Deploy to LangChain Cloud'], correctIndex: 1, explanation: 'LangSmith tracing is enabled by two environment variables. Once set, all chain and agent invocations are automatically traced with no code changes required.' },
        { id: 'q3', question: 'What is the most impactful cost optimization strategy for LLM applications?', options: ['Caching all responses', 'Using shorter prompts', 'Model tiering -- using the cheapest model that meets the quality bar for each task', 'Reducing max_tokens to 100'], correctIndex: 2, explanation: 'Model tiering -- using Haiku for simple classification, Sonnet for general tasks, and Opus only for complex reasoning -- can reduce costs by 50-80%. This architectural decision has more impact than any code-level optimization.' }
      ]
    }
        ]
      },
      {
        id: 'langgraph',
        title: 'LangGraph: Stateful Agent Graphs',
        description: 'Build complex, stateful agent workflows with graph-based orchestration',
        icon: '📊',
        color: '#e17055',
        order: 9,
        lessons: [
{
      id: 'why-langgraph',
      moduleId: 'langgraph',
      title: 'Why LangGraph?',
      description: 'When simple chains fail and you need conditionals, loops, state, and human-in-the-loop',
      order: 1,
      content: [
        { type: 'text', content: '## Simple Chains Are Not Enough\n\nLangChain chains are powerful for linear workflows: take input, call the model, parse output, done. But real-world agent systems are not linear. They need:\n\n- **Conditionals** -- if the code review finds a critical bug, route to the security team instead of merging\n- **Loops** -- if tests fail, send the error back to the coder and retry, up to 3 times\n- **Persistent state** -- remember what files were changed, which tests passed, and what the overall plan is across dozens of LLM calls\n- **Human-in-the-loop** -- pause the workflow and ask a human to approve before deploying to production\n- **Parallel execution** -- run the linter and type checker at the same time, then merge results\n\nA LangChain chain cannot do any of this cleanly. You end up with deeply nested if/else logic, manual state dictionaries, and fragile loop counters. The code becomes unreadable.\n\n### LangGraph: Workflows as Directed Graphs\n\nLangGraph models your workflow as a **directed graph** where:\n\n- **Nodes** = units of work (LLM calls, tool executions, human approvals)\n- **Edges** = transitions between nodes (can be conditional)\n- **State** = a typed object that flows through the graph and persists across nodes\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;">\n<div style="display:flex;flex-direction:column;gap:0.3rem;max-width:520px;">\n<div style="font-weight:700;font-size:1rem;color:#e84393;margin-bottom:0.5rem;">Chain (LangChain) -- Linear, Fixed Path</div>\n<div style="display:flex;align-items:center;gap:0.4rem;flex-wrap:wrap;">\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#6c5ce7;color:white;font-size:0.85rem;font-weight:600;">Input</div>\n<span style="color:#888;">&#8594;</span>\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#0984e3;color:white;font-size:0.85rem;font-weight:600;">Prompt</div>\n<span style="color:#888;">&#8594;</span>\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#00cec9;color:white;font-size:0.85rem;font-weight:600;">Model</div>\n<span style="color:#888;">&#8594;</span>\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#27ae60;color:white;font-size:0.85rem;font-weight:600;">Parser</div>\n<span style="color:#888;">&#8594;</span>\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#e17055;color:white;font-size:0.85rem;font-weight:600;">Output</div>\n</div>\n<div style="font-size:0.8rem;color:#888;margin:0.3rem 0 1.2rem;">Every input follows the same path. No branching, no loops, no decisions.</div>\n\n<div style="font-weight:700;font-size:1rem;color:#e84393;margin-bottom:0.5rem;">Graph (LangGraph) -- Dynamic, Stateful, Branching</div>\n<div style="position:relative;min-height:180px;border:2px solid #e84393;border-radius:12px;padding:1rem;background:rgba(232,67,147,0.03);">\n<div style="display:flex;justify-content:center;margin-bottom:0.8rem;">\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#6c5ce7;color:white;font-size:0.85rem;font-weight:600;">Start</div>\n</div>\n<div style="display:flex;justify-content:center;gap:0.3rem;align-items:center;margin-bottom:0.3rem;"><span style="color:#6c5ce7;">&#8595;</span></div>\n<div style="display:flex;justify-content:center;margin-bottom:0.8rem;">\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#0984e3;color:white;font-size:0.85rem;font-weight:600;">Analyze</div>\n</div>\n<div style="display:flex;justify-content:center;gap:0.3rem;align-items:center;margin-bottom:0.3rem;">\n<span style="color:#e17055;font-size:0.75rem;">if critical</span>\n<span style="color:#888;">&#8601;</span>\n<span style="color:#888;margin:0 0.5rem;"></span>\n<span style="color:#888;">&#8600;</span>\n<span style="color:#27ae60;font-size:0.75rem;">if okay</span>\n</div>\n<div style="display:flex;justify-content:center;gap:2rem;margin-bottom:0.8rem;">\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#e17055;color:white;font-size:0.85rem;font-weight:600;">Human Review</div>\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#27ae60;color:white;font-size:0.85rem;font-weight:600;">Auto-Merge</div>\n</div>\n<div style="display:flex;justify-content:center;gap:0.3rem;align-items:center;margin-bottom:0.3rem;">\n<span style="color:#888;">&#8600;</span>\n<span style="color:#888;margin:0 0.5rem;"></span>\n<span style="color:#888;">&#8601;</span>\n</div>\n<div style="display:flex;justify-content:center;">\n<div style="padding:0.4rem 0.8rem;border-radius:6px;background:#e84393;color:white;font-size:0.85rem;font-weight:600;">End</div>\n</div>\n</div>\n<div style="font-size:0.8rem;color:#888;margin-top:0.3rem;">Branching logic, loops, state persistence, and human gates -- all declarative.</div>\n</div>\n</div>\n\nThe graph model matches how you already think about complex workflows. Draw a flowchart on a whiteboard, and LangGraph lets you code it almost exactly as drawn.' },
        { type: 'code', content: '// Your first LangGraph: a simple two-node graph\nimport { StateGraph, Annotation, START, END } from \'@langchain/langgraph\';\nimport { ChatAnthropic } from \'@langchain/anthropic\';\n\n// Step 1: Define your state schema using Annotation\nconst GraphState = Annotation.Root({\n  input: Annotation<string>(),\n  analysis: Annotation<string>(),\n  output: Annotation<string>(),\n});\n\n// Step 2: Define nodes (functions that take state and return partial state)\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n});\n\nasync function analyzeNode(state: typeof GraphState.State) {\n  const response = await model.invoke([\n    { role: \'system\', content: \'Analyze the following text for sentiment and key themes.\' },\n    { role: \'user\', content: state.input },\n  ]);\n  return { analysis: response.content as string };\n}\n\nasync function summarizeNode(state: typeof GraphState.State) {\n  const response = await model.invoke([\n    { role: \'system\', content: \'Given this analysis, write a one-paragraph summary.\' },\n    { role: \'user\', content: state.analysis },\n  ]);\n  return { output: response.content as string };\n}\n\n// Step 3: Build the graph\nconst graph = new StateGraph(GraphState)\n  .addNode(\'analyze\', analyzeNode)\n  .addNode(\'summarize\', summarizeNode)\n  .addEdge(START, \'analyze\')       // Start -> Analyze\n  .addEdge(\'analyze\', \'summarize\') // Analyze -> Summarize\n  .addEdge(\'summarize\', END)       // Summarize -> End\n  .compile();\n\n// Step 4: Run it\nconst result = await graph.invoke({\n  input: \'The new deployment pipeline reduced build times by 40%...\',\n});\n\nconsole.log(result.output);\n// A structured summary based on the analysis', language: 'typescript' },
        { type: 'text', content: '### State: The Heart of LangGraph\n\nState is what makes LangGraph fundamentally different from LangChain chains. In a chain, data flows left-to-right and is discarded. In LangGraph, state **persists** across the entire graph execution and is accessible to every node.\n\nState is defined as a typed object using `Annotation`. Each node receives the full state and returns a **partial update** -- only the fields it modifies. LangGraph merges the update into the existing state automatically.\n\nThis means:\n- Node A can write `analysis` to state\n- Node B can read `analysis` AND write `decision` to state\n- Node C can read both `analysis` and `decision`\n- No data is lost between steps\n- You can inspect state at any point for debugging\n\n### When to Use LangGraph vs LangChain\n\n| Use LangChain When | Use LangGraph When |\n|-------------------|-------------------|\n| Linear workflows (A -> B -> C) | Branching workflows (A -> B or C depending on condition) |\n| Single-agent tasks | Multi-agent coordination |\n| Stateless request-response | Stateful multi-step processes |\n| Simple memory needs | Complex state management across many nodes |\n| Rapid prototyping | Production agent systems |\n\n### Key Takeaways\n\n1. **LangGraph models workflows as directed graphs** -- nodes (work), edges (transitions), state (shared data).\n2. **State persists across the entire graph** and is accessible to every node. Each node returns only the fields it modifies.\n3. **Conditional edges** let the graph make decisions at runtime -- routing, looping, and branching are all first-class.\n4. **Use LangChain for linear workflows, LangGraph for anything with branching, loops, or persistent state.**\n5. **The graph model matches flowchart thinking** -- if you can whiteboard it, you can code it in LangGraph.' },
        { type: 'tip', content: 'LangGraph is built by the LangChain team but is a separate package (`@langchain/langgraph`). It uses LangChain\'s model wrappers and tools but adds the graph execution engine on top. Think of it as: LangChain provides the building blocks (models, tools, prompts), LangGraph provides the orchestration layer (graphs, state, conditional routing).' }
      ],
      quiz: [
        { id: 'q1', question: 'What are the three core components of a LangGraph workflow?', options: ['Models, Prompts, Parsers', 'Nodes, Edges, State', 'Chains, Agents, Memory', 'Inputs, Outputs, Callbacks'], correctIndex: 1, explanation: 'LangGraph workflows are directed graphs with three core components: Nodes (units of work), Edges (transitions between nodes, which can be conditional), and State (a typed object that persists across all nodes).' },
        { id: 'q2', question: 'How does state work in LangGraph?', options: ['Each node gets a copy of state and changes are discarded', 'State is global and mutable by any node at any time', 'Each node receives full state and returns a partial update that is merged in', 'State must be passed explicitly between nodes as function arguments'], correctIndex: 2, explanation: 'Each node receives the full current state and returns only the fields it wants to update. LangGraph automatically merges the partial update into the existing state, preserving all other fields.' },
        { id: 'q3', question: 'When should you use LangGraph instead of LangChain chains?', options: ['Always -- LangGraph replaces LangChain', 'When you need branching, loops, persistent state, or human-in-the-loop', 'Only for multi-agent systems', 'Only when using Claude Opus'], correctIndex: 1, explanation: 'LangGraph adds value when your workflow needs conditionals (branching), loops (retry on failure), persistent state across many steps, or human-in-the-loop gates. For simple linear workflows, LangChain chains are simpler and sufficient.' }
      ]
    },
    {
      id: 'langgraph-conditional',
      moduleId: 'langgraph',
      title: 'Conditional Routing & Human-in-the-Loop',
      description: 'Conditional edges, interrupt() for human input, checkpointing, and quality gates',
      order: 2,
      content: [
        { type: 'text', content: '## Conditional Edges: The Graph Decides\n\nThe real power of LangGraph is **conditional edges** -- edges where the next node is determined at runtime by a function that inspects state. Instead of hardcoding "after analysis, go to summary," you write "after analysis, check the severity: if critical, go to human review; if minor, go to auto-fix; if none, go to done."\n\nThis is the difference between a script and an intelligent workflow.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:520px;">\n<div style="position:relative;border:2px solid #e84393;border-radius:12px;padding:1rem;background:rgba(232,67,147,0.03);">\n<div style="font-weight:700;font-size:0.95rem;color:#e84393;margin-bottom:0.8rem;">Conditional Routing Example: Code Review Pipeline</div>\n<div style="display:flex;justify-content:center;margin-bottom:0.6rem;">\n<div style="padding:0.35rem 0.7rem;border-radius:6px;background:#6c5ce7;color:white;font-size:0.82rem;font-weight:600;">Review Code</div>\n</div>\n<div style="display:flex;justify-content:center;margin-bottom:0.6rem;">\n<div style="padding:0.3rem 0.6rem;border-radius:6px;background:rgba(232,67,147,0.12);color:#e84393;font-size:0.8rem;font-weight:600;border:1px dashed #e84393;">Route by severity?</div>\n</div>\n<div style="display:flex;justify-content:center;gap:0.8rem;margin-bottom:0.6rem;">\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.3rem;">\n<span style="font-size:0.7rem;color:#e17055;font-weight:600;">CRITICAL</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.35rem 0.7rem;border-radius:6px;background:#e17055;color:white;font-size:0.82rem;font-weight:600;">Human Gate</div>\n</div>\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.3rem;">\n<span style="font-size:0.7rem;color:#fdcb6e;font-weight:600;">MEDIUM</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.35rem 0.7rem;border-radius:6px;background:#fdcb6e;color:#333;font-size:0.82rem;font-weight:600;">Auto-Fix</div>\n</div>\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.3rem;">\n<span style="font-size:0.7rem;color:#27ae60;font-weight:600;">NONE</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.35rem 0.7rem;border-radius:6px;background:#27ae60;color:white;font-size:0.82rem;font-weight:600;">Approve</div>\n</div>\n</div>\n<div style="display:flex;justify-content:center;gap:0.3rem;align-items:center;margin-bottom:0.3rem;">\n<span style="color:#888;">&#8600;</span>\n<span style="color:#888;margin:0 1rem;"></span>\n<span style="color:#888;">&#8595;</span>\n<span style="color:#888;margin:0 1rem;"></span>\n<span style="color:#888;">&#8601;</span>\n</div>\n<div style="display:flex;justify-content:center;">\n<div style="padding:0.35rem 0.7rem;border-radius:6px;background:#e84393;color:white;font-size:0.82rem;font-weight:600;">Done</div>\n</div>\n</div>\n</div>\n\n### The Routing Function\n\nA conditional edge uses a **routing function** that receives the current state and returns the name of the next node. The function can inspect any field in state -- LLM output, tool results, counters, flags -- and make its decision.' },
        { type: 'code', content: '// Conditional routing: route based on review severity\nimport { StateGraph, Annotation, START, END } from \'@langchain/langgraph\';\nimport { ChatAnthropic } from \'@langchain/anthropic\';\n\nconst ReviewState = Annotation.Root({\n  code: Annotation<string>(),\n  reviewResult: Annotation<string>(),\n  severity: Annotation<string>(),  // \'critical\' | \'medium\' | \'none\'\n  fixedCode: Annotation<string>(),\n  humanApproval: Annotation<boolean>(),\n  retryCount: Annotation<number>({ default: () => 0 }),\n});\n\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n});\n\n// Node: Review the code\nasync function reviewCode(state: typeof ReviewState.State) {\n  const response = await model.invoke([\n    { role: \'system\', content:\n      \'Review this code. Respond with JSON: \' +\n      \'{ \"severity\": \"critical\" | \"medium\" | \"none\", \"issues\": [...] }\' },\n    { role: \'user\', content: state.code },\n  ]);\n  const result = JSON.parse(response.content as string);\n  return {\n    reviewResult: response.content as string,\n    severity: result.severity,\n  };\n}\n\n// Node: Auto-fix medium issues\nasync function autoFix(state: typeof ReviewState.State) {\n  const response = await model.invoke([\n    { role: \'system\', content: \'Fix the medium-severity issues found in this review.\' },\n    { role: \'user\', content: `Code:\\n${state.code}\\n\\nReview:\\n${state.reviewResult}` },\n  ]);\n  return { fixedCode: response.content as string };\n}\n\n// Node: Approve (no issues found)\nasync function approve(state: typeof ReviewState.State) {\n  return { fixedCode: state.code };  // Pass through unchanged\n}\n\n// ROUTING FUNCTION: decides next node based on severity\nfunction routeBySeverity(state: typeof ReviewState.State): string {\n  switch (state.severity) {\n    case \'critical\': return \'human_gate\';\n    case \'medium\': return \'auto_fix\';\n    case \'none\': return \'approve\';\n    default: return \'human_gate\';  // Safety default\n  }\n}\n\n// Build the graph with conditional edges\nconst graph = new StateGraph(ReviewState)\n  .addNode(\'review\', reviewCode)\n  .addNode(\'human_gate\', humanGateNode)  // defined below\n  .addNode(\'auto_fix\', autoFix)\n  .addNode(\'approve\', approve)\n  .addEdge(START, \'review\')\n  .addConditionalEdges(\'review\', routeBySeverity, {\n    human_gate: \'human_gate\',\n    auto_fix: \'auto_fix\',\n    approve: \'approve\',\n  })\n  .addEdge(\'human_gate\', END)\n  .addEdge(\'auto_fix\', END)\n  .addEdge(\'approve\', END)\n  .compile();', language: 'typescript' },
        { type: 'text', content: '## Human-in-the-Loop with interrupt()\n\nSome decisions should not be automated. Deploying to production, deleting data, approving large refactors -- these need a human. LangGraph\'s `interrupt()` function pauses the graph execution and waits for human input before continuing.\n\nThe flow is:\n1. Graph runs until it hits an `interrupt()` call inside a node\n2. Execution pauses and returns a special `Interrupt` value\n3. Your application presents the interrupt to a human (UI, Slack message, email)\n4. The human provides input (approve, reject, modify)\n5. You resume the graph with `Command({ resume: humanInput })`\n6. The node continues from where it paused\n\n### Checkpointing: How Pause/Resume Works\n\nFor interrupt to work, the graph needs to save its state before pausing. This is called **checkpointing**. LangGraph provides a `MemorySaver` for development and database-backed checkpointers for production.\n\nEvery graph invocation gets a `thread_id` -- a unique identifier for this execution. When you resume, you provide the same `thread_id` and the graph picks up from the exact point where it paused.\n\n### Retry Loops and Quality Gates\n\nConditional edges plus state counters create **quality gates** -- patterns where the graph retries a step until quality criteria are met, up to a maximum number of attempts.\n\nCommon quality gate patterns:\n- **Code review loop:** Code -> Review -> if issues found AND retries < 3 -> Fix -> Review again\n- **Test loop:** Code -> Test -> if tests fail AND retries < 3 -> Fix -> Test again\n- **Escalation ladder:** Auto-fix -> if still failing -> Senior review -> if still failing -> Human gate' },
        { type: 'code', content: '// Human-in-the-loop with interrupt() and checkpointing\nimport { StateGraph, Annotation, START, END, interrupt, Command } from \'@langchain/langgraph\';\nimport { MemorySaver } from \'@langchain/langgraph/checkpointers\';\n\nconst DeployState = Annotation.Root({\n  changes: Annotation<string>(),\n  testResults: Annotation<string>(),\n  approved: Annotation<boolean>(),\n  deployResult: Annotation<string>(),\n});\n\n// Node that pauses for human approval\nasync function humanApproval(state: typeof DeployState.State) {\n  // interrupt() pauses the graph and sends data to the human\n  const decision = interrupt({\n    question: \'Approve deployment to production?\',\n    context: {\n      changes: state.changes,\n      testResults: state.testResults,\n    },\n  });\n\n  // When resumed, \'decision\' contains the human\'s response\n  return { approved: decision.approved };\n}\n\nasync function deploy(state: typeof DeployState.State) {\n  if (!state.approved) {\n    return { deployResult: \'Deployment rejected by reviewer.\' };\n  }\n  // Perform actual deployment...\n  return { deployResult: \'Successfully deployed to production.\' };\n}\n\n// Compile with a checkpointer (required for interrupt)\nconst checkpointer = new MemorySaver();\n\nconst graph = new StateGraph(DeployState)\n  .addNode(\'run_tests\', runTestsNode)\n  .addNode(\'human_approval\', humanApproval)\n  .addNode(\'deploy\', deploy)\n  .addEdge(START, \'run_tests\')\n  .addEdge(\'run_tests\', \'human_approval\')\n  .addEdge(\'human_approval\', \'deploy\')\n  .addEdge(\'deploy\', END)\n  .compile({ checkpointer });\n\n// --- Usage: Start the graph ---\nconst threadId = \'deploy-v2.3.1\';\nconst config = { configurable: { thread_id: threadId } };\n\nconst result1 = await graph.invoke(\n  { changes: \'Added pagination to /api/users\' },\n  config\n);\n// result1 contains an Interrupt -- graph is paused\n\n// --- Later: Human approves via your UI ---\nconst result2 = await graph.invoke(\n  new Command({ resume: { approved: true } }),\n  config  // Same thread_id resumes from the interrupt point\n);\n// result2.deployResult === \'Successfully deployed to production.\'\n\n// --- Retry loop pattern with quality gate ---\nfunction routeAfterTests(state: { testsPassing: boolean; retryCount: number }): string {\n  if (state.testsPassing) return \'deploy_ready\';\n  if (state.retryCount >= 3) return \'escalate_to_human\';\n  return \'fix_code\';  // Loop back to fix\n}\n\n// In the fix_code node, increment the counter:\nasync function fixCode(state: { retryCount: number; /* ... */ }) {\n  // ... fix logic ...\n  return { retryCount: state.retryCount + 1 };\n}', language: 'typescript' },
        { type: 'tip', content: 'Use `MemorySaver` for development and testing only. In production, use a persistent checkpointer backed by PostgreSQL or Redis. If your server restarts during an interrupt, `MemorySaver` loses all state. A database-backed checkpointer lets you resume graph execution even after server restarts, container redeployments, or scaling events.' },
        { type: 'warning', content: 'Always set a maximum retry count in your quality gate loops. Without it, a subtle bug that makes tests fail every time will cause your graph to loop forever, burning API credits. The pattern is: conditional edge checks `if retryCount >= MAX` and routes to an escalation node (human review or graceful failure) instead of looping again.' }
      ],
      quiz: [
        { id: 'q1', question: 'What does a conditional edge routing function receive and return?', options: ['It receives the model output and returns a prompt', 'It receives the current state and returns the name of the next node', 'It receives user input and returns a tool call', 'It receives an error and returns a fallback strategy'], correctIndex: 1, explanation: 'A conditional edge routing function receives the current graph state (the full typed state object) and returns a string -- the name of the next node to execute. This allows runtime decisions based on any field in state.' },
        { id: 'q2', question: 'How does interrupt() enable human-in-the-loop workflows?', options: ['It sends an email to a human', 'It pauses graph execution and waits for a Command with resume data to continue', 'It stops the graph permanently', 'It switches to a different model'], correctIndex: 1, explanation: 'interrupt() pauses the graph at the current node. The graph returns an Interrupt value to your application. When the human provides input, you call graph.invoke() with a Command({ resume: data }) and the same thread_id to continue from the pause point.' },
        { id: 'q3', question: 'Why is a checkpointer required for interrupt() to work?', options: ['It caches the LLM responses', 'It saves the graph state before pausing so execution can resume later from the same point', 'It stores the tool definitions', 'It logs the conversation for compliance'], correctIndex: 1, explanation: 'When interrupt() pauses the graph, the current state must be saved somewhere so it can be restored when the human responds. The checkpointer persists this state. Without it, the graph has no way to resume from where it paused.' }
      ]
    },
    {
      id: 'langgraph-multi-agent',
      moduleId: 'langgraph',
      title: 'Multi-Agent Graphs',
      description: 'Build a dev team as a graph: analyzer, planner, coder, tester, reviewer',
      order: 3,
      content: [
        { type: 'text', content: '## A Development Team as a Graph\n\nThe most powerful application of LangGraph is **multi-agent orchestration** -- a graph where each node is a specialized agent with its own tools, system prompt, and expertise. Together, they form a virtual development team.\n\nConsider how a real dev team works on a Jira ticket:\n\n1. A **tech lead** reads the ticket and breaks it into tasks\n2. An **architect** designs the approach\n3. A **developer** writes the code\n4. A **tester** writes and runs tests\n5. A **reviewer** checks code quality\n6. If issues are found, the code goes back to the developer\n\nIn LangGraph, each of these roles is a node. The edges define the workflow. Conditional edges handle routing when tests fail or the reviewer finds issues.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="position:relative;border:2px solid #e84393;border-radius:12px;padding:1.2rem;background:rgba(232,67,147,0.03);">\n<div style="font-weight:700;font-size:1rem;color:#e84393;margin-bottom:1rem;text-align:center;">Multi-Agent Development Pipeline</div>\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.4rem;">\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#6c5ce7;color:white;font-size:0.85rem;font-weight:600;">Jira Ticket (Input)</div>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#0984e3;color:white;font-size:0.85rem;font-weight:600;">Analyzer Node</div>\n<span style="font-size:0.72rem;color:#666;">Reads ticket, identifies requirements, checks existing code</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#00cec9;color:white;font-size:0.85rem;font-weight:600;">Planner Node</div>\n<span style="font-size:0.72rem;color:#666;">Creates step-by-step implementation plan</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#fdcb6e;color:#333;font-size:0.85rem;font-weight:600;">Coder Node</div>\n<span style="font-size:0.72rem;color:#666;">Writes code following the plan</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#e17055;color:white;font-size:0.85rem;font-weight:600;">Tester Node</div>\n<span style="font-size:0.72rem;color:#666;">Writes tests, runs them, reports results</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.3rem 0.6rem;border-radius:6px;background:rgba(232,67,147,0.12);color:#e84393;font-size:0.8rem;font-weight:600;border:1px dashed #e84393;">Tests pass?</div>\n<div style="display:flex;gap:2.5rem;align-items:flex-start;margin-top:0.3rem;">\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.3rem;">\n<span style="font-size:0.7rem;color:#e17055;font-weight:600;">NO (retry &lt; 3)</span>\n<span style="color:#888;">&#8593; back to Coder</span>\n</div>\n<div style="display:flex;flex-direction:column;align-items:center;gap:0.3rem;">\n<span style="font-size:0.7rem;color:#27ae60;font-weight:600;">YES</span>\n<span style="color:#888;">&#8595;</span>\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#27ae60;color:white;font-size:0.85rem;font-weight:600;">Reviewer Node</div>\n</div>\n</div>\n<div style="display:flex;justify-content:center;margin-top:0.5rem;">\n<span style="color:#888;">&#8595;</span>\n</div>\n<div style="display:flex;justify-content:center;">\n<div style="padding:0.4rem 1rem;border-radius:6px;background:#e84393;color:white;font-size:0.85rem;font-weight:600;">PR Created (Output)</div>\n</div>\n</div>\n</div>\n</div>\n\n### Key Design Principle: Each Agent Has a Single Responsibility\n\nJust like microservices, each agent node should do one thing well. The analyzer does not write code. The coder does not run tests. The tester does not create PRs. This separation means you can:\n- Give each agent **specialized tools** (coder gets write_file, tester gets run_tests)\n- Give each agent a **focused system prompt** optimized for its task\n- **Debug independently** -- when tests fail, you only inspect the tester and coder nodes\n- **Upgrade independently** -- swap the coder from Sonnet to Opus without touching other nodes' },
        { type: 'code', content: '// Multi-agent development team graph\nimport { StateGraph, Annotation, START, END } from \'@langchain/langgraph\';\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { createToolCallingAgent, AgentExecutor } from \'langchain/agents\';\nimport { ChatPromptTemplate, MessagesPlaceholder } from \'@langchain/core/prompts\';\n\n// Shared state across all agents\nconst TeamState = Annotation.Root({\n  ticket: Annotation<string>(),\n  requirements: Annotation<string[]>({ default: () => [] }),\n  plan: Annotation<string>(),\n  codeChanges: Annotation<{ file: string; content: string }[]>({\n    default: () => [],\n  }),\n  testResults: Annotation<{ passed: boolean; output: string }>({\n    default: () => ({ passed: false, output: \'\' }),\n  }),\n  reviewFeedback: Annotation<string>(),\n  retryCount: Annotation<number>({ default: () => 0 }),\n  prUrl: Annotation<string>(),\n});\n\n// --- Agent factory: create specialized agents ---\nfunction createSpecialistAgent(\n  systemPrompt: string,\n  tools: any[],\n  modelName: string = \'claude-sonnet-4-6-20250514\'\n) {\n  const model = new ChatAnthropic({ modelName, temperature: 0 });\n  const prompt = ChatPromptTemplate.fromMessages([\n    [\'system\', systemPrompt],\n    [\'human\', \'{input}\'],\n    new MessagesPlaceholder(\'agent_scratchpad\'),\n  ]);\n  const agent = createToolCallingAgent({ llm: model, tools, prompt });\n  return new AgentExecutor({ agent, tools, maxIterations: 15 });\n}\n\n// --- Specialized agents ---\nconst analyzerAgent = createSpecialistAgent(\n  \'You are a senior tech lead. Analyze the Jira ticket and extract:\\n\' +\n  \'1. Clear requirements\\n2. Affected files and modules\\n\' +\n  \'3. Potential risks\\nUse the search and read tools to understand the codebase.\',\n  [searchCodeTool, readFileTool]\n);\n\nconst plannerAgent = createSpecialistAgent(\n  \'You are a software architect. Given requirements, create a detailed\\n\' +\n  \'implementation plan with specific file changes and their order.\',\n  [searchCodeTool, readFileTool]\n);\n\nconst coderAgent = createSpecialistAgent(\n  \'You are a senior developer. Follow the plan exactly.\\n\' +\n  \'Write clean, tested, production-quality code.\\n\' +\n  \'If you received test failure feedback, fix the specific issue.\',\n  [readFileTool, writeFileTool, searchCodeTool],\n  \'claude-opus-4-6-20250414\'  // Use Opus for complex coding\n);\n\nconst testerAgent = createSpecialistAgent(\n  \'You are a QA engineer. Write comprehensive tests and run them.\\n\' +\n  \'Test happy paths, edge cases, and error conditions.\\n\' +\n  \'Report results clearly: which tests pass and which fail.\',\n  [readFileTool, writeFileTool, runCommandTool]\n);\n\nconst reviewerAgent = createSpecialistAgent(\n  \'You are a code reviewer. Check for:\\n\' +\n  \'1. Code quality and readability\\n2. Security vulnerabilities\\n\' +\n  \'3. Performance issues\\n4. Adherence to project conventions\',\n  [readFileTool, searchCodeTool]\n);\n\n// --- Graph nodes: wrap agents as node functions ---\nasync function analyzeNode(state: typeof TeamState.State) {\n  const result = await analyzerAgent.invoke({\n    input: `Analyze this ticket:\\n${state.ticket}`,\n  });\n  return { requirements: JSON.parse(result.output) };\n}\n\nasync function planNode(state: typeof TeamState.State) {\n  const result = await plannerAgent.invoke({\n    input: `Requirements: ${JSON.stringify(state.requirements)}`,\n  });\n  return { plan: result.output };\n}\n\nasync function codeNode(state: typeof TeamState.State) {\n  const feedback = state.testResults.passed === false && state.retryCount > 0\n    ? `\\nPrevious test failure: ${state.testResults.output}\\nFix the issue.`\n    : \'\';\n  const result = await coderAgent.invoke({\n    input: `Plan: ${state.plan}${feedback}`,\n  });\n  return {\n    codeChanges: JSON.parse(result.output),\n    retryCount: state.retryCount + (feedback ? 1 : 0),\n  };\n}\n\nasync function testNode(state: typeof TeamState.State) {\n  const result = await testerAgent.invoke({\n    input: `Test these changes: ${JSON.stringify(state.codeChanges)}`,\n  });\n  return { testResults: JSON.parse(result.output) };\n}\n\nasync function reviewNode(state: typeof TeamState.State) {\n  const result = await reviewerAgent.invoke({\n    input: `Review these changes: ${JSON.stringify(state.codeChanges)}`,\n  });\n  return { reviewFeedback: result.output };\n}', language: 'typescript' },
        { type: 'code', content: '// Wire the graph with conditional routing\nfunction routeAfterTests(state: typeof TeamState.State): string {\n  if (state.testResults.passed) return \'review\';     // Tests pass -> review\n  if (state.retryCount >= 3) return \'review\';         // Max retries -> review anyway\n  return \'code\';                                       // Tests fail -> back to coder\n}\n\nfunction routeAfterReview(state: typeof TeamState.State): string {\n  const hasBlockers = state.reviewFeedback.toLowerCase().includes(\'blocker\');\n  if (hasBlockers && state.retryCount < 3) return \'code\';  // Fix blockers\n  return \'create_pr\';  // Approved or max retries\n}\n\nasync function createPRNode(state: typeof TeamState.State) {\n  // Create the PR using git tools\n  return { prUrl: \'https://github.com/org/repo/pull/123\' };\n}\n\nconst teamGraph = new StateGraph(TeamState)\n  .addNode(\'analyze\', analyzeNode)\n  .addNode(\'plan\', planNode)\n  .addNode(\'code\', codeNode)\n  .addNode(\'test\', testNode)\n  .addNode(\'review\', reviewNode)\n  .addNode(\'create_pr\', createPRNode)\n  // Linear edges\n  .addEdge(START, \'analyze\')\n  .addEdge(\'analyze\', \'plan\')\n  .addEdge(\'plan\', \'code\')\n  .addEdge(\'code\', \'test\')\n  // Conditional edges\n  .addConditionalEdges(\'test\', routeAfterTests, {\n    review: \'review\',\n    code: \'code\',  // Retry loop\n  })\n  .addConditionalEdges(\'review\', routeAfterReview, {\n    code: \'code\',        // Fix blockers\n    create_pr: \'create_pr\',\n  })\n  .addEdge(\'create_pr\', END)\n  .compile();\n\n// Run the full pipeline\nconst result = await teamGraph.invoke({\n  ticket: \'PROJ-456: Add cursor-based pagination to GET /api/users\',\n});\n\nconsole.log(\'PR Created:\', result.prUrl);\nconsole.log(\'Retry count:\', result.retryCount);\nconsole.log(\'Review feedback:\', result.reviewFeedback);', language: 'typescript' },
        { type: 'agent-demo', content: 'langgraph-team-demo' },
        { type: 'text', content: '### Design Decisions for Multi-Agent Graphs\n\n**Model selection per node:** Use the cheapest model that meets the quality bar. The analyzer and planner can use Sonnet (reading and reasoning). The coder might need Opus (complex code generation). The tester can use Sonnet (writing tests is structured). The reviewer can use Sonnet (pattern matching against quality criteria).\n\n**State as the communication channel:** Agents do not talk to each other directly. They communicate through shared state. The planner writes `plan` to state; the coder reads `plan` from state. This decoupling means you can swap any agent without changing the others.\n\n**Retry loops with counters:** Always include a `retryCount` in state and check it in your conditional routing. The pattern is: if quality gate fails AND retries < max, loop back. If retries >= max, escalate (human review, or proceed with warnings). Never allow unbounded loops.\n\n### Common Mistakes\n\n1. **Too many agents.** Start with 3-4 agents and add more only when a specific quality problem demands specialization. More agents = more complexity = harder to debug.\n2. **Agents that are too general.** An agent with 15 tools and a vague prompt will perform worse than one with 3 tools and a focused prompt. Specialization is the point.\n3. **Not logging intermediate state.** When the pipeline produces bad output, you need to see what each agent contributed. Log `state` after every node for debugging.\n4. **Skipping the planner.** Jumping straight from ticket to code is tempting but produces worse results. The planner step forces the system to think before acting -- TAOR at the graph level.' },
        { type: 'tip', content: 'Start with a 3-node graph (plan -> code -> test) and get it working end-to-end before adding more agents. A working 3-node pipeline you can debug is worth more than a perfect 7-node pipeline you cannot. Add the analyzer and reviewer after the core loop is solid.' }
      ],
      quiz: [
        { id: 'q1', question: 'Why should each agent node have a single responsibility?', options: ['To reduce API costs', 'So you can give each agent specialized tools, focused prompts, and debug/upgrade them independently', 'Because LangGraph only allows one tool per node', 'To make the graph look cleaner'], correctIndex: 1, explanation: 'Single responsibility means each agent gets a focused system prompt, specialized tools, and can be debugged or upgraded independently. This mirrors the microservices principle: small, focused, independently deployable units.' },
        { id: 'q2', question: 'How do agents communicate in a multi-agent LangGraph?', options: ['They call each other directly', 'Through shared state -- each agent reads from and writes to the state object', 'Through a message queue', 'Through the LLM context window'], correctIndex: 1, explanation: 'Agents communicate through shared state. The planner writes a plan to state; the coder reads it. This decoupling means you can swap any agent without changing the others, as long as the state interface stays the same.' },
        { id: 'q3', question: 'What happens when tests fail in the multi-agent pipeline?', options: ['The pipeline stops immediately', 'The conditional edge routes back to the coder node with the test failure in state, up to a retry limit', 'A human is notified', 'The tester agent fixes the code'], correctIndex: 1, explanation: 'The conditional routing function after the test node checks if tests passed. If not and retries are under the limit, it routes back to the coder with the test failure output in state. The coder reads the failure and attempts a fix. This creates a self-healing loop with bounded retries.' }
      ]
    },
    {
      id: 'langgraph-taor',
      moduleId: 'langgraph',
      title: 'LangGraph + TAOR: The Complete Pattern',
      description: 'TAOR inside nodes, LangGraph between nodes -- the production architecture',
      order: 4,
      content: [
        { type: 'text', content: '## Two Levels of Intelligence\n\nProduction AI systems operate at two levels simultaneously, and understanding this distinction is what separates toy prototypes from real-world tools.\n\n### Level 1: TAOR Micro (Inside Each Node)\n\nEach node in the graph runs its own TAOR agent loop. The coder node does not just call Claude once and paste the output. It **thinks** about the plan, **acts** by reading a file, **observes** the current code, **thinks** about what to change, **acts** by writing the change, **observes** the result, and **repeats** until its specific task is complete.\n\nThis is TAOR at the **micro** level -- disciplined, step-by-step reasoning within a single agent.\n\n### Level 2: LangGraph Macro (Between Nodes)\n\nThe graph itself is a higher-level TAOR. The graph **routes** between agents (which agent works next), **manages state** (what has been accomplished), **enforces quality gates** (do tests pass?), and **handles failures** (retry, escalate, or abort).\n\nThis is TAOR at the **macro** level -- orchestration of multiple agents toward a shared goal.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="border:2px solid #e84393;border-radius:12px;padding:1.2rem;background:rgba(232,67,147,0.03);">\n<div style="font-weight:700;font-size:1rem;color:#e84393;margin-bottom:1rem;text-align:center;">The Complete Architecture</div>\n<div style="display:flex;gap:0.8rem;flex-wrap:wrap;justify-content:center;">\n<div style="border:2px solid #0984e3;border-radius:10px;padding:0.8rem;flex:1;min-width:140px;max-width:200px;">\n<div style="font-weight:700;color:#0984e3;font-size:0.9rem;margin-bottom:0.4rem;">Planner Node</div>\n<div style="font-size:0.75rem;color:#666;border-top:1px dashed #ccc;padding-top:0.3rem;line-height:1.6;">\n<span style="color:#0984e3;">T:</span> Read requirements<br>\n<span style="color:#00cec9;">A:</span> Search codebase<br>\n<span style="color:#e17055;">O:</span> Found 3 files<br>\n<span style="color:#0984e3;">T:</span> Plan approach<br>\n<span style="color:#27ae60;">R:</span> Done, plan ready\n</div>\n</div>\n<div style="border:2px solid #6c5ce7;border-radius:10px;padding:0.8rem;flex:1;min-width:140px;max-width:200px;">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.9rem;margin-bottom:0.4rem;">Coder Node</div>\n<div style="font-size:0.75rem;color:#666;border-top:1px dashed #ccc;padding-top:0.3rem;line-height:1.6;">\n<span style="color:#0984e3;">T:</span> Read plan<br>\n<span style="color:#00cec9;">A:</span> Read users.ts<br>\n<span style="color:#e17055;">O:</span> Current code seen<br>\n<span style="color:#00cec9;">A:</span> Write changes<br>\n<span style="color:#e17055;">O:</span> File saved<br>\n<span style="color:#27ae60;">R:</span> Done, code ready\n</div>\n</div>\n<div style="border:2px solid #e17055;border-radius:10px;padding:0.8rem;flex:1;min-width:140px;max-width:200px;">\n<div style="font-weight:700;color:#e17055;font-size:0.9rem;margin-bottom:0.4rem;">Tester Node</div>\n<div style="font-size:0.75rem;color:#666;border-top:1px dashed #ccc;padding-top:0.3rem;line-height:1.6;">\n<span style="color:#0984e3;">T:</span> Review changes<br>\n<span style="color:#00cec9;">A:</span> Write test file<br>\n<span style="color:#00cec9;">A:</span> Run tests<br>\n<span style="color:#e17055;">O:</span> 2/5 failing<br>\n<span style="color:#0984e3;">T:</span> Analyze failures<br>\n<span style="color:#27ae60;">R:</span> Report results\n</div>\n</div>\n</div>\n<div style="margin-top:1rem;text-align:center;">\n<div style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.4rem 1rem;border-radius:20px;background:rgba(232,67,147,0.1);font-size:0.85rem;color:#e84393;font-weight:600;">\nLangGraph routes between nodes based on state\n</div>\n</div>\n<div style="margin-top:0.8rem;display:flex;justify-content:center;gap:0.4rem;flex-wrap:wrap;">\n<span style="padding:0.2rem 0.5rem;border-radius:4px;background:rgba(39,174,96,0.1);color:#27ae60;font-size:0.75rem;">Tests pass &#8594; Reviewer</span>\n<span style="padding:0.2rem 0.5rem;border-radius:4px;background:rgba(225,112,85,0.1);color:#e17055;font-size:0.75rem;">Tests fail &#8594; Coder (retry)</span>\n<span style="padding:0.2rem 0.5rem;border-radius:4px;background:rgba(108,92,231,0.1);color:#6c5ce7;font-size:0.75rem;">Max retries &#8594; Human gate</span>\n</div>\n</div>\n</div>\n\n### Why This Architecture Wins\n\n1. **Each node is reliable** because TAOR forces step-by-step verification within the agent.\n2. **The graph is resilient** because conditional edges handle failures, retries, and escalation.\n3. **State provides continuity** -- every node knows what happened before and can build on it.\n4. **The system self-heals** -- test failures loop back to the coder with specific error context.' },
        { type: 'code', content: '// The Complete Pattern: TAOR agents inside LangGraph nodes\nimport { StateGraph, Annotation, START, END } from \'@langchain/langgraph\';\nimport { MemorySaver } from \'@langchain/langgraph/checkpointers\';\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport Anthropic from \'@anthropic-ai/sdk\';\n\n// --- State definition ---\nconst PipelineState = Annotation.Root({\n  ticket: Annotation<string>(),\n  plan: Annotation<string>(),\n  code: Annotation<{ file: string; content: string }[]>({\n    default: () => [],\n  }),\n  testOutput: Annotation<string>(),\n  testsPassing: Annotation<boolean>({ default: () => false }),\n  reviewResult: Annotation<string>(),\n  approved: Annotation<boolean>({ default: () => false }),\n  retryCount: Annotation<number>({ default: () => 0 }),\n  prUrl: Annotation<string>(),\n  log: Annotation<string[]>({\n    default: () => [],\n    // Reducer: append new log entries instead of replacing\n    reducer: (existing, newEntries) => [...existing, ...newEntries],\n  }),\n});\n\n// --- TAOR Agent Runner (micro level) ---\n// This is the inner loop each node runs\nconst rawClient = new Anthropic();\n\nasync function runTaorAgent(\n  systemPrompt: string,\n  task: string,\n  tools: Anthropic.Tool[],\n  maxIterations: number = 20\n): Promise<string> {\n  const messages: Anthropic.MessageParam[] = [\n    { role: \'user\', content: task },\n  ];\n\n  for (let i = 0; i < maxIterations; i++) {\n    const response = await rawClient.messages.create({\n      model: \'claude-sonnet-4-6-20250514\',\n      max_tokens: 4096,\n      system: systemPrompt,\n      tools,\n      messages,\n    });\n\n    messages.push({ role: \'assistant\', content: response.content });\n\n    // TAOR: If the agent is done (end_turn), extract final answer\n    if (response.stop_reason === \'end_turn\') {\n      const textBlock = response.content.find(b => b.type === \'text\');\n      return textBlock ? textBlock.text : \'\';\n    }\n\n    // TAOR: If the agent wants to use a tool, execute and observe\n    if (response.stop_reason === \'tool_use\') {\n      const toolUse = response.content.find(b => b.type === \'tool_use\')!;\n      const result = await executeTool(toolUse.name, toolUse.input);\n      messages.push({\n        role: \'user\',\n        content: [{\n          type: \'tool_result\',\n          tool_use_id: toolUse.id,\n          content: typeof result === \'string\' ? result : JSON.stringify(result),\n        }],\n      });\n    }\n  }\n\n  return \'Max iterations reached\';\n}\n\n// --- Graph nodes: each runs a TAOR agent ---\nasync function plannerNode(state: typeof PipelineState.State) {\n  const plan = await runTaorAgent(\n    \'You are a software architect. Create a detailed implementation plan.\',\n    `Ticket: ${state.ticket}\\n\\nAnalyze the requirements and create a ` +\n    \'step-by-step plan with specific files to change.\',\n    [searchCodeTool, readFileTool]\n  );\n  return {\n    plan,\n    log: [`[Planner] Created implementation plan`],\n  };\n}\n\nasync function coderNode(state: typeof PipelineState.State) {\n  const retryContext = state.retryCount > 0\n    ? `\\n\\nPREVIOUS ATTEMPT FAILED. Test output:\\n${state.testOutput}\\nFix the issue.`\n    : \'\';\n\n  const result = await runTaorAgent(\n    \'You are a senior developer. Write clean, production-quality code. \' +\n    \'Follow the plan exactly. Return the changes as JSON.\',\n    `Plan:\\n${state.plan}${retryContext}`,\n    [readFileTool, writeFileTool, searchCodeTool],\n  );\n\n  return {\n    code: JSON.parse(result),\n    log: [`[Coder] Wrote code (attempt ${state.retryCount + 1})`],\n  };\n}\n\nasync function testerNode(state: typeof PipelineState.State) {\n  const result = await runTaorAgent(\n    \'You are a QA engineer. Write tests and run them. \' +\n    \'Return JSON: { \"passed\": boolean, \"output\": string }\',\n    `Test these changes:\\n${JSON.stringify(state.code)}`,\n    [readFileTool, writeFileTool, runCommandTool],\n  );\n\n  const parsed = JSON.parse(result);\n  return {\n    testOutput: parsed.output,\n    testsPassing: parsed.passed,\n    retryCount: parsed.passed ? state.retryCount : state.retryCount + 1,\n    log: [`[Tester] Tests ${parsed.passed ? \'PASSED\' : \'FAILED\'}`],\n  };\n}', language: 'typescript' },
        { type: 'code', content: '// Wire the complete graph\nfunction routeAfterTests(state: typeof PipelineState.State): string {\n  if (state.testsPassing) return \'reviewer\';\n  if (state.retryCount >= 3) return \'escalate\';\n  return \'coder\';  // Retry loop\n}\n\nasync function reviewerNode(state: typeof PipelineState.State) {\n  const result = await runTaorAgent(\n    \'You are a code reviewer. Check quality, security, and conventions. \' +\n    \'Return JSON: { \"approved\": boolean, \"feedback\": string }\',\n    `Review:\\n${JSON.stringify(state.code)}`,\n    [readFileTool, searchCodeTool],\n  );\n  const parsed = JSON.parse(result);\n  return {\n    reviewResult: parsed.feedback,\n    approved: parsed.approved,\n    log: [`[Reviewer] ${parsed.approved ? \'Approved\' : \'Changes requested\'}`],\n  };\n}\n\nasync function escalateNode(state: typeof PipelineState.State) {\n  // In production: send to Slack, create a Jira comment, etc.\n  return {\n    log: [`[Escalation] Tests failed ${state.retryCount} times. Human review needed.`],\n  };\n}\n\nasync function createPRNode(state: typeof PipelineState.State) {\n  // In production: use git tools to create branch, commit, push, create PR\n  return {\n    prUrl: \'https://github.com/org/repo/pull/456\',\n    log: [`[PR] Created pull request`],\n  };\n}\n\nconst checkpointer = new MemorySaver();\n\nconst pipeline = new StateGraph(PipelineState)\n  .addNode(\'planner\', plannerNode)\n  .addNode(\'coder\', coderNode)\n  .addNode(\'tester\', testerNode)\n  .addNode(\'reviewer\', reviewerNode)\n  .addNode(\'escalate\', escalateNode)\n  .addNode(\'create_pr\', createPRNode)\n  // Edges\n  .addEdge(START, \'planner\')\n  .addEdge(\'planner\', \'coder\')\n  .addEdge(\'coder\', \'tester\')\n  .addConditionalEdges(\'tester\', routeAfterTests, {\n    reviewer: \'reviewer\',\n    coder: \'coder\',        // Retry loop\n    escalate: \'escalate\',  // Max retries exceeded\n  })\n  .addEdge(\'reviewer\', \'create_pr\')\n  .addEdge(\'escalate\', END)\n  .addEdge(\'create_pr\', END)\n  .compile({ checkpointer });\n\n// --- Run the complete pipeline ---\nconst finalState = await pipeline.invoke(\n  { ticket: \'PROJ-789: Add rate limiting to /api/payments endpoint\' },\n  { configurable: { thread_id: \'proj-789-impl\' } }\n);\n\nconsole.log(\'\\n=== Pipeline Log ===\");\nfinalState.log.forEach((entry: string) => console.log(entry));\nconsole.log(\'PR:\', finalState.prUrl);\nconsole.log(\'Tests passing:\', finalState.testsPassing);\nconsole.log(\'Approved:\', finalState.approved);', language: 'typescript' },
        { type: 'text', content: '## Why This Is How Production AI Tools Work\n\nEvery serious AI coding tool -- Claude Code, GitHub Copilot Workspace, Cursor Agent, Devin -- uses some variation of this architecture. The specifics differ, but the pattern is universal:\n\n1. **Specialized agents** that each do one thing well (read code, write code, run tests, create PRs)\n2. **A graph/orchestrator** that routes work between agents based on results\n3. **State management** that preserves context across dozens of LLM calls\n4. **Quality gates** that catch failures and trigger retries before shipping broken code\n5. **Human-in-the-loop checkpoints** for high-stakes decisions\n\n### The TAOR + LangGraph Mental Model\n\n| Level | What | How | Example |\n|-------|------|-----|--------|\n| **Micro (TAOR)** | Inside each node | Think-Act-Observe-Repeat agent loop | Coder reads file, writes change, verifies it compiled |\n| **Macro (LangGraph)** | Between nodes | State + conditional edges + quality gates | Tests fail -> route back to coder with error context |\n| **Meta (Human)** | Above the graph | interrupt() + checkpointing | Approve deployment to production |\n\n### Building Your Own: A Practical Roadmap\n\n1. **Week 1:** Build a single TAOR agent that can read/write files and run commands\n2. **Week 2:** Split into 3 agents (plan, code, test) wired with LangGraph\n3. **Week 3:** Add conditional routing (test failure -> retry loop) and state management\n4. **Week 4:** Add human-in-the-loop gates, LangSmith observability, and production hardening\n\nEach week builds on the previous one. By week 4, you have a production-grade development pipeline that mirrors how the best AI tools work.\n\n### Key Takeaways\n\n1. **TAOR micro (inside nodes) + LangGraph macro (between nodes)** is the complete production pattern.\n2. **Each node runs a full TAOR agent** -- not a single LLM call. The agent loops internally until its sub-task is done.\n3. **The graph provides routing, retries, and state** -- concerns that individual agents should not manage.\n4. **Quality gates (test -> retry loop)** are what make the system reliable. Without them, you ship broken code.\n5. **This is not theoretical.** This is how Claude Code, Copilot Workspace, and Devin actually work under the hood.' },
        { type: 'tip', content: 'The state `log` field with the append reducer is a production essential. It creates an audit trail of what every agent did, in order. When something goes wrong, you do not need to dig through LangSmith traces -- the log tells you exactly which agent acted and what happened. Add a `log` reducer to every production graph.' },
        { type: 'warning', content: 'Do not try to build the full 6-node pipeline on day one. Start with the simplest possible graph (2 nodes, 1 edge) and get it working end-to-end. Then add one node at a time. Every node you add introduces potential failure modes and state interactions. Incremental development applies to graph design just as much as it applies to application code.' }
      ],
      quiz: [
        { id: 'q1', question: 'What is the difference between TAOR micro and TAOR macro in this architecture?', options: ['Micro is for small tasks, macro is for large tasks', 'Micro is the TAOR loop inside each agent node; macro is the graph-level routing and quality gates between nodes', 'Micro uses Haiku, macro uses Opus', 'There is no difference -- they are the same pattern'], correctIndex: 1, explanation: 'TAOR micro is the Think-Act-Observe-Repeat loop running inside each individual agent node (e.g., the coder reading files, writing code, checking results). TAOR macro is the graph-level orchestration: routing between nodes, managing state, enforcing quality gates, and handling retries.' },
        { id: 'q2', question: 'Why does the coder node receive test failure output on retries?', options: ['To increase the token count', 'So it can fix the specific issue that caused the test failure instead of guessing', 'Because LangGraph requires it', 'To help the coder write tests'], correctIndex: 1, explanation: 'When the conditional edge routes back to the coder after a test failure, the test output is in state. The coder node checks retryCount and includes the test failure as context, so the TAOR agent inside can reason about the specific error and fix it. Without this feedback, the coder would repeat the same mistake.' },
        { id: 'q3', question: 'What does the state log reducer (append mode) provide?', options: ['Better performance', 'An audit trail showing what every agent did in order, for debugging and observability', 'Automatic error correction', 'Reduced memory usage'], correctIndex: 1, explanation: 'The log field with an append reducer accumulates entries from every node: [Planner] Created plan, [Coder] Wrote code (attempt 1), [Tester] Tests FAILED, [Coder] Wrote code (attempt 2), etc. This creates a complete audit trail for debugging, without needing to inspect individual agent traces.' }
      ]
    }
        ]
      },
      {
        id: 'mcp-deep-dive',
        title: 'MCP Deep Dive',
        description: 'Build custom MCP servers and integrate AI with any external system',
        icon: '🔌',
        color: '#6c5ce7',
        order: 10,
        lessons: [
{
      id: 'mcp-architecture',
      moduleId: 'mcp-deep-dive',
      title: 'MCP Protocol Architecture',
      description: 'Understand MCP as the universal integration layer for AI agents',
      order: 1,
      content: [
        { type: 'text', content: '## MCP: USB for AI\n\nBefore MCP, every AI tool integration was a bespoke bridge. If you had **N** AI hosts (Claude, GPT, Gemini, your own agent) and **M** services (Slack, Jira, GitHub, a database), you needed **N x M** custom integrations. MCP collapses that to **N + M**: every host speaks one protocol, every service exposes one server.\n\n### Why This Matters for Your Team\n\nImagine your team has three agents: a code-review bot, an incident-response agent, and a deployment pipeline assistant. Without MCP, each one needs hand-written glue code for every tool it touches. When the Jira API changes, you fix it in three places. When you add Confluence, you write three new integrations.\n\nWith MCP, Jira exposes a single MCP server. All three agents connect to it. When the API changes, you update one server. When you add Confluence, you build one server and all agents gain Confluence access automatically.\n\nThis is exactly the insight behind USB: before it, every peripheral needed a unique port. After it, one port fits everything. MCP is that moment for AI integrations.\n\n### The Core Insight\n\nMCP does not replace your existing APIs. It **wraps** them with a standardized protocol that AI models already understand. Your REST endpoints, GraphQL queries, database connections, and CLI tools all keep working. MCP just gives them a uniform shape that any LLM host can discover and invoke.' },
        { type: 'text', content: '## Architecture: Host, Client, Server, Service\n\nMCP follows a clean four-layer architecture. Understanding each layer is critical for building reliable integrations.\n\n<div style="display:flex;flex-direction:column;gap:0;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="padding:0.8rem 1rem;border-radius:8px 8px 0 0;border:2px solid #0984e3;background:rgba(9,132,227,0.08);">\n<div style="font-weight:700;color:#0984e3;font-size:1rem;">HOST (Claude Desktop, Claude Code, your app)</div>\n<div style="font-size:0.85rem;color:#555;margin-top:0.3rem;">The application the user interacts with. Manages one or more MCP clients. Owns the conversation context and decides when to call tools.</div>\n</div>\n<div style="text-align:center;font-size:1.2rem;color:#0984e3;padding:0.2rem 0;">| JSON-RPC 2.0 |</div>\n<div style="padding:0.8rem 1rem;border:2px solid #00cec9;background:rgba(0,206,201,0.08);">\n<div style="font-weight:700;color:#00cec9;font-size:1rem;">CLIENT (inside the host)</div>\n<div style="font-size:0.85rem;color:#555;margin-top:0.3rem;">Maintains a 1:1 stateful session with a single MCP server. Handles capability negotiation, message routing, and connection lifecycle.</div>\n</div>\n<div style="text-align:center;font-size:1.2rem;color:#00cec9;padding:0.2rem 0;">| stdio or HTTP+SSE |</div>\n<div style="padding:0.8rem 1rem;border:2px solid #fdcb6e;background:rgba(253,203,110,0.08);">\n<div style="font-weight:700;color:#e17055;font-size:1rem;">SERVER (your MCP server)</div>\n<div style="font-size:0.85rem;color:#555;margin-top:0.3rem;">Exposes tools, resources, and prompts via a standardized interface. One server per service domain (e.g., one for Jira, one for your database).</div>\n</div>\n<div style="text-align:center;font-size:1.2rem;color:#e17055;padding:0.2rem 0;">| native SDK / HTTP / CLI |</div>\n<div style="padding:0.8rem 1rem;border-radius:0 0 8px 8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.08);">\n<div style="font-weight:700;color:#6c5ce7;font-size:1rem;">SERVICE (Jira, GitHub, PostgreSQL, etc.)</div>\n<div style="font-size:0.85rem;color:#555;margin-top:0.3rem;">The actual external system. The MCP server talks to it using whatever native protocol the service requires. The host never touches this layer directly.</div>\n</div>\n</div>\n\n**Key principle:** The host never talks directly to the service. The MCP server is a clean abstraction boundary. This means your agent code stays the same even when the underlying service changes completely.' },
        { type: 'text', content: '## Tools vs Resources: Two Fundamental Primitives\n\nMCP servers expose two core primitives, and confusing them is a common mistake.\n\n### Tools (Actions)\n\nTools are **functions the model can call** to perform actions or computations. They follow the standard function-calling pattern: name, description, JSON Schema for inputs, and a handler that returns results.\n\nExamples: `create_jira_issue`, `run_sql_query`, `send_slack_message`, `deploy_service`.\n\nThe model **decides** when to call a tool based on the user\'s request. Tools are model-controlled.\n\n### Resources (Data)\n\nResources are **data the application can read** to provide context. Think of them as files or documents the host can fetch and inject into the conversation. They have URIs (like `jira://issue/PROJ-123` or `db://schema/users`) and return content.\n\nExamples: `jira://issue/PROJ-456`, `github://repo/myorg/myrepo/file/src/main.ts`, `db://schema/public`.\n\nResources are **application-controlled** -- the host decides when to fetch them, not the model.\n\n### Why the Distinction Matters\n\n| Aspect | Tools | Resources |\n|--------|-------|----------|\n| Who controls | Model decides | Application decides |\n| Direction | Action (write/compute) | Data (read) |\n| Analogy | POST endpoint | GET endpoint |\n| Risk | Can change state | Read-only |\n| Discovery | Listed with schemas | Listed with URIs |\n\nA well-designed MCP server uses **tools** for operations that change state and **resources** for operations that fetch context. This separation lets hosts enforce security policies: resources are always safe to fetch, but tools might need confirmation.' },
        { type: 'text', content: '## Transport: stdio vs HTTP+SSE\n\nMCP supports two transport mechanisms, and choosing the right one depends on your deployment model.\n\n### stdio (Standard I/O)\n\nThe host launches the MCP server as a **child process** and communicates via stdin/stdout. Each message is a newline-delimited JSON-RPC frame.\n\n**Best for:** Local tools, CLI integrations, development, single-user scenarios. Claude Desktop and Claude Code use stdio for local MCP servers.\n\n**Advantages:** Zero network config, process-level isolation, automatic lifecycle (host starts/stops the server).\n\n### HTTP + SSE (Server-Sent Events)\n\nThe server runs as a **standalone HTTP service**. The client sends requests via HTTP POST and receives streamed responses via SSE.\n\n**Best for:** Remote servers, shared infrastructure, multi-user scenarios, cloud deployment.\n\n**Advantages:** Network-accessible, can serve multiple clients, standard HTTP tooling (load balancers, auth proxies).\n\n### Discovery Flow\n\nWhen a host connects to an MCP server, a three-step handshake occurs:\n\n1. **Initialize** -- Client sends `initialize` with its capabilities. Server responds with its capabilities.\n2. **List** -- Client calls `tools/list` and `resources/list` to discover what the server offers.\n3. **Ready** -- Client sends `initialized` notification. The session is live.\n\nAfter discovery, the host knows every tool name, description, and input schema. It injects these into the model\'s context so the LLM can decide when to use them.' },
        { type: 'code', content: '// MCP server configuration in Claude Desktop / Claude Code\n// File: claude_desktop_config.json\n\n{\n  "mcpServers": {\n    // stdio transport — local process\n    "jira": {\n      "command": "node",\n      "args": ["./mcp-servers/jira-server/dist/index.js"],\n      "env": {\n        "JIRA_URL": "https://mycompany.atlassian.net",\n        "JIRA_TOKEN": "your-api-token"\n      }\n    },\n\n    // stdio transport — npx for quick setup\n    "github": {\n      "command": "npx",\n      "args": ["-y", "@modelcontextprotocol/server-github"],\n      "env": {\n        "GITHUB_TOKEN": "ghp_xxxxxxxxxxxx"\n      }\n    },\n\n    // HTTP+SSE transport — remote server\n    "company-db": {\n      "url": "https://mcp.internal.company.com/db",\n      "headers": {\n        "Authorization": "Bearer ${MCP_DB_TOKEN}"\n      }\n    }\n  }\n}', language: 'json' },
        { type: 'tip', content: 'Start with stdio for development and local tools. Switch to HTTP+SSE only when you need remote access or multi-user support. Most teams run their first MCP servers locally for months before needing the HTTP transport.' },
        { type: 'warning', content: 'MCP servers run with the permissions of the process that hosts them. A stdio server launched by Claude Desktop inherits YOUR filesystem access and environment variables. Treat MCP server code with the same security rigor as any server-side code -- validate inputs, limit permissions, and never expose secrets in tool outputs.' }
      ],
      quiz: [
        { id: 'mcp-arch-q1', question: 'Why does MCP reduce the integration problem from N x M to N + M?', options: ['It replaces all existing APIs with a single API', 'Every host and every service speaks one standardized protocol, so each only needs one implementation', 'It uses AI to automatically generate integrations', 'It only works with a limited number of services'], correctIndex: 1, explanation: 'MCP standardizes the protocol between hosts and services. Each host implements one MCP client, each service implements one MCP server, and they all interoperate. This is the same insight behind USB or TCP/IP.' },
        { id: 'mcp-arch-q2', question: 'What is the key difference between MCP Tools and Resources?', options: ['Tools are faster than Resources', 'Tools are model-controlled actions; Resources are application-controlled data', 'Tools use JSON; Resources use XML', 'There is no real difference — they are interchangeable'], correctIndex: 1, explanation: 'Tools are functions the model decides to call (actions, computations, state changes). Resources are data the application decides to fetch (context, documents, schemas). This separation enables clear security policies.' },
        { id: 'mcp-arch-q3', question: 'During the MCP discovery flow, what does the client learn from tools/list?', options: ['The server\'s pricing model', 'Every available tool name, description, and input JSON Schema', 'The server\'s source code', 'Which other servers are available'], correctIndex: 1, explanation: 'The tools/list call returns every tool the server exposes, including names, descriptions, and full JSON Schema for inputs. The host injects these into the LLM\'s context so it knows what it can call and what parameters are needed.' }
      ]
    },
    {
      id: 'building-mcp-server',
      moduleId: 'mcp-deep-dive',
      title: 'Building a Custom MCP Server',
      description: 'Step-by-step guide to creating an MCP server with TypeScript and the official SDK',
      order: 2,
      content: [
        { type: 'text', content: '## Why Build Your Own MCP Server?\n\nThe MCP ecosystem already has pre-built servers for GitHub, Slack, PostgreSQL, Jira, and dozens more. So why build your own?\n\nBecause your team has **internal systems** that no open-source server covers: your deployment pipeline, your internal wiki, your custom monitoring stack, your company-specific APIs. These are exactly the systems where AI agents add the most value, because they encode institutional knowledge that only your team has.\n\nBuilding an MCP server is simpler than building a REST API. There are no routes to design, no authentication middleware to configure, no OpenAPI specs to maintain. You define tools with Zod schemas and write handler functions. The SDK handles all the protocol machinery.\n\n### What You Will Build\n\nIn this lesson, we will build a complete MCP server for a hypothetical internal deployment service. It will expose:\n\n- **Tools**: `deploy_service`, `rollback_service`, `get_deploy_status`\n- **Resources**: `deploy://services` (list of services), `deploy://service/{name}/history` (deployment history)\n\nBy the end, you will be able to connect this server to Claude Desktop and have Claude manage your deployments through natural language.' },
        { type: 'code', content: '// Step 1: Initialize the project\n// mkdir my-deploy-mcp && cd my-deploy-mcp\n// npm init -y\n// npm install @modelcontextprotocol/sdk zod\n// npm install -D typescript @types/node\n\n// tsconfig.json\n{\n  "compilerOptions": {\n    "target": "ES2022",\n    "module": "Node16",\n    "moduleResolution": "Node16",\n    "outDir": "./dist",\n    "rootDir": "./src",\n    "strict": true,\n    "esModuleInterop": true,\n    "declaration": true\n  },\n  "include": ["src/**/*"]\n}\n\n// package.json — add these fields\n{\n  "type": "module",\n  "bin": {\n    "my-deploy-mcp": "./dist/index.js"\n  },\n  "scripts": {\n    "build": "tsc",\n    "start": "node dist/index.js"\n  }\n}', language: 'json' },
        { type: 'code', content: '// Step 2: src/index.ts — Full MCP server implementation\nimport { McpServer } from \'@modelcontextprotocol/sdk/server/mcp.js\';\nimport { StdioServerTransport } from \'@modelcontextprotocol/sdk/server/stdio.js\';\nimport { z } from \'zod\';\n\n// Create the server\nconst server = new McpServer({\n  name: \'deploy-server\',\n  version: \'1.0.0\',\n  description: \'Manage internal service deployments\'\n});\n\n// --- TOOLS ---\n\n// Tool 1: Deploy a service\nserver.tool(\n  \'deploy_service\',\n  \'Deploy a service to the specified environment\',\n  {\n    service: z.string().describe(\'Service name, e.g. "auth-api"\'),\n    environment: z.enum([\'staging\', \'production\']).describe(\'Target environment\'),\n    version: z.string().describe(\'Git tag or commit SHA to deploy\'),\n    dry_run: z.boolean().default(false).describe(\'If true, validate without deploying\')\n  },\n  async ({ service, environment, version, dry_run }) => {\n    // Input validation (defense in depth)\n    if (environment === \'production\' && !version.match(/^v\\d+\\.\\d+\\.\\d+$/)) {\n      return {\n        content: [{\n          type: \'text\',\n          text: `ERROR: Production deploys require semver tags (e.g. v1.2.3). Got: ${version}`\n        }]\n      };\n    }\n\n    if (dry_run) {\n      return {\n        content: [{\n          type: \'text\',\n          text: `DRY RUN: Would deploy ${service}@${version} to ${environment}. Validation passed.`\n        }]\n      };\n    }\n\n    // Call your actual deployment API\n    const result = await triggerDeploy(service, environment, version);\n\n    return {\n      content: [{\n        type: \'text\',\n        text: `Deployment initiated:\\n- Service: ${service}\\n- Version: ${version}\\n- Environment: ${environment}\\n- Deploy ID: ${result.deployId}\\n- Status: ${result.status}\\n- ETA: ${result.estimatedMinutes} minutes`\n      }]\n    };\n  }\n);\n\n// Tool 2: Rollback a service\nserver.tool(\n  \'rollback_service\',\n  \'Rollback a service to its previous version\',\n  {\n    service: z.string().describe(\'Service name\'),\n    environment: z.enum([\'staging\', \'production\']).describe(\'Target environment\'),\n    reason: z.string().describe(\'Why are you rolling back? (logged for audit)\')\n  },\n  async ({ service, environment, reason }) => {\n    const result = await triggerRollback(service, environment, reason);\n    return {\n      content: [{\n        type: \'text\',\n        text: `Rollback initiated:\\n- Service: ${service}\\n- Environment: ${environment}\\n- Rolling back to: ${result.previousVersion}\\n- Reason: ${reason}\\n- Deploy ID: ${result.deployId}`\n      }]\n    };\n  }\n);\n\n// Tool 3: Get deployment status\nserver.tool(\n  \'get_deploy_status\',\n  \'Check the status of a deployment\',\n  {\n    deploy_id: z.string().describe(\'The deployment ID to check\')\n  },\n  async ({ deploy_id }) => {\n    const status = await getDeployStatus(deploy_id);\n    return {\n      content: [{\n        type: \'text\',\n        text: JSON.stringify(status, null, 2)\n      }]\n    };\n  }\n);\n\n// --- RESOURCES ---\n\n// Resource: List all services\nserver.resource(\n  \'services-list\',\n  \'deploy://services\',\n  { description: \'List of all deployable services and their current versions\' },\n  async () => ({\n    contents: [{\n      uri: \'deploy://services\',\n      mimeType: \'application/json\',\n      text: JSON.stringify(await getServicesList(), null, 2)\n    }]\n  })\n);\n\n// Resource template: Deployment history for a specific service\nserver.resource(\n  \'service-history\',\n  \'deploy://service/{name}/history\',\n  { description: \'Deployment history for a specific service\' },\n  async (uri, { name }) => ({\n    contents: [{\n      uri: uri.href,\n      mimeType: \'application/json\',\n      text: JSON.stringify(await getDeployHistory(name), null, 2)\n    }]\n  })\n);\n\n// --- START SERVER ---\nasync function main() {\n  const transport = new StdioServerTransport();\n  await server.connect(transport);\n  console.error(\'Deploy MCP server running on stdio\');\n}\n\nmain().catch(console.error);', language: 'typescript' },
        { type: 'text', content: '## Anatomy of a Tool Definition\n\nLet\'s break down what makes a good tool definition, because this is where most MCP server quality is determined.\n\n### The Three Parts\n\n1. **Name** -- Short, verb-first, snake_case. The model uses this to decide WHICH tool to call. Bad: `serviceDeployment`. Good: `deploy_service`.\n\n2. **Description** -- A clear sentence explaining what the tool does. This is injected into the LLM\'s context. The model reads this to decide WHEN to call the tool. Be specific: not "manages deployments" but "Deploy a service to the specified environment."\n\n3. **Schema** -- Zod schemas define the inputs. Each field has a `.describe()` that tells the model WHAT to pass. The model generates JSON matching this schema.\n\n### Schema Design Principles\n\n- **Use enums for constrained choices**: `z.enum([\'staging\', \'production\'])` prevents the model from inventing environments.\n- **Add defaults for optional params**: `z.boolean().default(false)` means the model doesn\'t have to specify every field.\n- **Describe every field**: The `.describe()` string is the model\'s documentation. Treat it like you\'re explaining the param to a new team member.\n- **Validate beyond the schema**: Your handler should still validate inputs. The schema prevents malformed JSON, but you should enforce business rules (like "production requires semver tags").\n\n### The Handler Return Format\n\nEvery tool handler returns `{ content: [{ type: \'text\', text: \'...\' }] }`. Keep responses concise and structured. The model will read this output and decide what to do next, so make it easy to parse. Include IDs, statuses, and next steps.' },
        { type: 'text', content: '## Testing and Security\n\n### Testing Locally\n\nThe MCP Inspector is your best friend during development. It lets you connect to your server and call tools interactively without needing Claude Desktop.\n\n```bash\nnpx @modelcontextprotocol/inspector node dist/index.js\n```\n\nThis opens a browser UI where you can:\n- See all discovered tools and resources\n- Call tools with custom inputs\n- View raw JSON-RPC messages\n- Debug schema validation errors\n\n### Connecting to Claude Desktop\n\nAdd your server to `claude_desktop_config.json`:\n\n```json\n{\n  "mcpServers": {\n    "deploy": {\n      "command": "node",\n      "args": ["/path/to/my-deploy-mcp/dist/index.js"],\n      "env": {\n        "DEPLOY_API_URL": "https://deploy.internal.company.com",\n        "DEPLOY_API_TOKEN": "your-token"\n      }\n    }\n  }\n}\n```\n\nRestart Claude Desktop. You should see a hammer icon indicating tools are loaded. Ask Claude "What tools do you have for deployments?" to verify.\n\n### Security Guards\n\nEvery MCP server that can modify state needs safety rails:\n\n1. **Dry-run by default** -- Add a `dry_run` parameter to destructive tools. Consider making it default to `true`.\n2. **Input validation** -- Validate beyond the schema. Check that services exist, environments are valid, users have permissions.\n3. **Audit logging** -- Log every tool invocation with who called it, what inputs were provided, and what happened.\n4. **Rate limiting** -- Prevent runaway agents from deploying 100 times in a loop.\n5. **Confirmation for danger** -- For production deploys or rollbacks, return a confirmation prompt instead of acting immediately.\n6. **Secret hygiene** -- Never include API tokens, passwords, or connection strings in tool outputs. The model sees everything you return.' },
        { type: 'tip', content: 'Write tool descriptions as if you are explaining the tool to a senior engineer who has never seen your codebase. The LLM is that engineer. "Deploy a service to the specified environment" is better than "deploy" because it tells the model exactly what to expect. Poor descriptions are the #1 cause of models calling the wrong tool.' },
        { type: 'warning', content: 'Never trust tool inputs from the model without validation. LLMs can hallucinate parameter values -- they might invent service names that do not exist or pass "staging" when the user said "production." Always validate against your actual system state inside the handler.' }
      ],
      quiz: [
        { id: 'build-mcp-q1', question: 'Why do we use Zod schemas with .describe() for tool parameters?', options: ['Zod is faster than JSON Schema', 'The .describe() text is injected into the LLM context so the model knows what to pass for each parameter', 'Zod is required by the MCP specification', 'It makes the code shorter'], correctIndex: 1, explanation: 'Zod schemas define the shape of inputs, and .describe() strings become documentation that the LLM reads to understand what values to provide. Without good descriptions, the model guesses -- and often guesses wrong.' },
        { id: 'build-mcp-q2', question: 'What is the purpose of a dry_run parameter on destructive tools?', options: ['To make the tool faster', 'To allow validation and preview without actually changing state', 'It is required by the MCP protocol', 'To save API costs'], correctIndex: 1, explanation: 'A dry_run parameter lets the model (or user) verify that inputs are valid and preview what would happen before committing to a destructive action. This is a critical safety rail for production systems.' },
        { id: 'build-mcp-q3', question: 'What does the MCP Inspector help you do during development?', options: ['Deploy your MCP server to production', 'Interactively call tools, view schemas, and debug JSON-RPC messages without needing a full host', 'Generate TypeScript types from your tools', 'Monitor server performance in production'], correctIndex: 1, explanation: 'The MCP Inspector is a browser-based development tool that connects to your server and lets you explore tools, call them with custom inputs, and see raw protocol messages. It is essential for local development and debugging.' }
      ]
    },
    {
      id: 'mcp-composition',
      moduleId: 'mcp-deep-dive',
      title: 'Composing MCP Servers for Full Automation',
      description: 'Combine multiple MCP servers to give agents access to entire workflows',
      order: 3,
      content: [
        { type: 'text', content: '## The Composition Superpower\n\nA single MCP server is useful. Multiple MCP servers connected to the same host are **transformative**.\n\nWhen you configure Claude with access to Jira, Grafana, Git, and your database simultaneously, something remarkable happens: Claude sees ALL tools from ALL servers in a single context. It can read a Jira ticket, check Grafana dashboards, search the codebase, and query the database -- all in one conversation, all without you switching tools.\n\nThis is not just convenience. It enables **cross-system workflows** that were previously impossible to automate:\n\n- Read a Jira bug report, find the relevant code, check error logs in Grafana, write a fix, run tests, and update the ticket -- all in one agent loop.\n- An alert fires in Grafana, the agent checks the dashboard, queries the database for anomalies, finds the recent deploy that caused it, rolls back, and creates a post-mortem Jira ticket.\n- A developer asks "what changed since last deploy?" and the agent correlates Git commits, Jira tickets, and deployment logs.\n\n### Why Composition Works\n\nEach MCP server is independently simple. The composition happens at the **host level**: the host collects all tools from all servers and presents them to the model in one unified tool list. The model does not know or care which server provides which tool. It just picks the best tool for the current step.\n\nThis is identical to how a human engineer works: you have Jira open in one tab, Grafana in another, your terminal in a third. You switch between them fluidly based on what you need. MCP composition gives agents that same fluid multi-tool capability.' },
        { type: 'text', content: '## Real-World Workflow: Incident Response\n\nLet\'s trace a concrete example: an automated incident response workflow using four MCP servers.\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="font-weight:700;font-size:1rem;color:#333;margin-bottom:0.3rem;">Incident Response — 4 MCP Servers Composed</div>\n<div style="display:grid;grid-template-columns:1fr 1fr;gap:0.5rem;">\n<div style="padding:0.6rem 0.8rem;border-radius:6px;border:2px solid #e17055;background:rgba(225,112,85,0.07);font-size:0.85rem;">\n<div style="font-weight:700;color:#e17055;">Grafana MCP</div>\n<div style="color:#555;">query_metrics, get_dashboard, list_alerts, get_logs</div>\n</div>\n<div style="padding:0.6rem 0.8rem;border-radius:6px;border:2px solid #0984e3;background:rgba(9,132,227,0.07);font-size:0.85rem;">\n<div style="font-weight:700;color:#0984e3;">Jira MCP</div>\n<div style="color:#555;">create_issue, update_issue, search_issues, add_comment</div>\n</div>\n<div style="padding:0.6rem 0.8rem;border-radius:6px;border:2px solid #00b894;background:rgba(0,184,148,0.07);font-size:0.85rem;">\n<div style="font-weight:700;color:#00b894;">Git MCP</div>\n<div style="color:#555;">search_code, read_file, get_commits, get_diff</div>\n</div>\n<div style="padding:0.6rem 0.8rem;border-radius:6px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.07);font-size:0.85rem;">\n<div style="font-weight:700;color:#6c5ce7;">Deploy MCP</div>\n<div style="color:#555;">deploy_service, rollback_service, get_deploy_status</div>\n</div>\n</div>\n<div style="text-align:center;font-size:0.9rem;color:#888;padding:0.3rem 0;">All tools visible to Claude in a single context</div>\n<div style="padding:0.8rem 1rem;border-radius:8px;border:2px solid #00cec9;background:rgba(0,206,201,0.06);">\n<div style="font-weight:700;color:#00cec9;font-size:0.95rem;">Claude\'s TAOR Loop</div>\n<div style="font-size:0.85rem;color:#555;line-height:1.6;margin-top:0.3rem;">\n1. THINK: Alert says auth-api latency spike. Check metrics first.<br/>\n2. ACT: <code>query_metrics</code> (Grafana) -- p99 latency jumped from 50ms to 2s<br/>\n3. ACT: <code>get_logs</code> (Grafana) -- NullPointerException in AuthService.java<br/>\n4. ACT: <code>get_commits</code> (Git) -- last deploy was 20 min ago, commit abc123<br/>\n5. ACT: <code>get_diff</code> (Git) -- commit changed null handling in AuthService<br/>\n6. THINK: Recent commit likely caused the regression. Rollback.<br/>\n7. ACT: <code>rollback_service</code> (Deploy) -- rolling back auth-api<br/>\n8. ACT: <code>query_metrics</code> (Grafana) -- latency back to 50ms<br/>\n9. ACT: <code>create_issue</code> (Jira) -- post-mortem ticket with full timeline\n</div>\n</div>\n</div>\n\nNotice how Claude fluidly switches between servers. It never needed to be told "now use Grafana" or "now use Git." It picked the right tool for each step based on what it needed to accomplish.' },
        { type: 'code', content: '// Configuration: Multiple MCP servers in Claude Desktop\n// File: claude_desktop_config.json\n{\n  "mcpServers": {\n    "grafana": {\n      "command": "npx",\n      "args": ["-y", "@modelcontextprotocol/server-grafana"],\n      "env": {\n        "GRAFANA_URL": "https://grafana.company.com",\n        "GRAFANA_TOKEN": "${GRAFANA_TOKEN}"\n      }\n    },\n    "jira": {\n      "command": "npx",\n      "args": ["-y", "@modelcontextprotocol/server-atlassian"],\n      "env": {\n        "JIRA_URL": "https://company.atlassian.net",\n        "JIRA_TOKEN": "${JIRA_TOKEN}"\n      }\n    },\n    "github": {\n      "command": "npx",\n      "args": ["-y", "@modelcontextprotocol/server-github"],\n      "env": {\n        "GITHUB_TOKEN": "${GITHUB_TOKEN}"\n      }\n    },\n    "deploy": {\n      "command": "node",\n      "args": ["./mcp-servers/deploy-server/dist/index.js"],\n      "env": {\n        "DEPLOY_API_URL": "https://deploy.internal.company.com",\n        "DEPLOY_API_TOKEN": "${DEPLOY_TOKEN}"\n      }\n    }\n  }\n}\n\n// Claude Code equivalent: .mcp.json in your project root\n{\n  "mcpServers": {\n    "grafana": {\n      "command": "npx",\n      "args": ["-y", "@modelcontextprotocol/server-grafana"],\n      "env": {\n        "GRAFANA_URL": "https://grafana.company.com",\n        "GRAFANA_TOKEN": "${GRAFANA_TOKEN}"\n      }\n    },\n    "deploy": {\n      "command": "node",\n      "args": ["./mcp-servers/deploy-server/dist/index.js"]\n    }\n  }\n}', language: 'json' },
        { type: 'text', content: '## How Claude Decides Which Tool to Use\n\nWhen Claude has access to 20+ tools from 4 servers, how does it decide which one to call? Understanding this decision process helps you write better tool descriptions and diagnose composition problems.\n\n### The Decision Process\n\n1. **Goal analysis** -- Claude identifies what it needs to accomplish in this step of the TAOR loop.\n2. **Tool scanning** -- It reads through all available tool names and descriptions.\n3. **Best-match selection** -- It picks the tool whose description most closely matches the current need.\n4. **Parameter filling** -- It generates the input JSON based on the schema and `.describe()` strings.\n\n### When Composition Goes Wrong\n\nComposition fails when tool descriptions overlap or are ambiguous:\n\n| Problem | Symptom | Fix |\n|---------|---------|-----|\n| **Overlapping names** | Two tools named `search` from different servers | Prefix with domain: `jira_search`, `git_search` |\n| **Vague descriptions** | Model picks wrong tool | Make descriptions specific: "Search Jira issues by JQL" not "Search" |\n| **Missing tools** | Model tries to do something it cannot | Add the tool or guide it in the system prompt |\n| **Too many tools** | Model gets confused or picks randomly | Reduce to essential tools; remove rarely-used ones |\n\n### Best Practices for Composition\n\n- **Keep servers focused**: One server per domain (Jira, Git, Deploy). Do not build a single mega-server.\n- **Use unique tool names**: Prefix with domain if there is any ambiguity.\n- **Limit total tools**: 15-25 total tools is a sweet spot. Beyond 40, model performance degrades.\n- **Write system prompts that guide**: Tell Claude the workflow: "When investigating incidents, start with Grafana metrics, then check recent Git commits, then decide on rollback."\n- **Test the composition**: Ask Claude to list its tools and explain what each one does. If it gets confused, your descriptions need work.' },
        { type: 'agent-demo', content: 'mcp-composition-demo' },
        { type: 'tip', content: 'The quickest way to test MCP composition: ask Claude "What tools do you have available? Group them by domain and explain when you would use each one." If Claude misunderstands any tool, that tool\'s description needs improvement.' },
        { type: 'warning', content: 'More servers does not always mean better. Each server adds startup time, memory overhead, and tools to the model\'s context window. If an agent only needs Git tools for a specific task, do not load Jira, Grafana, and Deploy servers too. Match the server composition to the workflow.' }
      ],
      quiz: [
        { id: 'mcp-comp-q1', question: 'Why is MCP composition more powerful than individual server connections?', options: ['It is faster', 'The model sees all tools from all servers in a single context, enabling cross-system workflows', 'It uses less memory', 'It requires fewer API tokens'], correctIndex: 1, explanation: 'Composition means the model can fluidly use tools from any connected server in a single TAOR loop. This enables workflows that span Jira, Grafana, Git, and deployment systems without any manual switching.' },
        { id: 'mcp-comp-q2', question: 'What is the recommended total number of tools for composed MCP servers?', options: ['As many as possible for maximum flexibility', '5 or fewer', '15-25 tools is the sweet spot', 'Exactly 10'], correctIndex: 2, explanation: 'Between 15-25 tools gives the model enough capability without overwhelming it. Beyond about 40 tools, models start to get confused, pick wrong tools, or ignore available tools entirely.' },
        { id: 'mcp-comp-q3', question: 'Two MCP servers both expose a tool called "search." What should you do?', options: ['Remove one server', 'Rename them to be domain-specific, like "jira_search" and "git_search"', 'Hope the model figures it out from context', 'Add a configuration flag to disable one'], correctIndex: 1, explanation: 'Ambiguous tool names cause the model to pick the wrong one. Prefix tool names with their domain to make each one unique and unambiguous in the combined tool list.' }
      ]
    },
    {
      id: 'project-ai-config',
      moduleId: 'mcp-deep-dive',
      title: 'Project Configuration Files for AI Tools',
      description: 'Use CLAUDE.md, .cursorrules, and copilot-instructions to orchestrate AI behavior per project',
      order: 4,
      content: [
        { type: 'text', content: '## Why Project Configuration Matters\n\nEvery AI coding tool -- Claude Code, GitHub Copilot, Cursor -- reads project-level configuration files that shape how it behaves in your codebase. These files are the most underused lever your team has.\n\nWithout configuration, every AI interaction starts from zero. The model does not know your coding standards, your architecture patterns, your deployment process, or your testing requirements. It generates generic code that might work but does not fit your project.\n\nWith configuration, the AI starts every interaction already knowing:\n- Your project structure and architecture decisions\n- Your coding conventions and style rules\n- Which files and patterns to avoid\n- How to run tests and what frameworks you use\n- Security constraints and forbidden patterns\n- Your team\'s preferred approaches to common problems\n\n### The ROI of Good Configuration\n\nTeams that invest 30 minutes writing a good `CLAUDE.md` report:\n- 60-80% fewer "that\'s not how we do it" corrections\n- Consistent output across team members (the AI follows the same rules for everyone)\n- Faster onboarding: new developers ask the AI questions and get answers that match your team\'s patterns\n- Reduced review cycles: generated code already follows your standards\n\nThis is not optional for production teams. It is the difference between an AI that helps and an AI that creates cleanup work.' },
        { type: 'text', content: '## The Configuration Landscape\n\nDifferent AI tools read different files, but the principles are identical. Here is a comparison:\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:600px;">\n<table style="width:100%;border-collapse:collapse;font-size:0.85rem;">\n<tr style="background:#f5f5f5;"><th style="padding:0.5rem;border:1px solid #ddd;text-align:left;">Tool</th><th style="padding:0.5rem;border:1px solid #ddd;text-align:left;">Config File</th><th style="padding:0.5rem;border:1px solid #ddd;text-align:left;">Scope</th><th style="padding:0.5rem;border:1px solid #ddd;text-align:left;">Format</th></tr>\n<tr><td style="padding:0.5rem;border:1px solid #ddd;font-weight:600;color:#0984e3;">Claude Code</td><td style="padding:0.5rem;border:1px solid #ddd;"><code>CLAUDE.md</code></td><td style="padding:0.5rem;border:1px solid #ddd;">Per directory (hierarchical)</td><td style="padding:0.5rem;border:1px solid #ddd;">Markdown (free-form)</td></tr>\n<tr style="background:#fafafa;"><td style="padding:0.5rem;border:1px solid #ddd;font-weight:600;color:#00b894;">Cursor</td><td style="padding:0.5rem;border:1px solid #ddd;"><code>.cursorrules</code></td><td style="padding:0.5rem;border:1px solid #ddd;">Project root</td><td style="padding:0.5rem;border:1px solid #ddd;">Plain text / Markdown</td></tr>\n<tr><td style="padding:0.5rem;border:1px solid #ddd;font-weight:600;color:#6c5ce7;">GitHub Copilot</td><td style="padding:0.5rem;border:1px solid #ddd;"><code>.github/copilot-instructions.md</code></td><td style="padding:0.5rem;border:1px solid #ddd;">Repository</td><td style="padding:0.5rem;border:1px solid #ddd;">Markdown</td></tr>\n<tr style="background:#fafafa;"><td style="padding:0.5rem;border:1px solid #ddd;font-weight:600;color:#e17055;">Windsurf</td><td style="padding:0.5rem;border:1px solid #ddd;"><code>.windsurfrules</code></td><td style="padding:0.5rem;border:1px solid #ddd;">Project root</td><td style="padding:0.5rem;border:1px solid #ddd;">Markdown</td></tr>\n</table>\n</div>\n\n### CLAUDE.md: The Most Powerful Option\n\n`CLAUDE.md` is unique because it supports **hierarchical scoping**. You can place a `CLAUDE.md` at every level of your project, and they stack:\n\n- `~/CLAUDE.md` -- Global preferences (applies to all projects)\n- `/project/CLAUDE.md` -- Project-level rules\n- `/project/src/CLAUDE.md` -- Source-specific guidance\n- `/project/src/api/CLAUDE.md` -- API-layer-specific rules\n\nWhen Claude Code works in `/project/src/api/`, it reads ALL four files, with more specific ones taking priority. This lets you set global standards at the root and override per-subsystem.' },
        { type: 'code', content: '# CLAUDE.md — Example for a production TypeScript project\n\n## Project Overview\nThis is the **auth-service**, a Node.js/TypeScript microservice handling\nauthentication and authorization for our platform. It uses Express,\nPrisma ORM, PostgreSQL, and Redis for session caching.\n\n## Architecture\n- `src/routes/` — Express route handlers (thin — delegate to services)\n- `src/services/` — Business logic (testable, no HTTP concerns)\n- `src/repositories/` — Data access via Prisma (no business logic)\n- `src/middleware/` — Auth, validation, error handling, rate limiting\n- `src/types/` — Shared TypeScript interfaces and Zod schemas\n- `tests/` — Jest tests mirroring src/ structure\n\n## Coding Standards\n- TypeScript strict mode — no `any` types, no `as` casts unless commented\n- Zod for ALL external input validation (request bodies, query params, env vars)\n- Errors: throw typed AppError classes, never raw strings\n- Logging: use `logger.info/warn/error` from `src/lib/logger.ts`, never console.log\n- Async: always use async/await, never raw Promises or callbacks\n\n## Testing\n- Run tests: `npm test`\n- Run single file: `npm test -- --testPathPattern=auth.service`\n- Coverage threshold: 80% lines, 70% branches\n- Test files: `tests/unit/` and `tests/integration/`\n- Integration tests need: `docker compose up -d postgres redis`\n\n## Common Patterns\n- Route → validate with Zod → call service → return response\n- Service → call repository → apply business rules → return result\n- Repository → Prisma query → return typed data\n- NEVER put business logic in routes or repositories\n\n## Forbidden Patterns\n- Do NOT use `eval()` or `new Function()`\n- Do NOT store secrets in code — use environment variables\n- Do NOT use `SELECT *` — always specify columns\n- Do NOT disable TypeScript strict checks\n- Do NOT import from `src/` using relative paths — use `@/` alias\n\n## Git Conventions\n- Branch: `feature/PROJ-123-short-description`\n- Commit: `feat(auth): add OAuth2 PKCE flow` (conventional commits)\n- Always run `npm test` before committing', language: 'markdown' },
        { type: 'text', content: '## Hierarchical Scoping in Practice\n\nHere is how a real project uses hierarchical CLAUDE.md files:\n\n<div style="font-family:monospace;font-size:0.85rem;line-height:1.8;margin:1.5rem 0;padding:1rem;background:#1e1e1e;color:#d4d4d4;border-radius:8px;max-width:520px;">\n<div><span style="color:#6c5ce7;">~/</span>CLAUDE.md <span style="color:#888;">-- "Use TypeScript, prefer async/await"</span></div>\n<div><span style="color:#0984e3;">project/</span>CLAUDE.md <span style="color:#888;">-- "This is auth-service, uses Prisma+Express"</span></div>\n<div>&nbsp;&nbsp;<span style="color:#00cec9;">src/</span></div>\n<div>&nbsp;&nbsp;&nbsp;&nbsp;<span style="color:#00b894;">routes/</span>CLAUDE.md <span style="color:#888;">-- "Thin handlers, validate with Zod, delegate to services"</span></div>\n<div>&nbsp;&nbsp;&nbsp;&nbsp;<span style="color:#e17055;">services/</span>CLAUDE.md <span style="color:#888;">-- "Pure business logic, no HTTP, return typed results"</span></div>\n<div>&nbsp;&nbsp;&nbsp;&nbsp;<span style="color:#fdcb6e;">repositories/</span>CLAUDE.md <span style="color:#888;">-- "Prisma only, specify columns, no business logic"</span></div>\n<div>&nbsp;&nbsp;<span style="color:#fd79a8;">tests/</span>CLAUDE.md <span style="color:#888;">-- "Use Jest, mock repositories in unit tests"</span></div>\n</div>\n\nWhen Claude edits a file in `src/routes/`, it reads the global, project, and routes-level instructions. When it edits a repository file, it gets the repository-specific rules instead. This means each subsystem gets AI guidance tailored to its role.\n\n### What to Include vs Exclude\n\n**Include:**\n- Project architecture and directory layout\n- Coding conventions and naming patterns\n- How to run tests and build commands\n- Common patterns with examples\n- Forbidden patterns (what NOT to do)\n- Security constraints and compliance requirements\n\n**Exclude:**\n- Secrets, tokens, API keys (never in config files)\n- Personal preferences that vary per developer\n- Information that changes daily (use resources/tools for dynamic data)\n- Long code examples (link to files instead)\n\n### Guardrails: Protecting Production\n\nConfiguration files can enforce safety:\n\n```\n## Guardrails\n- NEVER modify files in `src/migrations/` — migrations are generated by Prisma\n- NEVER push directly to main — always create a PR\n- Before ANY production change, run the full test suite\n- Do NOT modify .env files — ask the developer about environment changes\n- When adding a dependency, check: license, bundle size, maintenance status\n```\n\nThese guardrails are read by the AI on every interaction. They act as persistent safety constraints that do not depend on the user remembering to mention them.' },
        { type: 'tip', content: 'Start your CLAUDE.md with a 2-3 sentence project overview. This gives the AI immediate context about what the project IS before diving into rules. Think of it like briefing a new contractor: "This is an auth service using Express and Prisma. It handles login, OAuth, and session management for our platform."' },
        { type: 'warning', content: 'Configuration files are committed to your repository. NEVER put secrets, API keys, or sensitive business logic in CLAUDE.md or .cursorrules. These files should contain public-knowledge project standards, not proprietary algorithms or credentials. Use environment variables and MCP server configuration for secrets.' }
      ],
      quiz: [
        { id: 'config-q1', question: 'Why does hierarchical CLAUDE.md scoping matter?', options: ['It makes files smaller', 'Different parts of the codebase have different rules, and hierarchical scoping applies the right rules for each subsystem', 'It is required by Claude Code', 'It improves performance'], correctIndex: 1, explanation: 'Routes, services, and repositories have different conventions. Hierarchical CLAUDE.md lets you set project-wide rules at the root and layer on subsystem-specific guidance at each directory level, so the AI always gets the right context for where it is working.' },
        { id: 'config-q2', question: 'What is the most common mistake with AI project configuration files?', options: ['Making them too long', 'Not writing them at all — using AI without any project context', 'Using Markdown format', 'Putting them in the wrong directory'], correctIndex: 1, explanation: 'The biggest mistake is having no configuration at all. Without a CLAUDE.md or equivalent, the AI generates generic code that does not match your project conventions, creating more review work than it saves.' },
        { id: 'config-q3', question: 'What should you NEVER put in a CLAUDE.md file?', options: ['Coding conventions', 'API keys, secrets, or tokens', 'Architecture descriptions', 'Test commands'], correctIndex: 1, explanation: 'CLAUDE.md is committed to your repository and visible to anyone with access. Secrets, API keys, and tokens must go in environment variables or secure configuration, never in project files.' }
      ]
    }
        ]
      },
      {
        id: 'rag',
        title: 'RAG & Knowledge Systems',
        description: 'Build retrieval-augmented generation pipelines for grounded AI responses',
        icon: '📚',
        color: '#27ae60',
        order: 11,
        lessons: [
{
      id: 'rag-fundamentals',
      moduleId: 'rag',
      title: 'RAG Fundamentals',
      description: 'Why models need external knowledge, and how the Index-Query-Retrieve-Generate pipeline works',
      order: 1,
      content: [
        { type: 'text', content: '## Why RAG Exists: The Knowledge Gap Problem\n\nLarge language models are trained on a snapshot of the internet. The moment training ends, the model\'s knowledge freezes. Claude does not know about your company\'s internal API, yesterday\'s incident report, or the code you committed this morning. This is the **knowledge cutoff problem**, and it is only half the story.\n\nThe other half is the **context window limit**. Even models with 200K token windows cannot hold your entire codebase, documentation, and conversation history simultaneously. You need a way to find the *right* information and inject *only* that into the prompt.\n\n**Retrieval-Augmented Generation (RAG)** solves both problems with a simple insight: instead of stuffing everything into the model\'s training data or context window, **search for what you need, then generate using what you found**.\n\nThis is not a new idea -- it is how humans work. When a developer gets a bug report, they do not read the entire codebase from scratch. They search for the relevant file, read the relevant function, and then reason about the fix. RAG gives AI systems the same workflow: search first, reason second.\n\n### When RAG Beats Pure Prompting\n\n- **Private data**: Internal docs, proprietary code, customer records -- the model was never trained on these\n- **Fresh data**: Anything after the training cutoff -- recent commits, new API versions, current incidents\n- **Precision**: When you need exact quotes, specific function signatures, or verbatim policy language\n- **Auditability**: RAG can cite its sources -- "this answer came from `auth-service/login.ts` line 47"' },
        { type: 'text', content: '## The RAG Pipeline: Four Stages\n\nEvery RAG system follows the same four-stage pipeline. The stages split into two phases: **offline** (done once, ahead of time) and **online** (done per query, in real time).\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="padding:0.5rem 0.8rem;border-radius:6px;background:rgba(108,92,231,0.08);border-left:4px solid #6c5ce7;font-size:0.85rem;">\n<span style="font-weight:700;color:#6c5ce7;">OFFLINE PHASE</span> -- Run once (or on schedule) to prepare your knowledge base\n</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.04);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.95rem;">1. INDEX: Chunk &#8594; Embed &#8594; Store</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">Split documents into chunks. Convert each chunk to a vector embedding. Store embeddings in a vector database (Pinecone, Chroma, pgvector).</div>\n</div>\n<div style="text-align:center;color:#6c5ce7;font-size:1.2rem;">&#8595;</div>\n<div style="padding:0.5rem 0.8rem;border-radius:6px;background:rgba(0,206,201,0.08);border-left:4px solid #00cec9;font-size:0.85rem;">\n<span style="font-weight:700;color:#00cec9;">ONLINE PHASE</span> -- Run per query in real time\n</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.04);">\n<div style="font-weight:700;color:#0984e3;font-size:0.95rem;">2. QUERY: Embed the Question</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">Convert the user\'s question into a vector using the same embedding model. This vector represents the <em>meaning</em> of the question.</div>\n</div>\n<div style="text-align:center;color:#0984e3;font-size:1.2rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #00cec9;background:rgba(0,206,201,0.04);">\n<div style="font-weight:700;color:#00cec9;font-size:0.95rem;">3. RETRIEVE: Similarity Search</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">Find the K chunks whose embeddings are most similar to the question embedding. These are your <strong>relevant context</strong>.</div>\n</div>\n<div style="text-align:center;color:#00cec9;font-size:1.2rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #27ae60;background:rgba(39,174,96,0.04);">\n<div style="font-weight:700;color:#27ae60;font-size:0.95rem;">4. GENERATE: LLM + Retrieved Context</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">Send the original question + retrieved chunks to the LLM. The model generates an answer <em>grounded in the retrieved context</em>, not just its training data.</div>\n</div>\n</div>\n\nThis pipeline is deceptively simple. The complexity -- and where most teams struggle -- is in the **details**: how you chunk, which embedding model you use, how many results you retrieve, and how you format the context for the LLM.' },
        { type: 'code', content: '// Complete RAG pipeline with LangChain + Claude\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { OpenAIEmbeddings } from \'@langchain/openai\';\nimport { MemoryVectorStore } from \'langchain/vectorstores/memory\';\nimport { RecursiveCharacterTextSplitter } from \'langchain/text_splitter\';\nimport { ChatPromptTemplate } from \'@langchain/core/prompts\';\nimport { StringOutputParser } from \'@langchain/core/output_parsers\';\nimport { createStuffDocumentsChain } from \'langchain/chains/combine_documents\';\nimport { Document } from \'@langchain/core/documents\';\n\n// ========== OFFLINE PHASE: Index ==========\n\n// Step 1a: Load your documents (here we use raw strings)\nconst rawDocuments = [\n  new Document({\n    pageContent: `The AuthService handles user authentication via JWT tokens.\n      The login() method validates credentials against the database,\n      generates a JWT with a 24-hour expiry, and sets an httpOnly cookie.\n      Rate limiting is applied: max 5 attempts per IP per minute.`,\n    metadata: { source: \'auth-service/README.md\', type: \'documentation\' },\n  }),\n  new Document({\n    pageContent: `export class AuthService {\n      async login(email: string, password: string): Promise<AuthResult> {\n        const user = await this.userRepo.findByEmail(email);\n        if (!user) throw new UnauthorizedError(\'Invalid credentials\');\n        const valid = await bcrypt.compare(password, user.passwordHash);\n        if (!valid) throw new UnauthorizedError(\'Invalid credentials\');\n        const token = this.jwtService.sign({ sub: user.id, role: user.role });\n        return { token, expiresIn: 86400 };\n      }\n    }`,\n    metadata: { source: \'auth-service/auth.service.ts\', type: \'code\' },\n  }),\n];\n\n// Step 1b: Chunk the documents\nconst splitter = new RecursiveCharacterTextSplitter({\n  chunkSize: 500,      // Characters per chunk\n  chunkOverlap: 50,    // Overlap between adjacent chunks\n});\nconst chunks = await splitter.splitDocuments(rawDocuments);\n\n// Step 1c: Embed and store in a vector database\nconst embeddings = new OpenAIEmbeddings({\n  modelName: \'text-embedding-3-small\',\n});\nconst vectorStore = await MemoryVectorStore.fromDocuments(chunks, embeddings);\n\n// ========== ONLINE PHASE: Query + Retrieve + Generate ==========\n\n// Step 2: Create a retriever (wraps similarity search)\nconst retriever = vectorStore.asRetriever({\n  k: 3,  // Return top 3 most relevant chunks\n});\n\n// Step 3: Retrieve relevant chunks for a question\nconst question = \'How does the login function handle invalid passwords?\';\nconst relevantDocs = await retriever.invoke(question);\nconsole.log(`Retrieved ${relevantDocs.length} chunks`);\n\n// Step 4: Generate answer with Claude using retrieved context\nconst model = new ChatAnthropic({\n  modelName: \'claude-sonnet-4-6-20250514\',\n  temperature: 0,\n});\n\nconst prompt = ChatPromptTemplate.fromMessages([\n  [\'system\',\n    \'Answer the question based ONLY on the following context. \' +\n    \'If the context does not contain enough information, say so. \' +\n    \'Cite the source file when possible.\\n\\n\' +\n    \'Context:\\n{context}\'\n  ],\n  [\'human\', \'{input}\'],\n]);\n\nconst chain = await createStuffDocumentsChain({\n  llm: model,\n  prompt,\n  outputParser: new StringOutputParser(),\n});\n\nconst answer = await chain.invoke({\n  input: question,\n  context: relevantDocs,\n});\n\nconsole.log(answer);\n// \"The login function in auth-service/auth.service.ts handles invalid\n//  passwords by comparing the provided password against the stored hash\n//  using bcrypt.compare(). If the comparison fails, it throws an\n//  UnauthorizedError with the message \'Invalid credentials\'...\"', language: 'typescript' },
        { type: 'text', content: '## Embeddings: The Engine Behind Retrieval\n\nEmbeddings are what make semantic search possible. An embedding model converts text into a **vector** -- a list of numbers (typically 256 to 3072 dimensions) that represents the *meaning* of that text. The key property: **similar text produces similar vectors**.\n\n"How do I authenticate a user?" and "What is the login process?" have completely different words but nearly identical embeddings because they mean the same thing. This is why vector search beats keyword search for RAG -- it matches on *meaning*, not exact words.\n\n**Cosine similarity** is the standard metric for comparing embeddings. It measures the angle between two vectors: 1.0 means identical meaning, 0.0 means unrelated, -1.0 means opposite. In practice, relevant chunks typically score 0.7-0.95.\n\n### Chunking Strategies: The Most Underrated Decision\n\nChunking is how you split documents before embedding. This decision has more impact on RAG quality than your choice of embedding model or vector database.\n\n| Strategy | How It Works | Best For | Watch Out |\n|----------|-------------|----------|-----------|\n| **Fixed-size** | Split every N characters | Simple docs, logs | Cuts mid-sentence, loses context |\n| **Recursive** | Split by paragraphs, then sentences, then words | General purpose (default choice) | May still split logical units |\n| **Semantic** | Use embeddings to detect topic boundaries | Research papers, long articles | Slower, more expensive to compute |\n| **Code-aware** | Split at function/class boundaries | Source code | Requires language-specific parsers |\n\n### RAG vs Long Context vs Hybrid\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #27ae60;background:rgba(39,174,96,0.04);">\n<div style="font-weight:700;color:#27ae60;font-size:0.9rem;">Use RAG when:</div>\n<div style="font-size:0.85rem;line-height:1.5;">Knowledge base > 200K tokens, data changes frequently, you need source citations, cost matters at scale</div>\n</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.04);">\n<div style="font-weight:700;color:#0984e3;font-size:0.9rem;">Use Long Context when:</div>\n<div style="font-size:0.85rem;line-height:1.5;">Data fits in the window (<200K tokens), you need cross-document reasoning, simplicity matters more than cost</div>\n</div>\n<div style="padding:0.6rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.04);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.9rem;">Use Hybrid (RAG + Long Context) when:</div>\n<div style="font-size:0.85rem;line-height:1.5;">Use RAG to narrow down to ~50 relevant chunks, then send all 50 in the long context window for cross-reference reasoning</div>\n</div>\n</div>' },
        { type: 'tip', content: 'The most common RAG mistake is choosing too small a chunk size. With 200-character chunks, you lose context -- a chunk might contain a function body but not the function name or its imports. Start with 500-1000 character chunks with 50-100 character overlap. Measure retrieval quality before optimizing. Overlap ensures that information split across chunk boundaries is still findable.' },
        { type: 'warning', content: 'Never assume your embedding model and LLM "speak the same language." Embeddings capture semantic similarity, but the LLM needs enough surrounding context to generate a useful answer. Retrieving a 200-character chunk that says "returns true" is useless without knowing WHAT returns true. Always include enough context in each chunk to be self-explanatory -- function signatures, class names, file paths in metadata.' },
        { type: 'text', content: '### Key Takeaways\n\n1. **RAG = Search then Generate.** Find relevant context first, then let the LLM reason over it. This solves both the knowledge cutoff and context window limits.\n2. **The pipeline has four stages**: Index (chunk, embed, store) -> Query (embed question) -> Retrieve (similarity search) -> Generate (LLM + context). The first stage is offline; the last three happen per query.\n3. **Embeddings convert meaning into numbers.** Similar text produces similar vectors. Cosine similarity measures how close two vectors are.\n4. **Chunking is the most impactful design decision.** Too small and you lose context. Too large and you dilute relevance. Start with 500-1000 chars and measure.\n5. **RAG vs Long Context is not either/or.** The hybrid approach -- RAG to narrow down, long context to reason across results -- often outperforms both individually.' }
      ],
      quiz: [
        { id: 'q1', question: 'What are the two fundamental problems that RAG solves?', options: ['Slow inference speed and high API costs', 'Knowledge cutoff (model doesn\'t know recent/private data) and context window limits (can\'t fit everything at once)', 'Model hallucination and token limits', 'Training data bias and output formatting'], correctIndex: 1, explanation: 'RAG addresses the knowledge cutoff problem (the model was never trained on your private or recent data) and the context window limit (even 200K tokens cannot hold an entire codebase). RAG searches for relevant information and injects only what is needed.' },
        { id: 'q2', question: 'In the RAG pipeline, what happens during the "Index" stage?', options: ['The user\'s question is embedded into a vector', 'Documents are chunked, each chunk is embedded into a vector, and vectors are stored in a database', 'The LLM generates an answer from retrieved context', 'Similar chunks are found via cosine similarity'], correctIndex: 1, explanation: 'The Index stage is the offline preparation phase: documents are split into chunks, each chunk is converted to a vector embedding, and those embeddings are stored in a vector database. This only needs to happen once (or on a schedule when documents change).' },
        { id: 'q3', question: 'Why does chunking strategy matter more than the choice of embedding model?', options: ['Because embedding models all produce the same vectors', 'Because chunks that are too small lose context and chunks that are too large dilute relevance, directly impacting retrieval quality', 'Because chunking is faster than embedding', 'Because the LLM cannot read embeddings'], correctIndex: 1, explanation: 'Chunking determines what the retriever CAN find. If a function body is split across two chunks without the function name, neither chunk is useful on its own. If chunks are 5000 characters, the relevant 200 characters are buried in noise. The embedding model can only work with what the chunking strategy gives it.' }
      ]
    },
    {
      id: 'rag-codebase',
      moduleId: 'rag',
      title: 'RAG for Codebase Understanding',
      description: 'Code-specific chunking, multi-level indexing, and keeping your code index fresh',
      order: 2,
      content: [
        { type: 'text', content: '## Why Code RAG Is Different from Document RAG\n\nApplying standard RAG to source code is like using a bread knife on sushi -- it technically cuts, but the results are ugly. Code has structure that plain text does not: functions, classes, imports, type definitions, and call graphs. If your chunking strategy ignores this structure, you get chunks that split a function in half, separate a function from its imports, or combine unrelated code from different classes.\n\nConsider what happens when you use a standard 500-character text splitter on a TypeScript file:\n\n```\n// Chunk 1 ends here:\n  async processPayment(order: Order): Promise<PaymentResult> {\n    const customer = await this.customerRepo.find\n\n// Chunk 2 starts here:\nById(order.customerId);\n    if (!customer.paymentMethod) {\n      throw new PaymentError(\'No payment method on file\');\n    }\n```\n\nThe retriever now has two useless chunks. Chunk 1 has the function name but not the logic. Chunk 2 has the logic but not the function name. If someone asks "how does processPayment work?", neither chunk gives a good answer.\n\n### Code RAG Requires Three Adaptations\n\n1. **Structural chunking**: Split at function, class, and module boundaries -- never mid-expression\n2. **Context preservation**: Include imports, type definitions, and class names with every chunk\n3. **Multi-level indexing**: Index at multiple granularities -- file summaries, function-level detail, and cross-references\n\nThese are not nice-to-haves. Without them, your code RAG system will consistently retrieve irrelevant or incomplete chunks, and the LLM will generate plausible-sounding but wrong answers about your codebase.' },
        { type: 'code', content: '// Code-aware chunking with RecursiveCharacterTextSplitter\nimport { RecursiveCharacterTextSplitter } from \'langchain/text_splitter\';\nimport { Document } from \'@langchain/core/documents\';\nimport * as fs from \'fs/promises\';\nimport * as path from \'path\';\n\n// TypeScript-aware splitter: splits at class/function boundaries first,\n// then falls back to smaller units only if needed\nconst codeAwareSplitter = new RecursiveCharacterTextSplitter({\n  chunkSize: 1500,       // Larger chunks for code -- functions can be long\n  chunkOverlap: 200,     // Overlap to capture context across boundaries\n  separators: [\n    \'\\nclass \',           // Split at class declarations first\n    \'\\nexport class \',\n    \'\\nexport default class \',\n    \'\\nexport function \', // Then exported functions\n    \'\\nexport async function \',\n    \'\\nfunction \',        // Then regular functions\n    \'\\nasync function \',\n    \'\\nexport const \',   // Then exported constants (often arrow fns)\n    \'\\nexport interface \',// Then type definitions\n    \'\\nexport type \',\n    \'\\n\\n\',              // Then double newlines (paragraph breaks)\n    \'\\n\',               // Then single newlines\n    \' \',                // Last resort: spaces\n  ],\n});\n\n// Enhanced: prepend imports and file path to EVERY chunk\nasync function chunkCodeFile(filePath: string): Promise<Document[]> {\n  const content = await fs.readFile(filePath, \'utf-8\');\n  const lines = content.split(\'\\n\');\n\n  // Extract import block (everything before first non-import line)\n  const importLines = lines.filter(\n    line => line.startsWith(\'import \') || line.startsWith(\'from \')\n  );\n  const importBlock = importLines.join(\'\\n\');\n\n  // Chunk the code\n  const rawChunks = await codeAwareSplitter.splitText(content);\n\n  // Prepend context to each chunk\n  return rawChunks.map((chunk, index) => new Document({\n    pageContent: [\n      `// File: ${filePath}`,\n      importBlock ? `// Imports:\\n${importBlock}` : \'\',\n      `// Chunk ${index + 1} of ${rawChunks.length}`,\n      \'\',\n      chunk,\n    ].filter(Boolean).join(\'\\n\'),\n    metadata: {\n      source: filePath,\n      chunkIndex: index,\n      totalChunks: rawChunks.length,\n      language: path.extname(filePath).slice(1),\n      hasImports: importLines.length > 0,\n    },\n  }));\n}', language: 'typescript' },
        { type: 'text', content: '## Multi-Level Indexing: The Secret to Accurate Code RAG\n\nSingle-level indexing (just chunking functions) works for small codebases but breaks down at scale. When you have 500 files and 3000 functions, the retriever has to pick the right function from thousands of embeddings. The signal-to-noise ratio is terrible.\n\nMulti-level indexing solves this by creating a **hierarchy of summaries**, like a table of contents for your codebase:\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:520px;">\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.04);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.95rem;">Level 1: Project Summary</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">"This is a payment processing microservice with auth, billing, and webhook modules. Built with NestJS + TypeScript."</div>\n</div>\n<div style="text-align:center;color:#6c5ce7;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.04);">\n<div style="font-weight:700;color:#0984e3;font-size:0.95rem;">Level 2: File Summaries</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">"auth.service.ts: Handles JWT authentication, login, logout, token refresh. Depends on UserRepository and JwtService."</div>\n</div>\n<div style="text-align:center;color:#0984e3;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #00cec9;background:rgba(0,206,201,0.04);">\n<div style="font-weight:700;color:#00cec9;font-size:0.95rem;">Level 3: Function-Level Chunks</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">The actual code, chunked at function boundaries with imports attached. This is what you saw in the previous code example.</div>\n</div>\n<div style="text-align:center;color:#00cec9;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #fdcb6e;background:rgba(253,203,110,0.04);">\n<div style="font-weight:700;color:#e17055;font-size:0.95rem;">Level 4: Cross-References</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">"AuthService.login() is called by AuthController.handleLogin() and tested in auth.service.spec.ts. It depends on UserRepository.findByEmail()."</div>\n</div>\n</div>\n\nWhen a query arrives, you can search the file-level summaries first to identify which files are relevant, then drill into function-level chunks within those files. This **two-phase retrieval** dramatically improves precision on large codebases because it narrows the search space before doing fine-grained matching.\n\nThe cross-reference level is particularly valuable for questions like "what calls this function?" or "where is this type used?" -- questions that require understanding relationships between code, not just the code itself.' },
        { type: 'code', content: '// Using Claude to generate file summaries for Level 2 indexing\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { Document } from \'@langchain/core/documents\';\nimport * as fs from \'fs/promises\';\nimport * as glob from \'glob\';\n\nconst summarizer = new ChatAnthropic({\n  modelName: \'claude-haiku-4-20250414\',  // Haiku is fast + cheap for summaries\n  temperature: 0,\n  maxTokens: 300,\n});\n\nasync function generateFileSummary(filePath: string): Promise<Document> {\n  const content = await fs.readFile(filePath, \'utf-8\');\n\n  const response = await summarizer.invoke([\n    {\n      role: \'system\',\n      content:\n        \'You are a code documentation tool. Given a source code file, \' +\n        \'produce a concise summary (2-4 sentences) covering: \' +\n        \'1) what the file does, 2) key exports/classes/functions, \' +\n        \'3) important dependencies. Be specific -- include actual names.\',\n    },\n    {\n      role: \'user\',\n      content: `File: ${filePath}\\n\\n${content.slice(0, 4000)}`,  // Truncate large files\n    },\n  ]);\n\n  return new Document({\n    pageContent: `File: ${filePath}\\nSummary: ${response.content}`,\n    metadata: {\n      source: filePath,\n      indexLevel: \'file-summary\',\n      generatedAt: new Date().toISOString(),\n    },\n  });\n}\n\n// Index an entire project with multi-level indexing\nasync function indexProject(projectRoot: string) {\n  const files = glob.sync(\'**/*.ts\', {\n    cwd: projectRoot,\n    ignore: [\'node_modules/**\', \'dist/**\', \'*.spec.ts\'],\n  });\n\n  const allDocuments: Document[] = [];\n\n  for (const file of files) {\n    const fullPath = `${projectRoot}/${file}`;\n\n    // Level 2: File summary\n    const summary = await generateFileSummary(fullPath);\n    allDocuments.push(summary);\n\n    // Level 3: Function-level chunks\n    const chunks = await chunkCodeFile(fullPath);\n    allDocuments.push(...chunks);\n  }\n\n  console.log(`Indexed ${files.length} files, ${allDocuments.length} total documents`);\n  return allDocuments;\n}\n\n// Git hook script for re-indexing on push (package.json)\n// {\n//   \"husky\": {\n//     \"hooks\": {\n//       \"pre-push\": \"npm run reindex\"\n//     }\n//   },\n//   \"scripts\": {\n//     \"reindex\": \"ts-node scripts/index-codebase.ts\"\n//   }\n// }\n\n// Incremental re-indexing: only process changed files\nasync function incrementalReindex(\n  projectRoot: string,\n  changedFiles: string[]\n) {\n  console.log(`Re-indexing ${changedFiles.length} changed files...`);\n\n  for (const file of changedFiles) {\n    // Delete old embeddings for this file\n    await vectorStore.delete({ filter: { source: file } });\n\n    // Re-index with fresh content\n    const summary = await generateFileSummary(`${projectRoot}/${file}`);\n    const chunks = await chunkCodeFile(`${projectRoot}/${file}`);\n\n    await vectorStore.addDocuments([summary, ...chunks]);\n  }\n\n  console.log(\'Incremental re-index complete.\');\n}', language: 'typescript' },
        { type: 'tip', content: 'Use Claude Haiku for generating file summaries -- it is 10-20x cheaper than Sonnet and perfectly adequate for summarization. For a 500-file codebase, summarization with Haiku costs under $1. Run it once on initial setup, then incrementally on changed files via git hooks. The summaries dramatically improve retrieval for high-level questions like "which service handles payments?" that function-level chunks alone cannot answer.' },
        { type: 'warning', content: 'The biggest code RAG failure mode is stale indexes. When you refactor a function but do not re-index, the retriever returns the OLD version of the code, and the LLM generates answers based on code that no longer exists. Set up automated re-indexing via git hooks (pre-push or post-merge) and include the `generatedAt` timestamp in metadata so you can detect and flag stale results.' },
        { type: 'text', content: '### Key Takeaways\n\n1. **Code requires structural chunking.** Never split mid-function. Use language-aware separators that respect class and function boundaries.\n2. **Always include imports and file paths with every chunk.** A function body without its imports and containing class is useless for the LLM -- it cannot determine types, dependencies, or module context.\n3. **Multi-level indexing beats flat indexing.** File summaries for broad questions, function chunks for specific questions, cross-references for relationship questions. Two-phase retrieval (files first, then functions) dramatically improves precision.\n4. **Freshness is non-negotiable.** Stale code indexes produce confidently wrong answers. Automate re-indexing with git hooks and track the `generatedAt` timestamp.\n5. **Use Haiku for summarization.** It is fast, cheap, and more than capable of generating file-level summaries. Save Sonnet and Opus for the generation step where reasoning quality matters.' }
      ],
      quiz: [
        { id: 'q1', question: 'What is the core problem with using standard text splitters on source code?', options: ['They are too slow for large codebases', 'They split mid-function, separating logic from its function name, imports, and class context', 'They cannot handle TypeScript syntax', 'They produce too many chunks'], correctIndex: 1, explanation: 'Standard text splitters split at fixed character counts regardless of code structure. This produces chunks where a function body is separated from its name, or imports are in a different chunk than the code that uses them. The retriever then returns incomplete, contextless code fragments.' },
        { id: 'q2', question: 'What is the purpose of multi-level indexing in code RAG?', options: ['To reduce storage costs', 'To create a hierarchy (project -> file summaries -> function chunks -> cross-references) that enables two-phase retrieval and handles different types of questions', 'To support multiple programming languages', 'To speed up embedding generation'], correctIndex: 1, explanation: 'Multi-level indexing creates summaries at different granularities. High-level questions ("which service handles auth?") match file summaries. Specific questions ("how does login validate passwords?") match function chunks. Relationship questions ("what calls login?") match cross-references. Two-phase retrieval narrows down files first, then searches functions within those files.' },
        { id: 'q3', question: 'Why should you automate code re-indexing with git hooks?', options: ['To reduce manual work', 'Because stale indexes cause the LLM to generate answers based on code that no longer exists, producing confidently wrong responses', 'To improve embedding quality', 'Because vector databases require periodic refreshes'], correctIndex: 1, explanation: 'When code changes but the index is not updated, the retriever returns outdated code. The LLM then generates answers that reference functions, parameters, or logic that have been refactored or deleted. Automated re-indexing via git hooks ensures the index stays current with the actual codebase.' }
      ]
    },
    {
      id: 'rag-agents',
      moduleId: 'rag',
      title: 'RAG + Agents: Autonomous Knowledge Workers',
      description: 'Self-RAG patterns where agents decide when to retrieve, applying TAOR to knowledge access',
      order: 3,
      content: [
        { type: 'text', content: '## The Problem with Forced Retrieval\n\nIn a standard RAG pipeline, retrieval happens on **every single query**, regardless of whether it is needed. Ask "what is 2+2?" and the system still embeds the question, searches the vector database, retrieves three chunks of irrelevant context, and sends them to the LLM. This wastes tokens, adds latency, and can actually **hurt** answer quality by injecting irrelevant context that confuses the model.\n\nThe insight behind Self-RAG is simple: **not every question needs retrieval**. Some questions the agent can answer from its training data. Some require searching the codebase. Some require searching documentation. Some require searching multiple sources. The agent should **decide** when and what to retrieve, just like a human developer decides when to search the codebase vs. when to answer from memory.\n\nThis is the TAOR pattern (Think, Act, Observe, Repeat) applied specifically to knowledge retrieval:\n\n<div style="display:flex;flex-direction:column;gap:0.5rem;margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:540px;">\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #6c5ce7;background:rgba(108,92,231,0.04);">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.95rem;">THINK: Do I have enough context?</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">The agent assesses whether it can answer the question from its existing knowledge and conversation history.</div>\n</div>\n<div style="display:flex;gap:1rem;align-items:flex-start;margin:0.3rem 0;">\n<div style="flex:1;text-align:center;">\n<div style="color:#27ae60;font-size:1.1rem;">&#8595; YES</div>\n<div style="padding:0.5rem 0.8rem;border-radius:8px;border:2px solid #27ae60;background:rgba(39,174,96,0.04);margin-top:0.3rem;">\n<div style="font-weight:700;color:#27ae60;font-size:0.85rem;">ACT: Answer directly</div>\n<div style="font-size:0.8rem;line-height:1.4;margin-top:0.2rem;">No retrieval needed. Respond immediately with lower latency and zero retrieval cost.</div>\n</div>\n</div>\n<div style="flex:1;text-align:center;">\n<div style="color:#e17055;font-size:1.1rem;">&#8595; NO</div>\n<div style="padding:0.5rem 0.8rem;border-radius:8px;border:2px solid #e17055;background:rgba(225,112,85,0.04);margin-top:0.3rem;">\n<div style="font-weight:700;color:#e17055;font-size:0.85rem;">ACT: Retrieve, then answer</div>\n<div style="font-size:0.8rem;line-height:1.4;margin-top:0.2rem;">Call the search tool, get relevant context, then generate a grounded answer.</div>\n</div>\n</div>\n</div>\n<div style="text-align:center;color:#0984e3;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px solid #0984e3;background:rgba(9,132,227,0.04);">\n<div style="font-weight:700;color:#0984e3;font-size:0.95rem;">OBSERVE: Was the answer sufficient?</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">If retrieval results were sparse or irrelevant, the agent can try a different search query or a different source.</div>\n</div>\n<div style="text-align:center;color:#fd79a8;font-size:1.1rem;">&#8595;</div>\n<div style="padding:0.7rem 1rem;border-radius:8px;border:2px dashed #fd79a8;background:rgba(253,121,168,0.04);">\n<div style="font-weight:700;color:#fd79a8;font-size:0.95rem;">REPEAT or RETURN</div>\n<div style="font-size:0.85rem;line-height:1.5;margin-top:0.3rem;">If more context is needed &#8594; refine the search and loop. If sufficient &#8594; return the final answer.</div>\n</div>\n</div>\n\nThe key difference from standard RAG: **retrieval is a tool the agent can choose to call**, not a mandatory step that runs on every query.' },
        { type: 'text', content: '## Self-RAG vs Standard RAG: A Direct Comparison\n\nConsider an agent that helps developers understand a codebase. Here is how standard RAG and Self-RAG handle the same queries:\n\n| Query | Standard RAG | Self-RAG |\n|-------|-------------|----------|\n| "What is a Promise in JavaScript?" | Searches codebase (irrelevant results), generates answer with noisy context | Answers from training data directly -- no search needed |\n| "How does our AuthService handle token refresh?" | Searches codebase, retrieves auth code, generates answer | Searches codebase, retrieves auth code, generates answer |\n| "What changed in AuthService in the last commit?" | Searches codebase (finds current code, not the diff), gives incomplete answer | Calls `git_diff` tool first, then searches codebase for context, then generates answer |\n| "Is our rate limiter configured correctly?" | Retrieves rate limiter code, answers based on code alone | Retrieves rate limiter code AND searches documentation for best practices, then compares |\n\nThe Self-RAG agent handles each query differently because it **reasons about what it needs** before acting. Standard RAG applies the same retrieve-then-generate pipeline regardless of the question.\n\n### The Three Types of Agent Knowledge\n\nA Self-RAG agent draws from three sources, and the decision of which to use is what makes it powerful:\n\n1. **Parametric knowledge** (training data): General programming concepts, language syntax, common patterns. Use when the question is about general knowledge, not your specific codebase.\n2. **Contextual knowledge** (conversation history): What the user said earlier, previous tool results, established context. Use when the answer is in the current session.\n3. **Retrieved knowledge** (external search): Your codebase, docs, APIs, databases. Use when the question requires specific, private, or fresh information.' },
        { type: 'code', content: '// Self-RAG Agent: search_codebase as a tool the agent chooses to call\nimport { ChatAnthropic } from \'@langchain/anthropic\';\nimport { tool } from \'@langchain/core/tools\';\nimport { z } from \'zod\';\nimport { createToolCallingAgent, AgentExecutor } from \'langchain/agents\';\nimport { ChatPromptTemplate, MessagesPlaceholder } from \'@langchain/core/prompts\';\n\n// Tool 1: Search the codebase (the agent DECIDES when to call this)\nconst searchCodebase = tool(\n  async ({ query, filePattern }) => {\n    // In production: query your vector store\n    const results = await vectorStore.similaritySearch(query, 5);\n\n    // Filter by file pattern if provided\n    const filtered = filePattern\n      ? results.filter(doc =>\n          doc.metadata.source.includes(filePattern)\n        )\n      : results;\n\n    return filtered.map(doc =>\n      `--- ${doc.metadata.source} ---\\n${doc.pageContent}`\n    ).join(\'\\n\\n\');\n  },\n  {\n    name: \'search_codebase\',\n    description:\n      \'Search the project codebase for relevant code, types, or documentation. \' +\n      \'Use this when you need to find specific implementations, understand \' +\n      \'how a feature works, or locate where something is defined. \' +\n      \'Do NOT use this for general programming questions that are not \' +\n      \'specific to this project.\',\n    schema: z.object({\n      query: z.string().describe(\n        \'Natural language description of what you are looking for, \' +\n        \'e.g. \"authentication token refresh logic\" or \"database connection setup\"\'\n      ),\n      filePattern: z.string().optional().describe(\n        \'Optional filter to narrow search to specific files/directories, \' +\n        \'e.g. \"auth-service\" or \"controller\"\'\n      ),\n    }),\n  }\n);\n\n// Tool 2: Read a specific file (for when the agent knows the exact path)\nconst readFile = tool(\n  async ({ filePath }) => {\n    try {\n      const content = await import(\'fs/promises\')\n        .then(fs => fs.readFile(filePath, \'utf-8\'));\n      return content;\n    } catch (err: any) {\n      return `Error: ${err.message}`;\n    }\n  },\n  {\n    name: \'read_file\',\n    description:\n      \'Read the full contents of a specific file by path. Use this when \' +\n      \'you already know which file to examine (from a previous search \' +\n      \'result or user mention). Prefer search_codebase when you do not \' +\n      \'know the exact file path.\',\n    schema: z.object({\n      filePath: z.string().describe(\'Absolute path to the file\'),\n    }),\n  }\n);\n\n// Tool 3: Search documentation (separate from codebase)\nconst searchDocs = tool(\n  async ({ query }) => {\n    const results = await docsVectorStore.similaritySearch(query, 3);\n    return results.map(doc =>\n      `--- ${doc.metadata.source} ---\\n${doc.pageContent}`\n    ).join(\'\\n\\n\');\n  },\n  {\n    name: \'search_documentation\',\n    description:\n      \'Search project documentation, ADRs, and runbooks. Use this for \' +\n      \'architecture decisions, deployment procedures, configuration guides, \' +\n      \'or policy questions. Do NOT use for finding code implementations.\',\n    schema: z.object({\n      query: z.string().describe(\'What documentation topic to search for\'),\n    }),\n  }\n);\n\n// The Self-RAG system prompt: guide the agent on WHEN to search\nconst selfRagPrompt = ChatPromptTemplate.fromMessages([\n  [\'system\',\n    \'You are a senior developer assistant with deep knowledge of this codebase. \' +\n    \'You have access to tools for searching code and documentation.\\n\\n\' +\n    \'IMPORTANT: Before using any search tool, ask yourself:\\n\' +\n    \'1. Can I answer this from general programming knowledge? If yes, answer directly.\\n\' +\n    \'2. Is the answer already in our conversation history? If yes, reference it.\\n\' +\n    \'3. Do I need project-specific information? Only then use search tools.\\n\\n\' +\n    \'When you DO search:\\n\' +\n    \'- Use search_codebase for implementation questions\\n\' +\n    \'- Use search_documentation for architecture/process questions\\n\' +\n    \'- Use read_file only when you know the exact path\\n\' +\n    \'- If first search results are insufficient, refine your query and try again\\n\\n\' +\n    \'Always cite the source file when using retrieved information.\'\n  ],\n  new MessagesPlaceholder(\'chat_history\'),\n  [\'human\', \'{input}\'],\n  new MessagesPlaceholder(\'agent_scratchpad\'),\n]);\n\nconst agent = createToolCallingAgent({\n  llm: new ChatAnthropic({\n    modelName: \'claude-sonnet-4-6-20250514\',\n    temperature: 0,\n  }),\n  tools: [searchCodebase, readFile, searchDocs],\n  prompt: selfRagPrompt,\n});\n\nconst executor = new AgentExecutor({\n  agent,\n  tools: [searchCodebase, readFile, searchDocs],\n  maxIterations: 8,\n  verbose: true,\n});\n\n// Example usage:\n// \"What is a Promise?\" -> Agent answers directly (no tool call)\n// \"How does our auth work?\" -> Agent calls search_codebase\n// \"What is our deployment process?\" -> Agent calls search_documentation\n// \"Show me auth.service.ts\" -> Agent calls read_file', language: 'typescript' },
        { type: 'text', content: '## Making Self-RAG Reliable: The Grounding Problem\n\nThe risk with giving the agent discretion over retrieval is that it might **skip retrieval when it should not**. Claude might confidently answer "the AuthService uses bcrypt for password hashing" from its general knowledge, but your codebase actually uses argon2. This is a **grounding failure** -- the agent used parametric knowledge when it should have retrieved.\n\nThree strategies to mitigate this:\n\n**1. Topic-based forced retrieval.** For certain topics (security, configuration, business logic), always force retrieval regardless of the agent\'s assessment. Add to the system prompt: "For ANY question about authentication, authorization, or security, ALWAYS search the codebase first, even if you think you know the answer."\n\n**2. Confidence calibration.** Instruct the agent to express its confidence level and retrieve when uncertain: "If you are less than 90% confident your answer reflects the current codebase, search before answering."\n\n**3. Post-generation verification.** After the agent generates an answer without retrieval, run a second check: search for the key claims and verify they match. This is expensive (double the searches) but catches grounding failures.\n\nIn practice, strategy #1 (topic-based forcing) gives the best cost/reliability trade-off. You maintain a list of "always search" topics and let the agent use discretion for everything else.\n\n### Common Mistake: Over-Searching\n\nThe opposite failure mode is an agent that searches on EVERY query, even "what does `Array.map` do?" This defeats the purpose of Self-RAG. The fix is in the tool descriptions: explicitly state "Do NOT use this for general programming questions." If the agent still over-searches, add negative examples to the system prompt.' },
        { type: 'tip', content: 'The system prompt is the steering wheel of Self-RAG. The three-question framework ("Can I answer from general knowledge? Is it in our conversation? Do I need project-specific info?") gives the agent a reliable decision procedure. Without it, retrieval decisions are inconsistent. Test by asking 10 general questions and 10 project-specific questions -- the agent should search for zero of the general ones and most of the specific ones.' },
        { type: 'warning', content: 'Self-RAG agents that skip retrieval can produce confidently wrong answers about your specific codebase. For security-critical code paths (authentication, authorization, encryption, payment processing), ALWAYS force retrieval in the system prompt. A wrong answer about how your auth works is worse than the latency cost of an unnecessary search.' },
        { type: 'text', content: '### Key Takeaways\n\n1. **Self-RAG makes retrieval a choice, not a mandate.** The agent decides when to search based on whether it needs project-specific information, saving tokens and latency on questions it can answer from training data.\n2. **This IS TAOR applied to knowledge retrieval.** Think (do I have enough context?) -> Act (answer directly or search) -> Observe (was the result sufficient?) -> Repeat (refine search if needed).\n3. **Three knowledge sources**: Parametric (training data) for general knowledge, contextual (conversation history) for session state, and retrieved (search tools) for project-specific information. The agent must learn to pick the right one.\n4. **Guard against grounding failures.** For sensitive topics (security, config, business logic), force retrieval regardless of the agent\'s confidence. The cost of an unnecessary search is far less than the cost of a wrong answer.\n5. **Tool descriptions control retrieval behavior.** Explicitly state when to use AND when NOT to use each search tool. "Do NOT use for general programming questions" prevents over-searching.' }
      ],
      quiz: [
        { id: 'q1', question: 'What is the key difference between standard RAG and Self-RAG?', options: ['Self-RAG uses better embeddings', 'Self-RAG lets the agent decide WHEN to retrieve instead of retrieving on every query', 'Self-RAG uses multiple vector databases', 'Self-RAG does not use an LLM for generation'], correctIndex: 1, explanation: 'Standard RAG retrieves on every query regardless of need. Self-RAG gives the agent discretion: it reasons about whether retrieval is needed (TAOR pattern) and only searches when the question requires project-specific information. This saves tokens, reduces latency, and avoids injecting irrelevant context.' },
        { id: 'q2', question: 'Why is topic-based forced retrieval important for Self-RAG agents?', options: ['It improves embedding quality', 'It prevents the agent from confidently answering project-specific questions (especially security-critical ones) using potentially outdated training data', 'It reduces the number of tool calls', 'It makes the agent faster'], correctIndex: 1, explanation: 'Without forced retrieval for sensitive topics, the agent might answer "your auth uses bcrypt" from training data when the codebase actually uses argon2. For security, configuration, and business logic questions, always forcing retrieval ensures answers are grounded in the actual codebase, not assumptions.' },
        { id: 'q3', question: 'How does the Self-RAG pattern relate to TAOR?', options: ['They are unrelated patterns', 'Self-RAG is TAOR applied to knowledge retrieval: Think (do I need context?) -> Act (answer or search) -> Observe (was it sufficient?) -> Repeat (refine if needed)', 'TAOR is a type of Self-RAG', 'Self-RAG replaces TAOR'], correctIndex: 1, explanation: 'Self-RAG is a specific application of the TAOR (Think, Act, Observe, Repeat) loop to the problem of knowledge retrieval. The agent thinks about whether it has enough context, acts by either answering directly or searching, observes the quality of retrieved results, and repeats with a refined query if needed.' }
      ]
    },
{
    id: 'hallucination-prevention',
    moduleId: 'rag',
    title: 'Hallucination Detection & Prevention',
    description: 'Why LLMs hallucinate, the four types of hallucination, and ranked prevention strategies from confidence prompting to multi-agent verification',
    order: 4,
    content: [
      { type: 'text', content: '## Why LLMs Hallucinate: Plausibility Over Truth\n\nThis is the single most important thing to understand about large language models: **they are trained to predict the most likely next token, not the most truthful one.** The training objective is statistical plausibility -- given this context, what word would a human most likely write next? Truth is correlated with plausibility (humans usually write true things), but correlation is not causation.\n\nWhen you ask Claude "What line is the `getUserById` function on?", it does not open a file and count lines. It predicts what a helpful response would look like. If the training data suggests that functions are often around line 42, it might confidently say "line 42" even if the function is on line 117 -- or does not exist at all. The model is not lying. It is doing exactly what it was trained to do: produce plausible text.\n\nThis distinction matters because it changes how you think about prevention. You cannot "fix" hallucination by telling the model to be more careful. You fix it by giving the model access to ground truth (tools, RAG, verification) so that the plausible answer and the true answer become the same thing.\n\n### The Four Types of Hallucination\n\nNot all hallucinations are created equal. Understanding the types helps you choose the right prevention strategy.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:560px;">\n<div style="display:flex;flex-direction:column;gap:0.6rem;">\n<div style="border-left:4px solid #e17055;padding:0.6rem 1rem;background:rgba(225,112,85,0.06);border-radius:0 8px 8px 0;">\n<div style="font-weight:700;color:#e17055;font-size:0.9rem;">1. Factual Fabrication</div>\n<div style="font-size:0.82rem;color:#555;margin-top:0.2rem;">Inventing facts that do not exist. "The <code>getUserById</code> function is on line 42 of users.ts" when the file has no such function. The model generates plausible-sounding specifics with zero basis in reality.</div>\n</div>\n<div style="border-left:4px solid #fdcb6e;padding:0.6rem 1rem;background:rgba(253,203,110,0.06);border-radius:0 8px 8px 0;">\n<div style="font-weight:700;color:#b58a00;font-size:0.9rem;">2. Confident Uncertainty</div>\n<div style="font-size:0.82rem;color:#555;margin-top:0.2rem;">Presenting guesses as certainties. "The API rate limit is 100 requests per minute" stated with zero hedging when the model has no idea what the actual limit is. No "I think" or "approximately" -- just a flat assertion.</div>\n</div>\n<div style="border-left:4px solid #6c5ce7;padding:0.6rem 1rem;background:rgba(108,92,231,0.06);border-radius:0 8px 8px 0;">\n<div style="font-weight:700;color:#6c5ce7;font-size:0.9rem;">3. Context Confusion</div>\n<div style="font-size:0.82rem;color:#555;margin-top:0.2rem;">Mixing information from different parts of the context. You provide docs for Service A and Service B. The model describes Service A but uses the authentication method from Service B. Each fact is real but the combination is wrong.</div>\n</div>\n<div style="border-left:4px solid #fd79a8;padding:0.6rem 1rem;background:rgba(253,121,168,0.06);border-radius:0 8px 8px 0;">\n<div style="font-weight:700;color:#fd79a8;font-size:0.9rem;">4. Capability Hallucination</div>\n<div style="font-size:0.82rem;color:#555;margin-top:0.2rem;">Claiming to have done something it did not actually do. "I\'ve updated the file" when the tool call failed silently. "I\'ve verified the API is running" when it has no network access. The model predicts what a successful response looks like.</div>\n</div>\n</div>\n</div>\n\nThe most dangerous hallucinations are **confident AND wrong** -- Type 1 and Type 2 combined. The model states a fabricated fact with absolute certainty. No hedging, no caveats, no "I\'m not sure." The user has no signal that the information is unreliable.' },
      { type: 'text', content: '## Prevention Strategies Ranked by Effectiveness\n\nNot all prevention strategies are equal. Here they are ranked from most to least effective, with the key insight: **the best strategies give the model access to ground truth rather than asking it to be more honest.**\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #6c5ce7;border-radius:12px;overflow:hidden;">\n<div style="background:#6c5ce7;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Hallucination Prevention Strategies (Ranked)</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(39,174,96,0.08);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#27ae60;">Tool Verification (TAOR Observe)</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#27ae60;font-weight:700;">Very High</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Agent reads actual file/API/DB before asserting facts. Reality check via tools makes fabrication nearly impossible.</td>\n</tr>\n<tr style="background:rgba(9,132,227,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#0984e3;">RAG Grounding</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#0984e3;font-weight:700;">High</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Retrieve relevant docs and force the model to cite sources. Answers tied to retrieved chunks are far more reliable.</td>\n</tr>\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#6c5ce7;">Extended Thinking</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#6c5ce7;font-weight:700;">High</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">More reasoning tokens = more self-correction. The model catches its own mistakes during the thinking phase before they reach the output.</td>\n</tr>\n<tr style="background:rgba(225,112,85,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#e17055;">Multi-Agent Verification</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#e17055;font-weight:700;">High</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">A second agent fact-checks the first. Independent verification catches errors that self-review misses.</td>\n</tr>\n<tr style="background:rgba(253,203,110,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#b58a00;">Confidence Prompting</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#b58a00;font-weight:700;">Medium</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">"If you\'re not sure, say so." Reduces confident uncertainty but does not prevent fabrication -- the model may be confidently wrong about its own confidence.</td>\n</tr>\n<tr style="background:rgba(253,121,168,0.04);">\n<td style="padding:0.5rem 0.8rem;font-weight:600;color:#fd79a8;">Temperature = 0</td>\n<td style="padding:0.5rem 0.8rem;color:#fd79a8;font-weight:700;">Low</td>\n<td style="padding:0.5rem 0.8rem;color:#555;">Makes output deterministic but does not make it correct. The most likely token is still not necessarily the true token.</td>\n</tr>\n</table>\n</div>\n</div>\n\n### The Key Insight\n\nNotice the pattern: the top strategies (tool verification, RAG, multi-agent) all give the model access to **external ground truth**. The bottom strategies (confidence prompting, temperature) only tweak the model\'s internal behavior. You cannot prompt your way out of a training objective. You must provide reality for the model to check against.' },
      { type: 'code', content: '// Pattern 1: Grounded Answer with RAG + Citation\n// The model MUST cite sources -- no source, no claim\nimport Anthropic from \'@anthropic-ai/sdk\';\n\ninterface RetrievedChunk {\n  content: string;\n  source: string;\n  score: number;\n}\n\nasync function groundedAnswer(\n  question: string,\n  chunks: RetrievedChunk[]\n): Promise<{ answer: string; citations: string[]; confidence: string }> {\n  const client = new Anthropic();\n\n  const sourcesBlock = chunks\n    .map((c, i) => `[Source ${i + 1}: ${c.source}]\\n${c.content}`)\n    .join(\'\\n\\n\');\n\n  const response = await client.messages.create({\n    model: \'claude-sonnet-4-6-20250514\',\n    max_tokens: 2048,\n    messages: [{\n      role: \'user\',\n      content: `Answer the following question using ONLY the provided sources.\n\nRULES:\n1. Every factual claim MUST have a [Source N] citation.\n2. If no source supports a claim, say "I don\'t have information about this."\n3. NEVER make up information not in the sources.\n4. Rate your confidence: HIGH (directly supported), MEDIUM (inferred), LOW (uncertain).\n\nSOURCES:\n${sourcesBlock}\n\nQUESTION: ${question}\n\nRespond as JSON: { "answer": "...", "citations": ["Source 1", ...], "confidence": "HIGH|MEDIUM|LOW" }`,\n    }],\n  });\n\n  const text = response.content[0].type === \'text\' ? response.content[0].text : \'\';\n  return JSON.parse(text);\n}\n\n// Usage: retrieve chunks first, then ground the answer\nconst chunks = await vectorStore.similaritySearch(\'rate limit configuration\', 5);\nconst result = await groundedAnswer(\'What is the API rate limit?\', chunks);\n\nconsole.log(result.answer);     // "The API rate limit is 500 req/min [Source 2]"\nconsole.log(result.confidence); // "HIGH"\nconsole.log(result.citations);  // ["Source 2"]', language: 'typescript' },
      { type: 'code', content: '// Pattern 2: Multi-Agent Verification\n// Agent A answers, Agent B fact-checks, disagreements flagged\nimport Anthropic from \'@anthropic-ai/sdk\';\n\ninterface VerificationResult {\n  originalAnswer: string;\n  verified: boolean;\n  issues: string[];\n  correctedAnswer?: string;\n}\n\nasync function verifiedAnswer(\n  question: string,\n  context: string\n): Promise<VerificationResult> {\n  const client = new Anthropic();\n\n  // Agent A: Generate the answer\n  const answerResponse = await client.messages.create({\n    model: \'claude-sonnet-4-6-20250514\',\n    max_tokens: 2048,\n    system: \'You are a helpful assistant. Answer based on the provided context.\',\n    messages: [{\n      role: \'user\',\n      content: `Context:\\n${context}\\n\\nQuestion: ${question}`,\n    }],\n  });\n\n  const originalAnswer = answerResponse.content[0].type === \'text\'\n    ? answerResponse.content[0].text\n    : \'\';\n\n  // Agent B: Fact-check the answer against the SAME context\n  const verifyResponse = await client.messages.create({\n    model: \'claude-sonnet-4-6-20250514\',\n    max_tokens: 2048,\n    system:\n      \'You are a fact-checker. Your job is to verify claims against source material.\\n\' +\n      \'Be skeptical. Check every factual claim. Flag anything not directly supported.\',\n    messages: [{\n      role: \'user\',\n      content: `SOURCE MATERIAL:\\n${context}\\n\\n` +\n        `ANSWER TO VERIFY:\\n${originalAnswer}\\n\\n` +\n        \'Check every factual claim in the answer against the source material.\\n\' +\n        \'Respond as JSON: {\\n\' +\n        \'  "verified": boolean,\\n\' +\n        \'  "issues": ["description of each unsupported claim"],\\n\' +\n        \'  "correctedAnswer": "corrected version if issues found"\\n\' +\n        \'}\',\n    }],\n  });\n\n  const verifyText = verifyResponse.content[0].type === \'text\'\n    ? verifyResponse.content[0].text\n    : \'{}\';\n  const verification = JSON.parse(verifyText);\n\n  return {\n    originalAnswer,\n    verified: verification.verified,\n    issues: verification.issues || [],\n    correctedAnswer: verification.correctedAnswer,\n  };\n}\n\n// Usage\nconst result = await verifiedAnswer(\n  \'What authentication does the /api/payments endpoint use?\',\n  retrievedDocs\n);\n\nif (!result.verified) {\n  console.warn(\'Hallucination detected!\', result.issues);\n  // Use correctedAnswer, or fall back to human review\n  return result.correctedAnswer ?? \'Unable to verify -- please check manually.\';\n}\nreturn result.originalAnswer;', language: 'typescript' },
      { type: 'text', content: '## Common Mistakes and How to Avoid Them\n\n**Mistake 1: Trusting confidence prompts alone.** Telling the model "say I don\'t know if unsure" helps, but the model can be confidently wrong about its own confidence. A model that fabricates a function name will also fabricate confidence in that function name. Always pair confidence prompting with tool verification or RAG.\n\n**Mistake 2: Not verifying tool call results.** Capability hallucination happens when the model claims a tool call succeeded without checking. After every tool call in your TAOR loop, verify the result: did the file actually change? Did the API return a 200? Did the test output match expectations? The Observe step in TAOR exists precisely for this.\n\n**Mistake 3: RAG without citation enforcement.** Retrieving relevant chunks is half the solution. If you do not force the model to cite which source supports each claim, it will use the retrieved chunks as "inspiration" and still hallucinate details. Always require `[Source N]` citations and validate them programmatically.\n\n**Mistake 4: Using temperature 0 as a hallucination fix.** Temperature 0 makes the output deterministic (same input = same output) but does not make it correct. The most likely token sequence can still be a hallucination. Temperature 0 is useful for reproducibility, not for truthfulness.\n\n### Key Takeaways\n\n1. **LLMs are trained for plausibility, not truth.** They predict likely tokens, not verified facts. This is the root cause of all hallucination.\n2. **The four types** -- factual fabrication, confident uncertainty, context confusion, and capability hallucination -- each require different prevention strategies.\n3. **Ground truth access beats prompting.** Tool verification, RAG with citations, and multi-agent fact-checking outperform "be careful" prompts because they provide reality for the model to check against.\n4. **Extended Thinking reduces hallucination** because more reasoning tokens give the model more opportunities to catch and correct its own mistakes before outputting them.\n5. **Always verify the Observe step.** After every tool call, check that the action actually succeeded. Capability hallucination is the sneakiest type because the model genuinely believes it did the thing.' },
      { type: 'tip', content: 'The highest-ROI hallucination prevention you can implement today: after every tool call in your agent loop, add a verification step that checks the tool result before the agent continues. Did the file write actually succeed? Does the file now contain the expected content? This single check eliminates capability hallucination, which is the most common type in agentic systems.' },
      { type: 'warning', content: 'Multi-agent verification doubles your API cost (two calls instead of one). Use it selectively: high-stakes outputs (code that will be deployed, customer-facing answers, data mutations) deserve verification. Low-stakes outputs (draft summaries, internal logs) usually do not. Budget your verification where the cost of being wrong is highest.' }
    ],
    quiz: [
      { id: 'q1', question: 'Why do LLMs hallucinate?', options: ['They are buggy and need to be patched', 'They are trained to predict the most likely next token, not the most truthful one', 'They intentionally lie to seem more helpful', 'They run out of context window space'], correctIndex: 1, explanation: 'LLMs are trained on a next-token prediction objective. They learn to produce statistically plausible text, not verified facts. Truth and plausibility are correlated but not identical, which is why hallucination is an inherent property of the architecture, not a bug to be patched.' },
      { id: 'q2', question: 'Which hallucination prevention strategy is ranked most effective?', options: ['Setting temperature to 0', 'Confidence prompting ("say I don\'t know if unsure")', 'Tool verification via the TAOR Observe step', 'Using a larger model'], correctIndex: 2, explanation: 'Tool verification is ranked "Very High" effectiveness because it provides the model with actual ground truth. The agent reads the real file, queries the real API, or checks the real database before making claims. This makes fabrication nearly impossible because the model is citing observed reality, not predicting plausible text.' },
      { id: 'q3', question: 'What is "capability hallucination"?', options: ['The model claims it can run faster than other models', 'The model claims to have performed an action (like updating a file) when the tool call actually failed', 'The model invents new programming languages', 'The model refuses to use tools it actually has access to'], correctIndex: 1, explanation: 'Capability hallucination occurs when the model says "I\'ve updated the file" or "I\'ve verified the API is running" when the tool call failed silently or was never executed. The model predicts what a successful response looks like rather than checking whether the action actually succeeded. This is prevented by verifying tool results in the TAOR Observe step.' }
    ]
  },
  {
    id: 'agent-observability',
    moduleId: 'rag',
    title: 'Agent Observability & Debugging',
    description: 'Tracing architecture, structured logging, tool comparison, and debugging strategies for non-deterministic AI agent systems',
    order: 5,
    content: [
      { type: 'text', content: '## You Cannot Debug Non-Deterministic Systems with Breakpoints\n\nTraditional debugging assumes determinism: set a breakpoint, step through the code, and the same input produces the same execution path every time. AI agents break this assumption completely. The same prompt can produce different tool call sequences, different reasoning chains, and different outputs on every run. A bug that appears on run 7 may not reproduce on run 8.\n\nThis is why agent systems require **observability** -- the ability to understand what happened inside a system by examining its outputs (logs, traces, metrics) rather than stepping through its execution. You are not debugging code; you are debugging a conversation between an LLM, tools, and state.\n\n### What You Need to Observe\n\nEvery agent run generates a rich stream of data. The question is which data to capture and how to structure it for debugging.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #0984e3;border-radius:12px;overflow:hidden;">\n<div style="background:#0984e3;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Agent Observability Checklist</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#6c5ce7;width:35%;">Full Message History</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Every system, user, and assistant message in the conversation. This is the "source of truth" for what the model saw and said.</td>\n</tr>\n<tr style="background:rgba(0,206,201,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#00cec9;">Tool Calls (name + params + result)</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Which tool was called, with what arguments, and what it returned. The most common debugging signal -- wrong action usually means wrong tool call.</td>\n</tr>\n<tr style="background:rgba(253,203,110,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#b58a00;">Token Usage Per Step</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Input tokens, output tokens, and cache hits for each LLM call. Essential for cost tracking and detecting context window bloat.</td>\n</tr>\n<tr style="background:rgba(225,112,85,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#e17055;">Latency Per Step</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Wall-clock time for each LLM call and tool execution. Reveals which steps are bottlenecks -- often tool calls, not model inference.</td>\n</tr>\n<tr style="background:rgba(253,121,168,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#fd79a8;">Decision Points</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Where the agent chose between options -- conditional edges in a graph, tool selection, or early termination. These are where bugs hide.</td>\n</tr>\n<tr style="background:rgba(39,174,96,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:600;color:#27ae60;">Error Recovery</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">When a tool call failed, did the agent retry? Adapt? Give up? Error recovery reveals agent resilience and failure modes.</td>\n</tr>\n<tr style="background:rgba(9,132,227,0.06);">\n<td style="padding:0.5rem 0.8rem;font-weight:600;color:#0984e3;">Final Outcome</td>\n<td style="padding:0.5rem 0.8rem;color:#555;">Did the agent complete the task? What was the final output? How many steps did it take? This is the high-level success metric.</td>\n</tr>\n</table>\n</div>\n</div>' },
      { type: 'text', content: '## Tracing Architecture: Every Step Gets a Timestamp\n\nThe core abstraction for agent observability is the **trace**. Each agent run gets a unique `traceId`. Every step within that run -- every LLM call, tool execution, and state transition -- is logged as a **span** within that trace, with start/end timestamps, inputs, and outputs.\n\nThis is the same model that distributed systems use (OpenTelemetry, Jaeger, Zipkin), adapted for AI agents. The difference is that your "microservices" are LLM calls and tool executions rather than HTTP endpoints.\n\n<div style="margin:1.5rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #6c5ce7;border-radius:12px;padding:1.2rem;background:rgba(108,92,231,0.03);">\n<div style="font-weight:700;font-size:1rem;color:#6c5ce7;margin-bottom:1rem;text-align:center;">Trace Architecture: Agent Run #a3f8</div>\n<div style="display:flex;flex-direction:column;gap:0.35rem;font-family:monospace;font-size:0.78rem;">\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:00.000</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#6c5ce7;color:white;font-weight:600;">TRACE START</div>\n<span style="color:#666;">traceId=a3f8 task=&quot;Add pagination&quot;</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:00.012</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM CALL</div>\n<span style="color:#666;">model=sonnet tokens_in=1,240 thinking...</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:02.341</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM DONE</div>\n<span style="color:#666;">tokens_out=385 latency=2,329ms decision=&quot;read file&quot;</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:02.345</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#00cec9;color:white;font-weight:600;">TOOL CALL</div>\n<span style="color:#666;">name=readFile params={path: &quot;src/api/users.ts&quot;}</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:02.358</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#27ae60;color:white;font-weight:600;">TOOL RESULT</div>\n<span style="color:#666;">status=ok bytes=4,821 latency=13ms</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:02.360</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM CALL</div>\n<span style="color:#666;">model=sonnet tokens_in=2,480 thinking...</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:05.102</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM DONE</div>\n<span style="color:#666;">tokens_out=920 latency=2,742ms decision=&quot;write file&quot;</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:05.105</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#00cec9;color:white;font-weight:600;">TOOL CALL</div>\n<span style="color:#666;">name=writeFile params={path: &quot;src/api/users.ts&quot;}</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:05.118</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#27ae60;color:white;font-weight:600;">TOOL RESULT</div>\n<span style="color:#666;">status=ok bytes_written=5,203 latency=13ms</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:05.120</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM CALL</div>\n<span style="color:#666;">model=sonnet tokens_in=3,600 thinking...</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:06.890</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#0984e3;color:white;font-weight:600;">LLM DONE</div>\n<span style="color:#666;">tokens_out=142 latency=1,770ms decision=&quot;end_turn&quot;</span>\n</div>\n<div style="display:flex;align-items:center;gap:0.4rem;">\n<span style="color:#888;min-width:70px;">00:06.891</span>\n<div style="padding:0.25rem 0.6rem;border-radius:4px;background:#e17055;color:white;font-weight:600;">TRACE END</div>\n<span style="color:#666;">steps=3 tools=2 total_tokens=8,667 total_latency=6.89s</span>\n</div>\n</div>\n</div>\n</div>\n\n### Tools Comparison\n\nThe observability ecosystem for AI agents is maturing rapidly. Here are the leading options:\n\n<div style="margin:1rem 0;font-family:system-ui,sans-serif;max-width:580px;">\n<div style="border:2px solid #00cec9;border-radius:12px;overflow:hidden;">\n<div style="background:#00cec9;color:white;padding:0.6rem 1rem;font-weight:700;font-size:0.95rem;">Observability Tools Comparison</div>\n<table style="width:100%;border-collapse:collapse;font-size:0.82rem;">\n<tr style="background:rgba(108,92,231,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:700;color:#6c5ce7;">LangSmith</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">SaaS by LangChain. Visual trace UI with step-by-step replays. Best for LangChain/LangGraph projects. Paid tiers for production volume.</td>\n</tr>\n<tr style="background:rgba(9,132,227,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:700;color:#0984e3;">OpenTelemetry</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Open standard for distributed tracing. Framework-agnostic. Integrates with Jaeger, Grafana, Datadog. Best for teams already using OTel in their stack.</td>\n</tr>\n<tr style="background:rgba(225,112,85,0.06);">\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;font-weight:700;color:#e17055;">Braintrust</td>\n<td style="padding:0.5rem 0.8rem;border-bottom:1px solid #eee;color:#555;">Combined eval + tracing platform. Run evals and trace production traffic in one tool. Strong prompt versioning and A/B testing features.</td>\n</tr>\n<tr style="background:rgba(39,174,96,0.06);">\n<td style="padding:0.5rem 0.8rem;font-weight:700;color:#27ae60;">Arize Phoenix</td>\n<td style="padding:0.5rem 0.8rem;color:#555;">Open source, runs locally. Excellent for development and debugging without sending data to a third party. Visual trace explorer. Free forever.</td>\n</tr>\n</table>\n</div>\n</div>' },
      { type: 'code', content: '// Minimal tracing implementation for agent loops\n// This captures the essential signals for debugging\nimport { randomUUID } from \'crypto\';\n\ninterface TraceSpan {\n  spanId: string;\n  traceId: string;\n  type: \'llm_call\' | \'tool_call\' | \'tool_result\' | \'decision\' | \'error\';\n  timestamp: number;\n  duration?: number;\n  data: Record<string, unknown>;\n}\n\nclass AgentTracer {\n  private traceId: string;\n  private spans: TraceSpan[] = [];\n  private startTime: number;\n\n  constructor(taskDescription: string) {\n    this.traceId = randomUUID().slice(0, 8);\n    this.startTime = Date.now();\n    this.addSpan(\'decision\', { event: \'trace_start\', task: taskDescription });\n  }\n\n  addSpan(type: TraceSpan[\'type\'], data: Record<string, unknown>): string {\n    const spanId = randomUUID().slice(0, 8);\n    this.spans.push({\n      spanId,\n      traceId: this.traceId,\n      type,\n      timestamp: Date.now() - this.startTime,\n      data,\n    });\n    return spanId;\n  }\n\n  // Call this when an LLM request starts, returns a function to call when it ends\n  startLlmCall(model: string, inputTokens: number): () => void {\n    const spanId = this.addSpan(\'llm_call\', { model, inputTokens, status: \'started\' });\n    const startTime = Date.now();\n\n    return (outputTokens?: number, decision?: string) => {\n      const duration = Date.now() - startTime;\n      this.addSpan(\'llm_call\', {\n        model,\n        inputTokens,\n        outputTokens,\n        duration,\n        decision,\n        status: \'completed\',\n        parentSpanId: spanId,\n      });\n    };\n  }\n\n  // Log a tool call and its result\n  logToolCall(\n    toolName: string,\n    params: Record<string, unknown>,\n    result: unknown,\n    durationMs: number\n  ): void {\n    this.addSpan(\'tool_call\', { toolName, params });\n    this.addSpan(\'tool_result\', {\n      toolName,\n      resultSize: JSON.stringify(result).length,\n      duration: durationMs,\n      success: true,\n    });\n  }\n\n  // Log an error during tool execution\n  logToolError(toolName: string, error: Error): void {\n    this.addSpan(\'error\', {\n      toolName,\n      errorMessage: error.message,\n      errorStack: error.stack?.split(\'\\n\').slice(0, 3).join(\'\\n\'),\n    });\n  }\n\n  // Get the complete trace for storage or display\n  getTrace(): {\n    traceId: string;\n    totalDuration: number;\n    spanCount: number;\n    spans: TraceSpan[];\n    summary: {\n      llmCalls: number;\n      toolCalls: number;\n      errors: number;\n      totalTokensIn: number;\n      totalTokensOut: number;\n    };\n  } {\n    const llmSpans = this.spans.filter(\n      s => s.type === \'llm_call\' && s.data.status === \'completed\'\n    );\n    return {\n      traceId: this.traceId,\n      totalDuration: Date.now() - this.startTime,\n      spanCount: this.spans.length,\n      spans: this.spans,\n      summary: {\n        llmCalls: llmSpans.length,\n        toolCalls: this.spans.filter(s => s.type === \'tool_call\').length,\n        errors: this.spans.filter(s => s.type === \'error\').length,\n        totalTokensIn: llmSpans.reduce(\n          (sum, s) => sum + (s.data.inputTokens as number || 0), 0\n        ),\n        totalTokensOut: llmSpans.reduce(\n          (sum, s) => sum + (s.data.outputTokens as number || 0), 0\n        ),\n      },\n    };\n  }\n}\n\n// Usage inside an agent loop\nconst tracer = new AgentTracer(\'Add pagination to /api/users\');\n\n// Before each LLM call\nconst endLlm = tracer.startLlmCall(\'claude-sonnet-4-6\', 1240);\n// ... make the API call ...\nendLlm(385, \'read_file\'); // tokens out, decision made\n\n// After each tool call\nconst toolStart = Date.now();\nconst fileContent = await readFile(\'src/api/users.ts\');\ntracer.logToolCall(\'readFile\', { path: \'src/api/users.ts\' }, fileContent, Date.now() - toolStart);\n\n// At the end\nconst trace = tracer.getTrace();\nconsole.log(`Trace ${trace.traceId}: ${trace.summary.llmCalls} LLM calls, ` +\n  `${trace.summary.toolCalls} tool calls, ${trace.totalDuration}ms`);', language: 'typescript' },
      { type: 'text', content: '## Debugging Common Agent Issues\n\nWith observability in place, here is how to diagnose the five most common agent problems. Each starts from the symptom and traces backwards to the root cause.\n\n**1. Agent loops forever (or for too many steps)**\n\nSymptom: The agent runs 20+ steps without completing. Open the trace and look for **repeated tool calls** -- the same tool with the same (or very similar) parameters called multiple times. This usually means the agent is stuck: it tries an action, the result does not match expectations, and it retries the same thing. Fix: check why the tool result is not what the agent expects (wrong file path? permission error? stale data?), or add a max-iteration guard.\n\n**2. Agent takes the wrong action**\n\nSymptom: The agent does something unexpected, like deleting a file instead of modifying it. Open the trace and find the **LLM call just before the bad tool call**. Look at the model\'s thinking/reasoning. Usually the problem is in the system prompt (ambiguous instructions), the state (missing context the agent needed), or the tool description (the agent misunderstood what the tool does). Fix: improve the system prompt, ensure state contains the necessary context, or clarify tool descriptions.\n\n**3. Agent is too slow**\n\nSymptom: The run takes 60+ seconds. Open the trace and check **latency per step**. The bottleneck is almost always one of: a tool call that is slow (external API, large file read, command execution), or an LLM call with a massive context window (too many tokens in). Fix: optimize the slow tool, reduce context size with summarization, or parallelize independent tool calls.\n\n**4. Agent is too expensive**\n\nSymptom: Each run costs $2+ in API credits. Open the trace and check **token usage per step**. Look for: large tool results being passed back to the model (a 10,000-line file read), accumulated message history growing without compaction, or unnecessary retries. Fix: truncate large tool results, implement message compaction after N steps, add prompt caching for repeated system prompts.\n\n**5. Agent gives the wrong answer**\n\nSymptom: The final output is incorrect. **Trace backwards from the final output.** Which step introduced the error? Was it a hallucination in an LLM call (check for unsupported claims)? A wrong tool result (check tool params)? A context confusion (check if unrelated information leaked in)? Find the first step where the trace diverges from correctness, and fix that step.\n\n### Key Takeaways\n\n1. **Traditional debugging does not work for agents** because they are non-deterministic. Observability (traces, logs, metrics) replaces breakpoints.\n2. **Every agent run needs a traceId** that ties together all LLM calls, tool executions, and state transitions into one coherent story.\n3. **The five essential signals:** message history, tool calls (name+params+result), token usage, latency, and decision points.\n4. **Debug by tracing backwards** from the symptom to the first step where things went wrong. Loops = repeated tool calls. Wrong action = bad thinking before the call. Slow = tool latency. Expensive = token bloat.\n5. **Choose your tooling based on your stack:** LangSmith for LangChain projects, OpenTelemetry for polyglot stacks, Arize Phoenix for local open-source development.' },
      { type: 'tip', content: 'Start with console-level tracing (just log each step with a timestamp and the essential data) before investing in a full observability platform. You can debug 90% of agent issues with a well-structured console log. Add LangSmith or Phoenix when you need to compare traces across multiple runs or share debugging context with your team.' },
      { type: 'warning', content: 'Be careful about what you log. Agent traces can contain sensitive data: API keys in tool parameters, PII in user messages, proprietary code in file contents. Always sanitize traces before storing them in external platforms. Redact API keys, mask PII, and truncate large file contents to the first/last N lines. Your tracing pipeline needs the same security review as your production data pipeline.' }
    ],
    quiz: [
      { id: 'q1', question: 'Why can\'t you debug AI agents with traditional breakpoints?', options: ['Breakpoints are too slow for LLM calls', 'Agents are non-deterministic -- the same input can produce different execution paths on every run', 'JavaScript does not support breakpoints', 'Agents run in the cloud where you cannot attach a debugger'], correctIndex: 1, explanation: 'AI agents are non-deterministic because the LLM may choose different tool calls, reasoning paths, and outputs for the same input. A bug that appears on run 7 may not reproduce on run 8. This is why you need observability (traces, logs, metrics) instead of step-through debugging.' },
      { id: 'q2', question: 'What is the most useful signal for debugging an agent that takes the wrong action?', options: ['Token usage per step', 'The LLM reasoning/thinking just before the bad tool call', 'Total latency of the run', 'The final output text'], correctIndex: 1, explanation: 'When an agent takes a wrong action, the root cause is almost always in the LLM\'s reasoning just before the bad tool call. The model misunderstood the task, lacked context, or misinterpreted a tool description. Examining the thinking/reasoning before the bad call reveals why the agent made that decision.' },
      { id: 'q3', question: 'How do you diagnose an agent that loops forever?', options: ['Check the system prompt for typos', 'Look in the trace for repeated tool calls with the same or similar parameters', 'Increase the max tokens', 'Switch to a different model'], correctIndex: 1, explanation: 'An agent stuck in a loop will show the same tool being called repeatedly with the same (or very similar) parameters in the trace. The agent tries an action, gets a result that does not match expectations, and retries the same thing. The fix is to understand why the tool result is unexpected and either fix the tool, fix the agent\'s expectations, or add a max-iteration guard.' }
    ]
  }
        ]
      }
    ];
  }
}
